_LOAD_MISSING = object()


def _session_load_set_step(
    key,
    *,
    label=None,
    state=None,
    detail=None,
    count=_LOAD_MISSING,
    total=_LOAD_MISSING,
):
    now = time.time()
    with _SESSION_LOAD_STATUS_LOCK:
        steps = _SESSION_LOAD_STATUS.setdefault("steps", {})
        order = _SESSION_LOAD_STATUS.setdefault("order", [])
        if key not in steps:
            steps[key] = {"key": key, "label": label or key, "state": "pending", "detail": ""}
            order.append(key)
        step = steps[key]
        if label is not None:
            step["label"] = label
        if state is not None:
            step["state"] = state
        if detail is not None:
            step["detail"] = detail
        if count is not _LOAD_MISSING:
            step["count"] = count
        if total is not _LOAD_MISSING:
            step["total"] = total
        _SESSION_LOAD_STATUS["updated_at"] = now


def _session_load_complete(rows):
    total = len(rows or [])
    interactive = sum(1 for r in (rows or []) if r.get("source") == "interactive")
    backlog = sum(1 for r in (rows or []) if r.get("source") == "backlog")
    pkood = sum(1 for r in (rows or []) if r.get("source") == "pkood")
    _session_load_set_step(
        "cards",
        state="done",
        count=total,
        detail=f"{total} total cards: {interactive} sessions, {pkood} agents, {backlog} backlog.",
    )
    with _SESSION_LOAD_STATUS_LOCK:
        _SESSION_LOAD_STATUS.update({
            "active": False,
            "title": "Sessions loaded",
            "message": f"{total} cards ready.",
            "phase": "done",
            "updated_at": time.time(),
        })


def _session_load_fail(err):
    _session_load_set_step("cards", state="error", detail=str(err)[:160])
    with _SESSION_LOAD_STATUS_LOCK:
        _SESSION_LOAD_STATUS.update({
            "active": False,
            "title": "Session load failed",
            "message": str(err)[:160],
            "phase": "error",
            "updated_at": time.time(),
        })


_SESSIONS_SINGLEFLIGHT_LOCK = threading.Lock()
_SESSIONS_SINGLEFLIGHT = {}
_SESSIONS_RESPONSE_CACHE = {}


def _sessions_cache_ttl_seconds():
    try:
        ms = int(os.environ.get("CCC_SESSIONS_CACHE_TTL_MS", "2000"))
    except (TypeError, ValueError):
        ms = 2000
    return max(0, ms) / 1000.0


def _cached_sessions_rows(key):
    ttl = _sessions_cache_ttl_seconds()
    if ttl <= 0:
        return None
    with _SESSIONS_SINGLEFLIGHT_LOCK:
        cached = _SESSIONS_RESPONSE_CACHE.get(key)
        if not cached:
            return None
        if time.time() - cached.get("ts", 0) > ttl:
            return None
        return list(cached.get("rows") or [])


def _load_sessions_singleflight(repo_path, *, include_old=False, progress=True):
    """Run one /api/sessions scan per repo/age mode at a time.

    The browser can trigger a foreground load, a restore load, and a poller load
    close together. Each scan walks transcript stores and may run git/GitHub
    probes; parallel copies just contend on the GIL and make unrelated endpoints
    feel hung. Followers wait for the leader's short-lived cached result.
    """
    repo_path = resolve_repo_path(repo_path)
    key = (repo_path, bool(include_old))
    cached = _cached_sessions_rows(key)
    if cached is not None:
        return cached

    while True:
        with _SESSIONS_SINGLEFLIGHT_LOCK:
            flight = _SESSIONS_SINGLEFLIGHT.get(key)
            if flight is None:
                event = threading.Event()
                _SESSIONS_SINGLEFLIGHT[key] = {"event": event}
                break
            event = flight["event"]
        event.wait(timeout=60)
        cached = _cached_sessions_rows(key)
        if cached is not None:
            return cached

    try:
        if progress:
            _session_load_begin(repo_path)
        rows = find_all_sessions(
            repo_path,
            progress=_session_load_set_step if progress else None,
            include_old=include_old,
        )
        if progress:
            _session_load_complete(rows)
        with _SESSIONS_SINGLEFLIGHT_LOCK:
            _SESSIONS_RESPONSE_CACHE[key] = {"ts": time.time(), "rows": list(rows or [])}
        return rows
    except Exception as exc:
        if progress:
            _session_load_fail(exc)
        raise
    finally:
        with _SESSIONS_SINGLEFLIGHT_LOCK:
            flight = _SESSIONS_SINGLEFLIGHT.pop(key, None)
            if flight:
                flight["event"].set()


# ── Archive-load progress (mirrors session-load) ──────────────────────────
#
# The archive view fires /api/conversations/all on every page load, which
# does an 8-stage scan: list folders, read JSONL headers, infer effective
# repos, extract tail meta, probe worktree dirty state, scan codex/gemini/cursor
# stores, prime PR states (gh CLI fan-out), refresh cross-repo PRs.
# On a cold cache with many folders this is the 5-15s wait the user sees
# behind the generic "Loading archive…" spinner. The progress channel here
# lets the frontend render a stage checklist instead.
_ARCHIVE_LOAD_STATUS_LOCK = threading.Lock()
_ARCHIVE_LOAD_STATUS = {
    "active": False,
    "title": "Loading archive",
    "message": "Waiting for the next scan.",
    "phase": "idle",
    "started_at": 0,
    "updated_at": 0,
    "steps": {},
    "order": [],
}


def _archive_load_snapshot():
    with _ARCHIVE_LOAD_STATUS_LOCK:
        order = list(_ARCHIVE_LOAD_STATUS.get("order") or [])
        steps_by_key = dict(_ARCHIVE_LOAD_STATUS.get("steps") or {})
        steps = [dict(steps_by_key[k]) for k in order if k in steps_by_key]
        return {
            "active": bool(_ARCHIVE_LOAD_STATUS.get("active")),
            "title": _ARCHIVE_LOAD_STATUS.get("title") or "Loading archive",
            "message": _ARCHIVE_LOAD_STATUS.get("message") or "",
            "phase": _ARCHIVE_LOAD_STATUS.get("phase") or "idle",
            "started_at": _ARCHIVE_LOAD_STATUS.get("started_at") or 0,
            "updated_at": _ARCHIVE_LOAD_STATUS.get("updated_at") or 0,
            "steps": steps,
        }


def _archive_load_begin():
    now = time.time()
    steps = {
        "folders":     {"key": "folders",     "label": "Scanning project folders",        "state": "pending", "detail": "Listing ~/.claude/projects/."},
        "transcripts": {"key": "transcripts", "label": "Reading conversation transcripts", "state": "pending", "detail": "Parsing JSONL headers."},
        "infer":       {"key": "infer",       "label": "Inferring active branches",        "state": "pending", "detail": "Walking recent sessions."},
        "worktrees":   {"key": "worktrees",   "label": "Checking worktree status",         "state": "pending", "detail": "git status per recent worktree."},
        "codex":       {"key": "codex",       "label": "Codex / Gemini conversations",     "state": "pending", "detail": "Scanning sibling stores."},
        "cursor":      {"key": "cursor",      "label": "Cursor conversations",             "state": "pending", "detail": "Scanning ~/.cursor/projects/."},
        "antigravity": {"key": "antigravity", "label": "Antigravity conversations",        "state": "pending", "detail": "Scanning ~/.gemini/antigravity/brain/."},
        "pr_states":   {"key": "pr_states",   "label": "Refreshing pull-request status",   "state": "pending", "detail": "gh pr view per known PR."},
        "issues":      {"key": "issues",      "label": "Refreshing GitHub issues",         "state": "pending", "detail": "gh issue list per repo."},
        "group_chats": {"key": "group_chats", "label": "Cross-repo group chats",           "state": "pending", "detail": "Reading sidecars."},
    }
    with _ARCHIVE_LOAD_STATUS_LOCK:
        _ARCHIVE_LOAD_STATUS.update({
            "active": True,
            "title": "Loading archive",
            "message": "Scanning sources by stage.",
            "phase": "running",
            "started_at": now,
            "updated_at": now,
            "steps": steps,
            "order": ["folders", "transcripts", "infer", "worktrees", "codex", "cursor", "antigravity", "pr_states", "issues", "group_chats"],
        })


def _archive_load_set_step(key, *, label=None, state=None, detail=None, count=_LOAD_MISSING, total=_LOAD_MISSING):
    now = time.time()
    with _ARCHIVE_LOAD_STATUS_LOCK:
        steps = _ARCHIVE_LOAD_STATUS.setdefault("steps", {})
        order = _ARCHIVE_LOAD_STATUS.setdefault("order", [])
        if key not in steps:
            steps[key] = {"key": key, "label": label or key, "state": "pending", "detail": ""}
            order.append(key)
        step = steps[key]
        if label is not None:
            step["label"] = label
        if state is not None:
            step["state"] = state
        if detail is not None:
            step["detail"] = detail
        if count is not _LOAD_MISSING:
            step["count"] = count
        if total is not _LOAD_MISSING:
            step["total"] = total
        _ARCHIVE_LOAD_STATUS["updated_at"] = now


def _archive_load_complete(rows):
    total = len(rows or [])
    with _ARCHIVE_LOAD_STATUS_LOCK:
        _ARCHIVE_LOAD_STATUS.update({
            "active": False,
            "title": "Archive loaded",
            "message": f"{total} conversations ready.",
            "phase": "done",
            "updated_at": time.time(),
        })


def _archive_load_fail(err):
    _archive_load_set_step("folders", state="error", detail=str(err)[:160])
    with _ARCHIVE_LOAD_STATUS_LOCK:
        _ARCHIVE_LOAD_STATUS.update({
            "active": False,
            "title": "Archive load failed",
            "message": str(err)[:160],
            "phase": "error",
            "updated_at": time.time(),
        })


def _load_custom_repos():
    """Return the list of user-picked repo paths (absolute, deduped, existing dirs)."""
    try:
        raw = _CUSTOM_REPOS_FILE.read_text()
    except OSError:
        return []
    out = []
    seen = set()
    for line in raw.splitlines():
        line = line.strip()
        if not line or line.startswith("#"):
            continue
        try:
            p = Path(line).expanduser().resolve()
        except (OSError, ValueError):
            continue
        s = str(p)
        if s in seen or not p.is_dir():
            continue
        seen.add(s)
        out.append(s)
    return out


def _load_recent_repos():
    """Return recently-used repo paths, most-recent first (deduped, existing dirs only)."""
    try:
        raw = _RECENT_REPOS_FILE.read_text()
    except OSError:
        return []
    out = []
    seen = set()
    for line in raw.splitlines():
        line = line.strip()
        if not line or line.startswith("#"):
            continue
        try:
            p = Path(line).expanduser().resolve()
        except (OSError, ValueError):
            continue
        s = str(p)
        if s in seen or not p.is_dir():
            continue
        seen.add(s)
        out.append(s)
        if len(out) >= _RECENT_REPOS_CAP:
            break
    return out


def _record_recent_repo(path_str):
    """Prepend a switch event to the recent list. Silent on I/O error — the
    recency ordering is a UX nicety, not load-bearing."""
    try:
        p = Path(path_str).expanduser().resolve()
    except (OSError, ValueError):
        return
    if not p.is_dir():
        return
    existing = _load_recent_repos()
    new_list = [str(p)] + [x for x in existing if x != str(p)]
    new_list = new_list[:_RECENT_REPOS_CAP]
    try:
        _RECENT_REPOS_FILE.parent.mkdir(parents=True, exist_ok=True)
        _RECENT_REPOS_FILE.write_text("\n".join(new_list) + "\n")
    except OSError:
        pass


def _append_custom_repo(path_str):
    """Persist a user-picked repo path. Returns the absolute resolved path.
    Raises ValueError if the path isn't an existing directory."""
    p = Path(path_str).expanduser().resolve()
    if not p.is_dir():
        raise ValueError(f"not a directory: {p}")
    existing = set(_load_custom_repos())
    if str(p) in existing:
        return str(p)
    _CUSTOM_REPOS_FILE.parent.mkdir(parents=True, exist_ok=True)
    with _CUSTOM_REPOS_FILE.open("a") as f:
        f.write(str(p) + "\n")
    return str(p)


# Visual-only override of which repo a session appears under in the all-repos
# archive view. {session_id: repo_path}. Does not touch the JSONL transcript —
# the session's recorded cwd is unchanged, only the row's grouping is moved.
# Used when a session was launched in repo A but the work logically belongs
# under repo B and the user wants the row to appear there for scanning.
_REPO_PINS_FILE = Path.home() / ".claude" / "command-center" / "repo-pins.json"


def _load_repo_pins():
    try:
        with open(_REPO_PINS_FILE) as f:
            data = json.load(f)
    except (OSError, json.JSONDecodeError):
        return {}
    if not isinstance(data, dict):
        return {}
    return {str(k): str(v) for k, v in data.items() if k and v}


def _save_repo_pins(pins):
    _REPO_PINS_FILE.parent.mkdir(parents=True, exist_ok=True)
    tmp = _REPO_PINS_FILE.with_suffix(".json.tmp")
    with open(tmp, "w") as f:
        json.dump(pins, f, indent=2, sort_keys=True)
    tmp.replace(_REPO_PINS_FILE)


def _load_session_overrides():
    """Return {session_id: {model, context_1m, engine, set_at}} or {}."""
    try:
        with open(SESSION_OVERRIDES_FILE) as f:
            data = json.load(f)
    except (OSError, json.JSONDecodeError):
        return {}
    return data if isinstance(data, dict) else {}


def _save_session_overrides(overrides):
    SESSION_OVERRIDES_FILE.parent.mkdir(parents=True, exist_ok=True)
    tmp = SESSION_OVERRIDES_FILE.with_suffix(".json.tmp")
    with open(tmp, "w") as f:
        json.dump(overrides, f, indent=2, sort_keys=True)
    tmp.replace(SESSION_OVERRIDES_FILE)


def _get_session_override(session_id):
    if not session_id:
        return None
    entry = _load_session_overrides().get(session_id)
    if not isinstance(entry, dict):
        return None
    return entry


def _set_session_override(session_id, model, context_1m, engine):
    overrides = _load_session_overrides()
    overrides[session_id] = {
        "model": str(model),
        "context_1m": bool(context_1m),
        "engine": str(engine or "claude"),
        "set_at": datetime.now(timezone.utc).strftime("%Y-%m-%dT%H:%M:%SZ"),
    }
    _save_session_overrides(overrides)


def _clear_session_override(session_id):
    overrides = _load_session_overrides()
    if session_id in overrides:
        del overrides[session_id]
        _save_session_overrides(overrides)


def _short_model_alias(model):
    """Turn `claude-sonnet-4-6` / `claude-sonnet-4-6[1m]` / `sonnet` into the
    alias form `/model` accepts: drop the `claude-` prefix and any `[1m]`
    suffix the caller may have included. Non-Claude model strings pass
    through unchanged (callers shouldn't be invoking this for them, but
    being permissive is cheap)."""
    if not model:
        return ""
    alias = model.strip()
    if alias.lower().startswith("claude-"):
        alias = alias[len("claude-"):]
    # Strip any trailing `[1m]`/`[1M]` — the slash command adds it back when
    # context_1m is true, and we don't want a double suffix.
    for tail in ("[1m]", "[1M]"):
        if alias.endswith(tail):
            alias = alias[: -len(tail)]
    return alias.strip()


def _build_slash_model_command(model, context_1m):
    """Compose the `/model <alias>[1m]` text injected into a live Claude
    session. Returns an empty string if model is missing — caller should
    treat that as a no-op."""
    alias = _short_model_alias(model)
    if not alias:
        return ""
    if context_1m:
        return f"/model {alias}[1m]"
    return f"/model {alias}"


