def _command_targets_engine_session(command, session_id, engine):
    if not command or not session_id:
        return False
    try:
        tokens = shlex.split(command)
    except ValueError:
        tokens = command.split()
    if not tokens:
        return False
    if engine == "codex":
        # `codex exec ... -- <prompt>` can contain arbitrary UUIDs in prompt
        # text. Only treat a session id as exact when it belongs to resume args.
        head = tokens[:tokens.index("--")] if "--" in tokens else tokens
        return any(tok == session_id and "resume" in head[:idx]
                   for idx, tok in enumerate(head))
    if engine == "gemini":
        return any(
            tok == session_id and (
                "--resume" in tokens[:idx] or
                (idx > 0 and tokens[idx - 1] in ("--resume", "resume"))
            )
            for idx, tok in enumerate(tokens)
        )
    if engine == "cursor":
        return any(
            tok == session_id and (
                "--resume" in tokens[:idx] or
                (idx > 0 and tokens[idx - 1] in ("--resume", "resume"))
            )
            for idx, tok in enumerate(tokens)
        )
    if engine == "antigravity":
        return any(
            tok == session_id and (
                "--conversation" in tokens[:idx] or
                (idx > 0 and tokens[idx - 1] in ("--conversation", "conversation"))
            )
            for idx, tok in enumerate(tokens)
        )
    return False


def _process_comm_is_claude(comm):
    """Return True when a ps comm value belongs to Claude Code.

    Native builds report the versioned binary path
    (`~/.local/share/claude/versions/2.1.144`) instead of the wrapper name
    `claude`, so basename-only checks miss live background agents.
    """
    if not comm:
        return False
    name = str(comm).rsplit("/", 1)[-1]
    if name == "claude":
        return True
    try:
        path = Path(comm).expanduser()
        versions_dir = Path.home() / ".local" / "share" / "claude" / "versions"
        path.resolve(strict=False).relative_to(versions_dir.resolve(strict=False))
    except (OSError, ValueError):
        return False
    return bool(re.match(r"^\d+\.\d+\.\d+(?:[-+].*)?$", name))


@_ttl_memo(3.0)
def _load_session_registry():
    """Read ~/.claude/sessions/*.json and return {session_id: {pid, cwd, ...}}.

    Claude Code writes one JSON file per running process with its current
    sessionId, giving us an authoritative pid↔session mapping.

    Staleness filter: we verify the pid still belongs to a `claude` process
    (not just that the pid exists — OSes recycle pids, so a dead claude's
    pid might be reused by something unrelated, which would silently point
    our Jump button at the wrong terminal).
    """
    registry = {}
    if not SESSIONS_REGISTRY.is_dir():
        return registry
    # Build a set of currently-live claude pids in one ps call
    live_claude_pids = set()
    try:
        ps_out = subprocess.run(
            ["ps", "-A", "-o", "pid=,comm="],
            capture_output=True, text=True, timeout=2,
        )
        for line in ps_out.stdout.splitlines():
            parts = line.strip().split(None, 1)
            if len(parts) == 2 and _process_comm_is_claude(parts[1]):
                try:
                    live_claude_pids.add(int(parts[0]))
                except ValueError:
                    pass
    except (subprocess.TimeoutExpired, FileNotFoundError, OSError):
        pass

    try:
        session_files = list(SESSIONS_REGISTRY.iterdir())
    except OSError:
        return registry
    for f in session_files:
        if not f.name.endswith(".json") or not f.is_file():
            continue
        try:
            data = json.loads(f.read_text())
        except (OSError, json.JSONDecodeError):
            continue
        sid = data.get("sessionId")
        try:
            pid = int(data.get("pid"))
        except (TypeError, ValueError):
            continue
        if not sid:
            continue
        if pid not in live_claude_pids:
            continue  # stale: pid dead or reassigned to a non-claude
        registry[sid] = data
    return registry


def session_live_status(session_id, session_cwd):
    """Look up a session's running process via ~/.claude/sessions/<pid>.json.

    Returns dict {live, pid, tty, cwd, terminal_app, recently_written}.
    The registry gives us an authoritative pid↔session mapping written by
    Claude Code itself — no more cwd-based heuristics.
    """
    result = {
        "session_id": session_id,
        "live": False,
        "pid": None,
        "tty": None,
        "terminal_app": None,
        "status": None,
        "kind": None,
        "job_id": None,
        "agent": None,
        "recently_written": False,
        "ambiguous": False,
        "match_count": 0,
    }
    if not session_id:
        return result

    if _is_codex_session(session_id):
        path = _resolve_codex_rollout_path(session_id)
        if path:
            try:
                result["recently_written"] = (time.time() - path.stat().st_mtime) < 300
            except OSError:
                pass
        registry_known = _spawn_registry_has_session(session_id, "codex")
        entry = _live_spawn_registry_entry_for_session(session_id, "codex")
        if not entry:
            entry = _find_live_spawn_entry_for_session(session_id)
        if entry:
            pid = entry["pid"]
            result["pid"] = pid
            result["tty"] = _process_tty(pid)
            result["cwd"] = _proc_cwd(pid) or entry.get("cwd") or session_cwd
            result["terminal_app"], _term_pid = _proc_ancestor_terminal(pid)
            result["live"] = True
            result["match_count"] = 1
            return result
        if not session_cwd:
            session_cwd = find_session_cwd(session_id)
        exact_matches = []
        cwd_matches = []
        for p in find_live_codex_processes():
            cmd = p.get("command") or ""
            if _command_targets_engine_session(cmd, session_id, "codex"):
                exact_matches.append(p)
            elif not registry_known and session_cwd and p.get("cwd") == session_cwd:
                cwd_matches.append(p)
        matches = exact_matches or cwd_matches
        result["match_count"] = len(matches)
        if not matches:
            return result
        if len(matches) > 1:
            exact = [
                p for p in matches
                if _command_targets_engine_session(p.get("command") or "", session_id, "codex")
            ]
            if len(exact) == 1:
                matches = exact
            else:
                result["ambiguous"] = True
                return result
        match = matches[0]
        result["pid"] = match["pid"]
        result["tty"] = match.get("tty")
        result["terminal_app"] = match.get("terminal_app")
        result["live"] = True
        return result

    if _is_gemini_session(session_id):
        path = _resolve_gemini_chat_path(session_id)
        if path:
            try:
                result["recently_written"] = (time.time() - path.stat().st_mtime) < 300
            except OSError:
                pass
        registry_known = _spawn_registry_has_session(session_id, "gemini")
        entry = _live_spawn_registry_entry_for_session(session_id, "gemini")
        if not entry:
            entry = _find_live_spawn_entry_for_session(session_id)
        if entry:
            pid = entry["pid"]
            result["pid"] = pid
            result["tty"] = _process_tty(pid)
            result["cwd"] = _proc_cwd(pid) or entry.get("cwd") or session_cwd
            result["terminal_app"], _term_pid = _proc_ancestor_terminal(pid)
            result["live"] = True
            result["match_count"] = 1
            return result
        if not session_cwd:
            session_cwd = find_session_cwd(session_id)
        exact_matches = []
        cwd_matches = []
        for p in find_live_gemini_processes():
            cmd = p.get("command") or ""
            if _command_targets_engine_session(cmd, session_id, "gemini"):
                exact_matches.append(p)
            elif not registry_known and session_cwd and p.get("cwd") == session_cwd:
                cwd_matches.append(p)
        matches = exact_matches or cwd_matches
        result["match_count"] = len(matches)
        if not matches:
            return result
        if len(matches) > 1:
            exact = [
                p for p in matches
                if _command_targets_engine_session(p.get("command") or "", session_id, "gemini")
            ]
            if len(exact) == 1:
                matches = exact
            else:
                result["ambiguous"] = True
                return result
        match = matches[0]
        result["pid"] = match["pid"]
        result["tty"] = match.get("tty")
        result["terminal_app"] = match.get("terminal_app")
        result["live"] = True
        return result

    if _is_cursor_session(session_id):
        path = _cursor_transcript_path(session_id)
        if path:
            try:
                result["recently_written"] = (time.time() - path.stat().st_mtime) < 300
            except OSError:
                pass
        registry_known = _spawn_registry_has_session(session_id, "cursor")
        entry = _live_spawn_registry_entry_for_session(session_id, "cursor")
        if entry:
            pid = entry["pid"]
            result["pid"] = pid
            result["tty"] = _process_tty(pid)
            result["cwd"] = _proc_cwd(pid) or entry.get("cwd") or session_cwd
            result["terminal_app"], _term_pid = _proc_ancestor_terminal(pid)
            result["live"] = True
            result["match_count"] = 1
            return result
        if not session_cwd:
            session_cwd = find_session_cwd(session_id)
        exact_matches = []
        cwd_matches = []
        for p in find_live_cursor_processes():
            cmd = p.get("command") or ""
            if _command_targets_engine_session(cmd, session_id, "cursor"):
                exact_matches.append(p)
            elif not registry_known and session_cwd and p.get("cwd") == session_cwd:
                cwd_matches.append(p)
        matches = exact_matches or cwd_matches
        result["match_count"] = len(matches)
        if not matches:
            return result
        if len(matches) > 1:
            exact = [
                p for p in matches
                if _command_targets_engine_session(p.get("command") or "", session_id, "cursor")
            ]
            if len(exact) == 1:
                matches = exact
            else:
                result["ambiguous"] = True
                return result
        match = matches[0]
        result["pid"] = match["pid"]
        result["tty"] = match.get("tty")
        result["terminal_app"] = match.get("terminal_app")
        result["live"] = True
        return result

    if _is_antigravity_session(session_id):
        path = _antigravity_transcript_path(session_id)
        if path:
            try:
                result["recently_written"] = (time.time() - path.stat().st_mtime) < 300
            except OSError:
                pass
        registry_known = _spawn_registry_has_session(session_id, "antigravity")
        entry = _live_spawn_registry_entry_for_session(session_id, "antigravity")
        if entry:
            pid = entry["pid"]
            result["pid"] = pid
            result["tty"] = _process_tty(pid)
            result["cwd"] = _proc_cwd(pid) or entry.get("cwd") or session_cwd
            result["terminal_app"], _term_pid = _proc_ancestor_terminal(pid)
            result["live"] = True
            result["match_count"] = 1
            return result
        if not session_cwd:
            session_cwd = find_session_cwd(session_id)
        exact_matches = []
        cwd_matches = []
        for p in find_live_antigravity_processes():
            cmd = p.get("command") or ""
            if _command_targets_engine_session(cmd, session_id, "antigravity"):
                exact_matches.append(p)
            elif not registry_known and session_cwd and p.get("cwd") == session_cwd:
                cwd_matches.append(p)
        matches = exact_matches or cwd_matches
        result["match_count"] = len(matches)
        if not matches:
            return result
        if len(matches) > 1:
            exact = [
                p for p in matches
                if _command_targets_engine_session(p.get("command") or "", session_id, "antigravity")
            ]
            if len(exact) == 1:
                matches = exact
            else:
                result["ambiguous"] = True
                return result
        match = matches[0]
        result["pid"] = match["pid"]
        result["tty"] = match.get("tty")
        result["terminal_app"] = match.get("terminal_app")
        result["live"] = True
        return result

    # Recency check on the .jsonl file (for the "is actively being used" signal)
    jsonl_name = session_id + ".jsonl"
    recent = False
    if PROJECTS_ROOT.is_dir():
        now = time.time()
        for project_dir in PROJECTS_ROOT.iterdir():
            if not project_dir.is_dir():
                continue
            candidate = project_dir / jsonl_name
            if candidate.is_file():
                try:
                    if now - candidate.stat().st_mtime < 300:  # 5 min
                        recent = True
                except OSError:
                    pass
                break
    result["recently_written"] = recent

    # Primary lookup: session registry (authoritative)
    registry = _load_session_registry()
    entry = registry.get(session_id)
    if entry:
        try:
            pid = int(entry["pid"])
        except (TypeError, ValueError, KeyError):
            pid = 0
        # CCC-45: only trust the registry entry when its pid is ACTUALLY alive.
        # A stale ~/.claude/sessions/<pid>.json — claude exited without cleanup
        # (e.g. after a /clear fork) — otherwise reported the session "live"
        # with a tty, so CCC keystroked input into a dead terminal / the ether.
        # When the pid is gone, fall through to scanning real running processes
        # (authoritative) instead of trusting the registry blindly.
        if pid and _pid_alive(pid):
            result["pid"] = pid
            result["match_count"] = 1
            result["status"] = entry.get("status")
            result["kind"] = entry.get("kind")
            result["job_id"] = entry.get("jobId")
            result["agent"] = entry.get("agent")
            # Hydrate tty + terminal_app from the live pid
            try:
                ps_out = subprocess.run(
                    ["ps", "-o", "tty=", "-p", str(pid)],
                    capture_output=True, text=True, timeout=1,
                )
                tty = (ps_out.stdout or "").strip()
                if tty and tty != "??":
                    result["tty"] = tty
            except (subprocess.TimeoutExpired, FileNotFoundError, OSError):
                pass
            term_app, _ = _proc_ancestor_terminal(pid)
            result["terminal_app"] = term_app
            result["live"] = True
            return result

    # Fallback: cwd-based matching (for older claude versions or missing registry)
    if not session_cwd:
        return result
    procs = find_live_claude_processes()
    matches = [p for p in procs if p["cwd"] == session_cwd]
    result["match_count"] = len(matches)
    if not matches:
        return result
    if len(matches) > 1:
        result["ambiguous"] = True
        return result
    match = matches[0]
    result["pid"] = match["pid"]
    result["tty"] = match["tty"]
    result["terminal_app"] = match["terminal_app"]
    if recent:
        result["live"] = True
    return result


def _preferred_terminal_app():
    """Pick a terminal to launch new sessions in.

    Prefers the terminal app that's hosting the newest running claude process,
    falling back to Terminal.app (which is always available on macOS).
    """
    procs = find_live_claude_processes()
    # Prefer known terminals
    for p in procs:
        if p.get("terminal_app") in _TERMINAL_APPS.values() or p.get("terminal_app") in ("Terminal", "iTerm2"):
            return p["terminal_app"]
    return "Terminal"


def _shell_quote(s):
    return "'" + str(s).replace("'", "'\\''") + "'"


def _build_resume_command(session_id, cwd, cwd_exists):
    """Same logic as the frontend buildResumeCommand — keep them in sync."""
    is_codex = _is_codex_session(session_id)
    is_gemini = _is_gemini_session(session_id)
    is_antigravity = _is_antigravity_session(session_id)
    if is_codex:
        resume_cmd = f"codex resume {session_id}"
    elif is_gemini:
        resume_cmd = f"gemini --resume {session_id}"
    elif _is_cursor_session(session_id):
        resume_cmd = f"cursor-agent --resume {session_id}"
    elif is_antigravity:
        # Two flavors of Antigravity session live on disk:
        #   1. AGY CLI sessions — have a `.pb` in ~/.gemini/antigravity-cli/
        #      conversations/. `agy --conversation <sid>` can resume them.
        #   2. Antigravity App sessions — live in ~/.gemini/antigravity/
        #      conversations/ only. The CLI cannot import these; running
        #      `agy --conversation <sid>` against them silently starts a
        #      fresh AGY chat with a confusing "not in conversation store"
        #      message. For app-only sessions we instead open Antigravity.app
        #      (so the user can pick up the session there) and drop the user
        #      into a login shell at the session's cwd — useful starting
        #      point, no misleading auto-exec into a stranger AGY chat.
        resolved = _resolve_antigravity_bin()
        cli_conversation = _antigravity_cli_conversation_path(session_id)
        cli_resumable = bool(cli_conversation and cli_conversation.is_file())
        if cli_resumable and resolved.get("available"):
            resume_cmd = (
                "echo " + _shell_quote("CCC: opening AGY conversation in the TUI.")
                + " && exec " + _antigravity_shell_command(resolved)
                + " --conversation " + _shell_quote(session_id)
            )
        elif _antigravity_app_conversation_path(session_id):
            # App-only session — open Antigravity.app (best-effort) and leave
            # the user at a shell. We deliberately do NOT exec into `agy`:
            # `agy --conversation <sid>` against an app-only id silently
            # starts a fresh AGY chat which is more confusing than helpful.
            # Always reach the final `exec`, even if `open -a Antigravity`
            # fails (no app installed), hence `; ` before exec.
            resume_cmd = (
                "echo " + _shell_quote(
                    "CCC: this Antigravity session lives in the app, not the AGY CLI. "
                    "Opening Antigravity.app so you can resume it there. "
                    "Shell stays at the session cwd."
                )
                + "; open -a Antigravity >/dev/null 2>&1 || true"
                + "; exec ${SHELL:-/bin/zsh} -l"
            )
        elif resolved.get("available"):
            # Antigravity session but neither CLI-store nor App-store has it
            # (rare — e.g. brain-only transcript). Skip the auto-exec into
            # AGY entirely so the user doesn't end up in an unrelated chat.
            resume_cmd = (
                "echo " + _shell_quote(
                    "CCC: this Antigravity session has no resumable conversation "
                    "(neither AGY CLI nor the app store has it). "
                    "Open Antigravity manually if you want to continue it."
                )
                + "; exec ${SHELL:-/bin/zsh} -l"
            )
        else:
            resume_cmd = (
                "echo " + _shell_quote(resolved.get("reason") or "Antigravity CLI not found.")
                + "; exec ${SHELL:-/bin/zsh} -l"
            )
    else:
        resume_cmd = f"claude --resume {session_id} --dangerously-skip-permissions"
    if not cwd:
        return resume_cmd
    q_cwd = _shell_quote(cwd)
    if cwd_exists:
        return f"cd {q_cwd} && {resume_cmd}"
    # Worktree recreation fallback
    m = re.search(r"/\.claude/worktrees/(.+)$", cwd)
    if m:
        branch = m.group(1)
        repo_base = cwd.split("/.claude/worktrees/")[0]
        q_repo = _shell_quote(repo_base)
        q_branch = _shell_quote(branch)
        return (
            f"(cd {q_repo} && git worktree add {q_cwd} {q_branch} 2>/dev/null "
            f"|| git worktree add {q_cwd} -b {q_branch} origin/main) "
            f"&& cd {q_cwd} && {resume_cmd}"
        )
    return f"cd {q_cwd} && {resume_cmd}"


# UUID-format check — Claude Desktop's deep-link handler validates the
# session ID against a UUID regex internally and silently drops anything
# else. We pre-check so the UI gets a clear error instead of an opaque
# "nothing happened".
_SESSION_UUID_RE = re.compile(
    r"^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$",
    re.IGNORECASE,
)


def open_session_in_claude_desktop(session_id):
    """Open the macOS Claude Desktop app and resume `session_id`.

    Uses the registered `claude://resume?session=<uuid>` deep-link, which
    the desktop app handles by importing the CLI session and navigating
    to it. macOS only — relies on `open(1)`.

    Returns {ok, error?, url?}.
    """
    if not session_id:
        return {"ok": False, "error": "missing session_id"}
    if not _SESSION_UUID_RE.match(session_id):
        return {"ok": False, "error": "invalid session_id (expected UUID)"}
    if sys.platform != "darwin":
        return {"ok": False, "error": "Claude Desktop deep-link is macOS-only"}
    url = f"claude://resume?session={session_id}"
    try:
        ctx = repo_from_session(session_id)
        log_dir = repo_log_dir(ctx["repo_path"])
        log_dir.mkdir(parents=True, exist_ok=True)
        log_path = log_dir / f"desktop-{session_id[:8]}.log"
        lf = open(log_path, "w")
        subprocess.Popen(["open", url], stdout=lf, stderr=lf)
    except RepoContextError as e:
        return e.as_payload()
    except (FileNotFoundError, OSError) as e:
        print(f"open_session_in_claude_desktop: {e!r}", file=sys.stderr, flush=True)
        return {"ok": False, "error": "could not launch Claude Desktop", "url": url}
    return {"ok": True, "url": url}


def open_session_in_codex_desktop(session_id, cwd=None):
    """Open the macOS Codex app for a Codex session.

    Codex.app registers a `codex://` URL scheme. We mirror the Claude
    Desktop launch path with a best-effort resume URL so the UI can expose a
    distinct app destination next to the terminal fallback.
    """
    if not session_id:
        return {"ok": False, "error": "missing session_id"}
    if not _is_codex_session(session_id):
        return {"ok": False, "error": "Codex launch only handles Codex sessions"}
    if sys.platform != "darwin":
        return {"ok": False, "error": "Codex app launch is macOS-only"}
    params = {"session": session_id}
    if cwd:
        params["cwd"] = cwd
    url = "codex://resume?" + urllib.parse.urlencode(params)
    try:
        ctx = repo_from_session(session_id)
        log_dir = repo_log_dir(ctx["repo_path"])
        log_dir.mkdir(parents=True, exist_ok=True)
        log_path = log_dir / f"codex-desktop-{session_id[:8]}.log"
        lf = open(log_path, "w")
        subprocess.Popen(["open", url], stdout=lf, stderr=lf)
    except RepoContextError as e:
        return e.as_payload()
    except (FileNotFoundError, OSError) as e:
        print(f"open_session_in_codex_desktop: {e!r}", file=sys.stderr, flush=True)
        return {"ok": False, "error": "could not launch Codex", "url": url}
    return {"ok": True, "url": url}


def launch_terminal_for_session(session_id, cwd=None, terminal_app=None, post_slash_commands=None):
    """Open a new terminal window and run the resume command for this session.

    Idempotent: if a live claude process with a TTY already exists for this
    session, bring that terminal to the front instead of opening a new one.
    Prevents the "I clicked Launch and got two terminals" race.

    Returns {ok, terminal_app, command, error?, existing?}.
    """
    if not session_id:
        return {"ok": False, "error": "missing session_id"}
    post_slash_commands = [
        str(cmd).strip()
        for cmd in (post_slash_commands or [])
        if str(cmd or "").strip()
    ]
    # Pre-check: is there already a live claude --resume on this session with a tty?
    try:
        existing = session_live_status(session_id, cwd) or {}
        if existing.get("live") and existing.get("tty"):
            tty = existing.get("tty")
            term_app = existing.get("terminal_app") or _preferred_terminal_app()
            jr = focus_terminal_by_tty(tty, term_app)
            post_results = []
            if jr.get("ok") and post_slash_commands:
                for command_text in post_slash_commands:
                    post_results.append(inject_input_via_keystroke(tty, term_app, command_text))
            return {
                "ok": bool(jr.get("ok")) and all(r.get("ok") for r in post_results),
                "terminal_app": term_app,
                "existing": True,
                "tty": tty,
                "note": "Live terminal already attached — focused it instead of opening a new one.",
                "post_results": post_results,
            }
    except Exception:
        pass  # fall through to the normal launch path
    if cwd is None:
        cwd = find_session_cwd(session_id)
    try:
        ctx = repo_from_session(session_id)
    except RepoContextError as e:
        return e.as_payload()
    if not cwd:
        cwd = ctx["cwd"]
    cwd_exists = bool(cwd and Path(cwd).is_dir())
    is_codex = _is_codex_session(session_id)
    is_non_claude_engine = is_codex or _is_gemini_session(session_id) or _is_antigravity_session(session_id)
    command = _build_resume_command(session_id, cwd, cwd_exists)
    target = terminal_app or _preferred_terminal_app()

    # AppleScript string needs the command embedded; escape backslashes and
    # double quotes for the AppleScript literal.
    def as_literal(s):
        return s.replace("\\", "\\\\").replace('"', '\\"')
    cmd_lit = as_literal(command)

    # Use a human-readable name for the terminal tab. Look it up cheaply: a
    # user rename override, else the title the parser derives from this
    # session's own transcript tail (custom-title / agent-name / ai-title),
    # which _extract_tail_meta caches by (mtime,size). This previously called
    # find_all_sessions(ctx["repo_path"]), which rebuilds the ENTIRE repo
    # session list (seconds — the dominant synchronous cost of a launch, and
    # far worse under load) just to read one row's display name.
    rename_target = None
    try:
        rename_target = _load_session_name_overrides().get(session_id)
    except Exception:
        rename_target = None
    if not rename_target:
        try:
            jsonl = _canonical_conversation_path(ctx["repo_path"], session_id)
            if jsonl and jsonl.exists():
                tm = _extract_tail_meta(jsonl)
                rename_target = (
                    tm.get("custom_title")
                    or tm.get("agent_name")
                    or tm.get("ai_title")
                )
        except Exception:
            rename_target = None
    if not rename_target:
        rename_target = (session_id or "")[:12]
    # Sanitize for AppleScript (no quotes/backslashes)
    rename_target = rename_target.replace('"', '').replace('\\', '').replace("'", "")[:60]
    color = _pick_color_for_session(rename_target)
    slash_commands = []
    if not is_non_claude_engine:
        slash_commands = [f"/rename {rename_target}", f"/color {color}"]
        slash_commands.extend(post_slash_commands)

    def slash_sequence(process_name, activate_block):
        chunks = []
        for idx, command_text in enumerate(slash_commands):
            command_lit = as_literal(command_text)
            chunks.append(activate_block)
            chunks.append("delay 0.3" if idx == 0 else "delay 0.2")
            chunks.append(f'''
        tell application "System Events"
          tell process "{process_name}"
            keystroke "{command_lit}"
            delay 0.25
            key code 36
          end tell
        end tell
        delay 0.7
        ''')
        return "\n".join(chunks)

    if target == "iTerm2":
        if is_non_claude_engine:
            script = f'''
            tell application "iTerm2"
              activate
              set newWin to (create window with default profile)
              tell current session of newWin
                write text "{cmd_lit}"
              end tell
            end tell
            return "ok"
            '''
        else:
            command_sequence = slash_sequence(
                "iTerm2",
                'tell application "iTerm2" to activate',
            )
            script = f'''
        tell application "iTerm2"
          activate
          set newWin to (create window with default profile)
          tell current session of newWin
            write text "{cmd_lit}"
          end tell
        end tell
        delay 2.0
        {command_sequence}
        return "ok"
        '''
    else:
        # Terminal.app: explicitly create a new window, hold onto it, and keep
        # it frontmost across the keystrokes. `do script` returns a tab whose
        # window we can reference.
        if is_non_claude_engine:
            script = f'''
            tell application "Terminal"
              activate
              do script "{cmd_lit}"
            end tell
            return "ok"
            '''
        else:
            script = f'''
        set winId to 0
        tell application "Terminal"
          activate
          set newTab to do script "{cmd_lit}"
          set winId to id of window 1
        end tell
        delay 2.0
        {slash_sequence(
            "Terminal",
            'tell application "Terminal"\n'
            '          activate\n'
            '          set frontmost of (first window whose id is winId) to true\n'
            '        end tell',
        )}
        return "ok"
        '''

    # Run the osascript in the background (captures stderr to a log for debugging).
    try:
        log_dir = repo_log_dir(ctx["repo_path"])
        log_dir.mkdir(parents=True, exist_ok=True)
        log_path = log_dir / f"jump-{(session_id or 'x')[:8]}.log"
        lf = open(log_path, "w")
        subprocess.Popen(["osascript", "-e", script], stdout=lf, stderr=lf)
    except (FileNotFoundError, OSError) as e:
        return {"ok": False, "error": str(e)}
    result = {"ok": True, "terminal_app": target, "command": command}
    # GH #71 (mechanism 2) — the terminal we just opened (`claude --resume`)
    # becomes the live process driving this session; a previously-spawned idle
    # headless is now a stale fallback. Retire it right here so CCC won't route
    # to it after the terminal closes. Claude-only and never a busy headless.
    if not is_non_claude_engine:
        retired = _retire_idle_headless_for_session(
            session_id, reason="launch-terminal", defer_if_busy=True)
        if retired.get("retired"):
            result["retired_headless_pid"] = retired.get("pid")
        elif retired.get("deferred"):
            # Busy mid-turn — the watcher retires it the moment it goes idle.
            result["headless_retire_deferred"] = True
    return result


def inject_input_via_keystroke(tty, terminal_app, text, submit_key="return"):
    """Find the terminal tab for `tty`, then send `text` + a submit key to it.

    Two stages, both inside one osascript call:
      1. Native terminal input API (`do script` for Terminal.app,
         `write text` for iTerm2) types the text into the TTY without
         needing System Events keystroke permissions for the body.
      2. Activate the terminal app and emit a real keypress via System
         Events so the TUI sees submission. Return submits normal input;
         Tab queues Codex slash commands while a turn is running.

    Stage 2 briefly steals focus; we capture the previously-frontmost
    process id and restore it at the end so the user's browser doesn't
    stay buried.
    """
    submit_key = str(submit_key or "return").strip().lower()
    submit_key_code = 48 if submit_key == "tab" else 36
    submit_label = "Tab" if submit_key_code == 48 else "Return"
    tty_short = tty.replace("/dev/", "")
    tty_full = "/dev/" + tty_short

    # Escape text for AppleScript string literal
    def as_lit(s):
        return s.replace("\\", "\\\\").replace('"', '\\"')
    text_lit = as_lit(text)

    def failure_payload(raw_error, *, timed_out=False):
        detail = (raw_error or "").strip()
        low = detail.lower()
        payload = {
            "ok": False,
            "via": "terminal-control",
            "tty": tty,
            "terminal_app": terminal_app,
            "error": detail or "AppleScript failed",
        }
        if timed_out or ("osascript" in low and "timed out" in low):
            payload.update({
                "code": "macos_automation_timeout",
                "error": (
                    f"macOS did not finish the CCC terminal-control request to "
                    f"{terminal_app}. If a permission dialog mentions "
                    "app_mode_loader, app_node, Python, or osascript, click "
                    "Allow; then grant the app running CCC Automation and "
                    "Accessibility access for Terminal and System Events if "
                    "macOS asks again."
                ),
                "detail": detail,
            })
        elif "not allowed to send keystrokes" in low or ("system events" in low and "1002" in low):
            payload.update({
                "code": "macos_keystroke_permission",
                "error": (
                    "macOS blocked CCC from typing into the terminal. Allow the app "
                    "running CCC to use Accessibility in System Settings > Privacy "
                    "& Security, then retry."
                ),
                "detail": detail,
            })
        elif (
            "not authorized to send apple events" in low
            or "not authorised to send apple events" in low
            or "not permitted to send apple events" in low
            or "automation" in low and "not" in low and "allow" in low
        ):
            payload.update({
                "code": "macos_automation_permission",
                "error": (
                    f"macOS blocked CCC from controlling {terminal_app}. Allow the "
                    f"app running CCC to control {terminal_app} in System Settings "
                    "> Privacy & Security > Automation, then retry."
                ),
                "detail": detail,
            })
        return payload

    if terminal_app == "iTerm2":
        # iTerm2: find the session by tty, write the body via the
        # native session API (no focus needed), then activate iTerm and
        # emit a real submit keystroke so the TUI accepts it.
        script = f'''
        set prevPid to 0
        try
          tell application "System Events" to set prevPid to unix id of first application process whose frontmost is true
        end try
        tell application "iTerm2"
          set foundSession to missing value
          set winCount to count of windows
          repeat with i from 1 to winCount
            try
              set w to window i
              repeat with j from 1 to (count of tabs of w)
                try
                  set t to tab j of w
                  repeat with s in sessions of t
                    try
                      if tty of s is "{tty_full}" then
                        set foundSession to s
                        select w
                        tell w to select t
                        select s
                        exit repeat
                      end if
                    end try
                  end repeat
                  if foundSession is not missing value then exit repeat
                end try
              end repeat
              if foundSession is not missing value then exit repeat
            end try
          end repeat
          if foundSession is missing value then return "notfound"
          tell foundSession to write text "{text_lit}"
          activate
        end tell
        delay 0.15
        set submitErr to ""
        try
          tell application "System Events"
            tell process "iTerm2"
              key code {submit_key_code}
            end tell
          end tell
        on error errMsg
          set submitErr to errMsg
        end try
        delay 0.05
        try
          if prevPid is not 0 then
            tell application "System Events" to set frontmost of first application process whose unix id is prevPid to true
          end if
        end try
        if submitErr is not "" then return "ok-no-submit:" & submitErr
        return "ok"
        '''
    else:
        # Terminal.app: find the tab by tty, focus it, send text through
        # Terminal's native `do script ... in tab` API, then activate
        # Terminal and emit a real submit keystroke via System Events so
        # the TUI accepts it. Target "process Terminal" explicitly so the
        # keystroke reaches the right process even if focus briefly shifts.
        script = f'''
        set prevPid to 0
        try
          tell application "System Events" to set prevPid to unix id of first application process whose frontmost is true
        end try
        tell application "Terminal"
          set foundWin to missing value
          set foundTab to missing value
          set winCount to count of windows
          repeat with i from 1 to winCount
            try
              set w to window i
              repeat with j from 1 to (count of tabs of w)
                try
                  set t to tab j of w
                  if tty of t is "{tty_full}" then
                    set foundWin to w
                    set foundTab to t
                    exit repeat
                  end if
                end try
              end repeat
              if foundTab is not missing value then exit repeat
            end try
          end repeat
          if foundTab is missing value then return "notfound"
          do script "{text_lit}" in foundTab
          activate
          set index of foundWin to 1
          set selected of foundTab to true
        end tell
        delay 0.15
        set submitErr to ""
        try
          tell application "System Events"
            tell process "Terminal"
              key code {submit_key_code}
            end tell
          end tell
        on error errMsg
          set submitErr to errMsg
        end try
        delay 0.05
        try
          if prevPid is not 0 then
            tell application "System Events" to set frontmost of first application process whose unix id is prevPid to true
          end if
        end try
        if submitErr is not "" then return "ok-no-submit:" & submitErr
        return "ok"
        '''

    def _run():
        timeout_s = 5
        try:
            return subprocess.run(
                ["osascript", "-e", script],
                capture_output=True, text=True, timeout=timeout_s,
            )
        except subprocess.TimeoutExpired:
            return failure_payload(
                f"osascript timed out after {timeout_s}s while controlling {terminal_app}",
                timed_out=True,
            )
        except FileNotFoundError as e:
            return e

    out = _run()
    if isinstance(out, dict):
        return out
    if isinstance(out, Exception):
        return failure_payload(str(out))
    result_str = (out.stdout or "").strip()
    # Auto-retry once on notfound — the tab often becomes findable ~200ms later
    # after a focus/Spaces transition settles.
    if result_str == "notfound":
        time.sleep(0.2)
        out = _run()
        if isinstance(out, dict):
            return out
        if isinstance(out, Exception):
            return failure_payload(str(out))
        result_str = (out.stdout or "").strip()
    if out.returncode != 0:
        return failure_payload((out.stderr or "").strip() or "AppleScript failed")
    if result_str.startswith("ok-no-submit:"):
        # Body was typed via `do script` / `write text` but the System
        # Events Return keystroke was rejected — typically because
        # macOS Accessibility hasn't been granted to osascript. The
        # text sits in Claude's TUI input buffer; the user has to
        # press Enter (or grant the permission and retry will start
        # auto-submitting).
        detail = result_str.split(":", 1)[1].strip()
        return {
            "ok": True,
            "via": "terminal-control",
            "tty": tty,
            "terminal_app": terminal_app,
            "submitted": False,
            "warning": (
                f"Text typed but auto-submit with {submit_label} was blocked. Grant "
                "Accessibility to osascript in System Settings > "
                "Privacy & Security > Accessibility, then retry."
            ),
            "code": "macos_keystroke_permission",
            "detail": detail,
        }
    if result_str == "notfound":
        return {
            "ok": False,
            "via": "terminal-control",
            "tty": tty,
            "terminal_app": terminal_app,
            "error": (
                f"No {terminal_app} tab found for {tty_short}; the tab may be "
                "hidden, on another Space, or behind a fullscreen app"
            ),
        }
    return {
        "ok": True,
        "tty": tty,
        "terminal_app": terminal_app,
        "via": "terminal-control",
        "submitted": True,
        "submit_key": "tab" if submit_key_code == 48 else "return",
    }


def interrupt_input_via_keystroke(tty, terminal_app):
    """Focus the terminal tab for `tty`, then send Esc (key code 53) via System Events.

    Mirrors `inject_input_via_keystroke` but delivers an interrupt instead of
    text — Claude Code's TUI treats Esc as cancel-the-current-stream when a
    response is in flight, and as clear-input-buffer when one isn't. Same focus
    + restore-prev-process dance so the user's browser doesn't stay buried.
    """
    tty_short = tty.replace("/dev/", "")
    tty_full = "/dev/" + tty_short

    if terminal_app == "iTerm2":
        script = f'''
        set prevPid to 0
        try
          tell application "System Events" to set prevPid to unix id of first application process whose frontmost is true
        end try
        tell application "iTerm2"
          set found to false
          set winCount to count of windows
          repeat with i from 1 to winCount
            try
              set w to window i
              repeat with j from 1 to (count of tabs of w)
                try
                  set t to tab j of w
                  repeat with s in sessions of t
                    try
                      if tty of s is "{tty_full}" then
                        select w
                        tell w to select t
                        select s
                        set found to true
                        exit repeat
                      end if
                    end try
                  end repeat
                  if found then exit repeat
                end try
              end repeat
              if found then exit repeat
            end try
          end repeat
          if not found then return "notfound"
          activate
        end tell
        delay 0.15
        tell application "System Events"
          tell process "iTerm2"
            key code 53
          end tell
        end tell
        delay 0.08
        try
          if prevPid is not 0 then
            tell application "System Events" to set frontmost of first application process whose unix id is prevPid to true
          end if
        end try
        return "ok"
        '''
    else:
        script = f'''
        set prevPid to 0
        try
          tell application "System Events" to set prevPid to unix id of first application process whose frontmost is true
        end try
        tell application "Terminal"
          set foundWin to missing value
          set foundTab to missing value
          set winCount to count of windows
          repeat with i from 1 to winCount
            try
              set w to window i
              repeat with j from 1 to (count of tabs of w)
                try
                  set t to tab j of w
                  if tty of t is "{tty_full}" then
                    set foundWin to w
                    set foundTab to t
                    exit repeat
                  end if
                end try
              end repeat
              if foundTab is not missing value then exit repeat
            end try
          end repeat
          if foundTab is missing value then return "notfound"
          activate
          set index of foundWin to 1
          set selected of foundTab to true
        end tell
        delay 0.15
        tell application "System Events"
          tell process "Terminal"
            key code 53
          end tell
        end tell
        delay 0.08
        try
          if prevPid is not 0 then
            tell application "System Events" to set frontmost of first application process whose unix id is prevPid to true
          end if
        end try
        return "ok"
        '''

    def _run():
        try:
            return subprocess.run(
                ["osascript", "-e", script],
                capture_output=True, text=True, timeout=5,
            )
        except (subprocess.TimeoutExpired, FileNotFoundError) as e:
            return e

    out = _run()
    if isinstance(out, Exception):
        return {"ok": False, "error": str(out)}
    result_str = (out.stdout or "").strip()
    if result_str == "notfound":
        time.sleep(0.2)
        out = _run()
        if isinstance(out, Exception):
            return {"ok": False, "error": str(out)}
        result_str = (out.stdout or "").strip()
    if out.returncode != 0:
        return {"ok": False, "error": (out.stderr or "").strip() or "AppleScript failed"}
    if result_str == "notfound":
        return {"ok": False, "error": f"No {terminal_app} tab found for {tty_short} — tab may be hidden, on another Space, or behind a fullscreen app"}
    return {"ok": True, "tty": tty}


def focus_terminal_by_tty(tty, terminal_app):
    """Bring the terminal window/tab backing `tty` to the front.

    `tty` is like "ttys008". `terminal_app` is the friendly name from
    _TERMINAL_APPS. Returns {ok, error}.
    """
    if not tty or tty == "??":
        return {"ok": False, "error": "No tty available"}
    if not terminal_app:
        return {"ok": False, "error": "Unknown terminal app"}

    tty_short = tty.replace("/dev/", "")
    tty_full = "/dev/" + tty_short

    if terminal_app == "iTerm2":
        # Defensive iteration: phantom/minimized windows can throw errors and
        # abort the whole loop. Use index-based iteration with try/on-error.
        script = f'''
        tell application "iTerm2"
          set found to false
          set winCount to count of windows
          repeat with i from 1 to winCount
            try
              set w to window i
              set tabCount to count of tabs of w
              repeat with j from 1 to tabCount
                try
                  set t to tab j of w
                  set sessList to sessions of t
                  repeat with s in sessList
                    try
                      if tty of s is "{tty_full}" then
                        select w
                        tell w to select t
                        select s
                        set found to true
                        exit repeat
                      end if
                    end try
                  end repeat
                  if found then exit repeat
                end try
              end repeat
              if found then exit repeat
            end try
          end repeat
          if found then
            activate
            return "ok"
          else
            return "notfound"
          end if
        end tell
        '''
    elif terminal_app == "Terminal":
        # Defensive iteration: Terminal.app can have phantom windows whose
        # `tabs` accessor throws, which would abort a naive `repeat with w in windows`.
        # We use index-based loops with try/on-error to skip them.
        script = f'''
        tell application "Terminal"
          set foundWin to missing value
          set foundTab to missing value
          set winCount to count of windows
          repeat with i from 1 to winCount
            try
              set w to window i
              set tabCount to count of tabs of w
              repeat with j from 1 to tabCount
                try
                  set t to tab j of w
                  if tty of t is "{tty_full}" then
                    set foundWin to w
                    set foundTab to t
                    exit repeat
                  end if
                end try
              end repeat
              if foundTab is not missing value then exit repeat
            end try
          end repeat
          if foundTab is not missing value then
            set selected of foundTab to true
            try
              set index of foundWin to 1
            end try
            activate
            return "ok"
          else
            return "notfound"
          end if
        end tell
        '''
    elif terminal_app == "Ghostty":
        # Ghostty doesn't expose tab-level AppleScript; best we can do is activate it
        script = 'tell application "Ghostty" to activate\nreturn "ok"'
    else:
        # Generic fallback: just activate the app
        script = f'tell application "{terminal_app}" to activate\nreturn "ok"'

    try:
        out = subprocess.run(
            ["osascript", "-e", script],
            capture_output=True, text=True, timeout=3,
        )
    except (subprocess.TimeoutExpired, FileNotFoundError) as e:
        return {"ok": False, "error": str(e)}
    result = (out.stdout or "").strip()
    if out.returncode != 0:
        return {"ok": False, "error": (out.stderr or "").strip() or "AppleScript failed"}
    if result == "notfound":
        return {"ok": False, "error": f"No {terminal_app} tab found for {tty_short}"}
    return {"ok": True, "terminal_app": terminal_app}


_CWD_RELOCATION_PRUNE_DIRS = {
    ".git", ".hg", ".svn", ".claude", ".codex", "__pycache__",
    "node_modules", ".next", "dist", "build", ".venv", "venv",
}


def _path_is_within(child, parent):
    try:
        c = Path(child).expanduser().resolve()
        p = Path(parent).expanduser().resolve()
        return c == p or p in c.parents
    except (OSError, ValueError, RuntimeError):
        return False


def _relocation_search_roots(session_id, missing_cwd):
    roots = []
    seen = set()

    def add(raw):
        if not raw:
            return
        try:
            p = Path(raw).expanduser().resolve()
        except (OSError, ValueError, RuntimeError):
            return
        if not p.is_dir():
            return
        # Avoid accidental whole-home scans; repo pins / marked ancestors give
        # us enough locality for moved project folders.
        try:
            if p == Path.home().resolve() or p == Path("/"):
                return
        except OSError:
            return
        s = str(p)
        if s not in seen:
            seen.add(s)
            roots.append(p)

    try:
        pin = _load_repo_pins().get(session_id)
    except Exception:
        pin = None
    add(pin)

    try:
        cwd_path = Path(missing_cwd).expanduser()
        existing = None
        for candidate in (cwd_path, *cwd_path.parents):
            if candidate.is_dir():
                existing = candidate
                break
        if existing:
            cur = existing
            for _ in range(4):
                add(cur)
                parent = cur.parent
                if parent == cur:
                    break
                cur = parent
    except (OSError, ValueError, RuntimeError):
        pass

    try:
        for repo in _known_repo_paths():
            if _path_is_within(missing_cwd, repo):
                add(repo)
    except Exception:
        pass

    return roots


def _first_existing_dir(*paths):
    """Return the first path that exists as a directory; None if none do.

    Used to pick an "effective" cwd for row metadata that may have been
    captured from a long-dead worktree path. Without this, Launch in
    Terminal would build `cd '/.../no-such-dir' && resume`, fail, and
    leave the user in their home directory.
    """
    for p in paths:
        if not p:
            continue
        try:
            if Path(p).is_dir():
                return p
        except (OSError, ValueError, RuntimeError):
            continue
    return None


def _relocate_missing_session_cwd(session_id, cwd):
    """Best-effort repair for transcripts whose recorded cwd was moved.

    Claude transcripts are immutable history, so a folder reorg can leave old
    `cwd` values pointing at a path that no longer exists. For display and
    repo-context purposes, use the transcript's own absolute tool paths as
    evidence: find a same-named directory under nearby project roots where
    those relative files now exist.
    """
    global _session_cwd_relocation_cache_dirty
    raw = str(cwd or "").strip()
    if not session_id or not raw:
        return None
    cache_key = (session_id, raw)
    if cache_key in _session_cwd_relocation_cache:
        cached = _session_cwd_relocation_cache[cache_key]
        # Negative cache: short-circuit. Positive cache: revalidate that
        # the cached target still exists — if a worktree was deleted since
        # the cache was written, drop it and fall through to a fresh walk.
        if cached is None:
            return None
        try:
            if Path(cached).is_dir():
                return cached
        except (OSError, ValueError, RuntimeError):
            pass
        with _session_cwd_relocation_cache_lock:
            _session_cwd_relocation_cache.pop(cache_key, None)
            _session_cwd_relocation_cache_dirty = True

    try:
        cwd_path = Path(raw).expanduser()
        if cwd_path.is_dir():
            result = str(cwd_path.resolve())
            with _session_cwd_relocation_cache_lock:
                _session_cwd_relocation_cache[cache_key] = result
                _session_cwd_relocation_cache_dirty = True
            return result
    except (OSError, ValueError, RuntimeError):
        with _session_cwd_relocation_cache_lock:
            _session_cwd_relocation_cache[cache_key] = None
            _session_cwd_relocation_cache_dirty = True
        return None

    # Past this point we're about to walk the filesystem. Honor the
    # per-request budget so a single cold scan can't burn 40s on
    # worktree-heavy repos. Do NOT cache the skip — let the next request
    # try again so the cache fills progressively.
    if _relocation_budget_exhausted():
        return None

    basename = cwd_path.name
    if not basename:
        with _session_cwd_relocation_cache_lock:
            _session_cwd_relocation_cache[cache_key] = None
            _session_cwd_relocation_cache_dirty = True
        return None

    try:
        file_paths, _cd_targets = _scan_session_tool_paths(session_id)
    except Exception:
        file_paths = []
    prefix = raw.rstrip("/") + "/"
    rel_paths = []
    rel_seen = set()
    for fp in file_paths:
        if not isinstance(fp, str) or not fp.startswith(prefix):
            continue
        rel = fp[len(prefix):].lstrip("/")
        if not rel or rel in rel_seen:
            continue
        rel_seen.add(rel)
        rel_paths.append(rel)
        if len(rel_paths) >= 25:
            break

    roots = _relocation_search_roots(session_id, raw)
    best = []
    candidate_seen = set()
    # Per-root visit cap. Dialed down from 8000 → 2000: even with the
    # per-request time budget guarding overall latency, a single root with
    # 8000 dirs of unrelated content can stall this loop for seconds. 2000
    # is enough to cover normal worktree layouts (BYM+Finie's worst case is
    # ~150 dirs per root) while keeping pathological roots bounded.
    try:
        visit_cap = int(os.environ.get("CCC_CWD_RELOCATION_VISIT_CAP", "2000"))
    except (TypeError, ValueError):
        visit_cap = 2000
    budget_hit = False
    for root in roots:
        if budget_hit:
            break
        visited = 0
        try:
            for dirpath, dirnames, _filenames in os.walk(root):
                visited += 1
                dirnames[:] = [
                    d for d in dirnames
                    if d not in _CWD_RELOCATION_PRUNE_DIRS and not d.startswith(".")
                ]
                if visited > visit_cap:
                    break
                if _relocation_budget_exhausted():
                    budget_hit = True
                    break
                p = Path(dirpath)
                if p.name != basename:
                    continue
                try:
                    p_key = str(p.resolve())
                except OSError:
                    p_key = str(p)
                if p_key in candidate_seen:
                    continue
                candidate_seen.add(p_key)
                score = 1 if not rel_paths else 0
                for rel in rel_paths:
                    try:
                        if (p / rel).exists():
                            score += 1
                    except OSError:
                        continue
                if score > 0:
                    best.append((score, len(p.parts), p))
        except OSError:
            continue

    # If the budget ran out mid-walk we may have an incomplete view; do not
    # cache so the next request can resume.
    if budget_hit and not best:
        return None
    if not best:
        with _session_cwd_relocation_cache_lock:
            _session_cwd_relocation_cache[cache_key] = None
            _session_cwd_relocation_cache_dirty = True
        return None
    best.sort(key=lambda item: (-item[0], item[1], str(item[2])))
    top_score = best[0][0]
    top = [p for score, _depth, p in best if score == top_score]
    if len(top) > 1 and rel_paths:
        # Multiple equally-supported targets means the transcript evidence is
        # ambiguous; keep the historical cwd rather than guessing wrong.
        with _session_cwd_relocation_cache_lock:
            _session_cwd_relocation_cache[cache_key] = None
            _session_cwd_relocation_cache_dirty = True
        return None
    try:
        result = str(top[0].resolve())
    except OSError:
        result = str(top[0])
    with _session_cwd_relocation_cache_lock:
        _session_cwd_relocation_cache[cache_key] = result
        _session_cwd_relocation_cache_dirty = True
    return result


def _resolve_session_cwd(session_id, cwd):
    if not cwd:
        return cwd
    try:
        p = Path(cwd).expanduser()
        if p.is_dir():
            return str(p.resolve())
    except (OSError, ValueError, RuntimeError):
        return cwd
    return _relocate_missing_session_cwd(session_id, cwd) or cwd


def find_session_cwd(session_id):
    """Locate the .jsonl for a session_id across ~/.claude/projects/*/ and return its cwd.

    Sessions may have been run in a worktree or other directory; `claude --resume`
    only finds them when run from the original cwd, so we need to `cd` there first.
    """
    if not session_id:
        return None
    if session_id in _session_cwd_cache:
        return _session_cwd_cache[session_id]
    codex_row = _codex_thread_row(session_id)
    if codex_row:
        cwd = codex_row.get("cwd")
        path = _codex_rollout_path_from_row(codex_row)
        if path:
            try:
                tail = _extract_codex_tail_meta(path) or {}
                cwd = tail.get("cwd") or cwd
            except Exception:
                pass
        if cwd:
            cwd = _resolve_session_cwd(session_id, cwd)
            _session_cwd_cache[session_id] = cwd
            return cwd
    gemini_path = _resolve_gemini_chat_path(session_id)
    if gemini_path:
        cwd = _gemini_project_root_for_chat(gemini_path)
        if cwd:
            cwd = _resolve_session_cwd(session_id, cwd)
            _session_cwd_cache[session_id] = cwd
            return cwd
    if _is_antigravity_session(session_id):
        cwd = _extract_antigravity_cwd(session_id)
        if cwd:
            cwd = _resolve_session_cwd(session_id, cwd)
            _session_cwd_cache[session_id] = cwd
            return cwd
    cursor_path = _cursor_transcript_path(session_id)
    if cursor_path:
        tail = _extract_cursor_tail_meta(cursor_path) or {}
        cwd = tail.get("cwd") or _cursor_cwd_from_transcript_path(cursor_path)
        if cwd:
            cwd = _resolve_session_cwd(session_id, cwd)
            _session_cwd_cache[session_id] = cwd
            return cwd
    if not PROJECTS_ROOT.is_dir():
        return None

    jsonl_name = session_id + ".jsonl"
    for project_dir in PROJECTS_ROOT.iterdir():
        if not project_dir.is_dir():
            continue
        candidate = project_dir / jsonl_name
        if not candidate.is_file():
            continue
        # Read until we find the first event with a `cwd` field
        try:
            with open(candidate, "r") as f:
                for i, line in enumerate(f):
                    if i >= 40:
                        break
                    line = line.strip()
                    if not line:
                        continue
                    try:
                        ev = json.loads(line)
                    except json.JSONDecodeError:
                        continue
                    cwd = ev.get("cwd")
                    if cwd:
                        cwd = _resolve_session_cwd(session_id, cwd)
                        _session_cwd_cache[session_id] = cwd
                        return cwd
        except (OSError, UnicodeDecodeError):
            continue
        # File matched but cwd wasn't in the first 40 lines — likely a very
        # young session that hasn't logged a user event yet. Try a sibling
        # .jsonl in the same project dir; sessions are grouped by cwd, so any
        # sibling with a cwd tells us ours too. We do NOT decode the project
        # dir name: Claude's encoding replaces '/' with '-' without escaping
        # literal hyphens, so `claude-command-center` round-trips as
        # `claude/command/center`, breaking `cd` in Launch-in-Terminal.
        for sibling in project_dir.glob("*.jsonl"):
            if sibling.name == jsonl_name:
                continue
            try:
                with open(sibling, "r") as f:
                    for i, line in enumerate(f):
                        if i >= 40:
                            break
                        line = line.strip()
                        if not line:
                            continue
                        try:
                            ev = json.loads(line)
                        except json.JSONDecodeError:
                            continue
                        cwd = ev.get("cwd")
                        if cwd:
                            cwd = _resolve_session_cwd(session_id, cwd)
                            _session_cwd_cache[session_id] = cwd
                            return cwd
            except (OSError, UnicodeDecodeError):
                continue
        # Don't cache the miss — let a later call succeed once Claude writes
        # a cwd-bearing event. Callers treat None as "resume without cd".
        return None
    return None


_issue_titles_cache = {}  # repo_path -> {"ts": float, "data": dict}

# Per-repo issue state map: repo_path -> {"ts": float, "data": {number_str: ...}}
_issue_state_cache = {}


_desktop_meta_cache = {}
_desktop_meta_cache_mtime = 0


def _claude_desktop_sessions_root():
    return (
        Path.home()
        / "Library"
        / "Application Support"
        / "Claude"
        / "claude-code-sessions"
    )


def _claude_desktop_metadata_files(root=None):
    root = root or _claude_desktop_sessions_root()
    if not root.is_dir():
        return []
    try:
        return [p for p in root.glob("*/*/local_*.json") if p.is_file()]
    except OSError:
        return []


def _claude_desktop_metadata_cache_key(root=None):
    root = root or _claude_desktop_sessions_root()
    if not root.is_dir():
        return None
    try:
        root_mtime = root.stat().st_mtime_ns
    except OSError:
        return None
    count = 0
    newest = 0
    total_mtime = 0
    total_size = 0
    for path in _claude_desktop_metadata_files(root):
        try:
            st = path.stat()
        except OSError:
            continue
        count += 1
        newest = max(newest, st.st_mtime_ns)
        total_mtime += st.st_mtime_ns
        total_size += st.st_size
    return (root_mtime, count, newest, total_mtime, total_size)


def _bust_claude_desktop_metadata_cache():
    global _desktop_meta_cache, _desktop_meta_cache_mtime
    _desktop_meta_cache = {}
    _desktop_meta_cache_mtime = 0


def _read_json_object(path):
    try:
        data = json.loads(path.read_text(encoding="utf-8"))
    except (OSError, json.JSONDecodeError, UnicodeDecodeError):
        return None
    return data if isinstance(data, dict) else None


def _load_desktop_app_metadata():
    """Read the Claude desktop app's per-session metadata overlay.

    The desktop app stores session metadata at
      ~/Library/Application Support/Claude/claude-code-sessions/<org>/<ws>/local_<sid>.json
    Each file has `cliSessionId` linking back to the CLI's .jsonl, plus
    human-friendly fields (title, model, cwd) the desktop UI surfaces.

    Returns {cliSessionId: {title, model, cwd, is_archived}}.
    Re-scans when the metadata file count, mtimes, or sizes change; cheap
    enough to call on every request.
    """
    global _desktop_meta_cache, _desktop_meta_cache_mtime
    root = _claude_desktop_sessions_root()
    cache_key = _claude_desktop_metadata_cache_key(root)
    if cache_key is None:
        _desktop_meta_cache = {}
        _desktop_meta_cache_mtime = 0
        return {}
    if cache_key == _desktop_meta_cache_mtime and _desktop_meta_cache:
        return _desktop_meta_cache
    out = {}
    for path in _claude_desktop_metadata_files(root):
        data = _read_json_object(path)
        if not data:
            continue
        cli_sid = data.get("cliSessionId")
        if not cli_sid:
            continue
        out[cli_sid] = {
            "title": data.get("title") or None,
            "model": data.get("model") or None,
            "cwd": data.get("cwd") or None,
            "is_archived": bool(data.get("isArchived")),
            "last_activity_at": data.get("lastActivityAt") or None,
        }
    _desktop_meta_cache = out
    _desktop_meta_cache_mtime = cache_key
    return out


def _claude_desktop_workspace_dirs(root=None):
    root = root or _claude_desktop_sessions_root()
    if not root.is_dir():
        return []
    dirs = []
    try:
        org_dirs = [p for p in root.iterdir() if p.is_dir()]
    except OSError:
        return []
    for org_dir in org_dirs:
        try:
            workspace_dirs = [p for p in org_dir.iterdir() if p.is_dir()]
        except OSError:
            continue
        for workspace_dir in workspace_dirs:
            newest = 0.0
            try:
                newest = workspace_dir.stat().st_mtime
            except OSError:
                pass
            for meta_path in workspace_dir.glob("local_*.json"):
                try:
                    newest = max(newest, meta_path.stat().st_mtime)
                except OSError:
                    continue
            dirs.append((newest, workspace_dir))
    dirs.sort(key=lambda item: item[0], reverse=True)
    return [p for _mtime, p in dirs]


def _claude_desktop_metadata_path_for_cli_session(session_id):
    sid = str(session_id or "").strip()
    if not sid:
        return None
    filename = f"local_{sid}.json"
    fallback = None
    for path in _claude_desktop_metadata_files():
        if path.name == filename:
            fallback = path
        data = _read_json_object(path)
        if data and data.get("cliSessionId") == sid:
            return path
    return fallback


def _claude_desktop_workspace_for_summary(summary, existing_path=None):
    if existing_path:
        try:
            parent = Path(existing_path).expanduser().resolve().parent
            if parent.is_dir():
                return parent
        except (OSError, RuntimeError, ValueError):
            pass

    dirs = _claude_desktop_workspace_dirs()
    if not dirs:
        return None

    cwd = str((summary or {}).get("cwd") or "").strip()
    if cwd:
        matches = []
        for workspace_dir in dirs:
            for path in workspace_dir.glob("local_*.json"):
                data = _read_json_object(path)
                if not data:
                    continue
                if cwd not in (data.get("cwd"), data.get("originCwd")):
                    continue
                try:
                    score = float(data.get("lastActivityAt") or 0) / 1000.0
                except (TypeError, ValueError):
                    score = 0.0
                if not score:
                    try:
                        score = path.stat().st_mtime
                    except OSError:
                        score = 0.0
                matches.append((score, workspace_dir))
        if matches:
            matches.sort(key=lambda item: item[0], reverse=True)
            return matches[0][1]

    return dirs[0]


def _claude_session_jsonl_path(session_id):
    sid = str(session_id or "").strip()
    if not sid or not PROJECTS_ROOT.is_dir():
        return None
    matches = []
    try:
        for path in PROJECTS_ROOT.glob(f"*/{sid}.jsonl"):
            if path.is_file():
                try:
                    matches.append((path.stat().st_mtime, path))
                except OSError:
                    matches.append((0.0, path))
    except (OSError, RuntimeError, ValueError):
        return None
    if not matches:
        return None
    matches.sort(key=lambda item: item[0], reverse=True)
    return matches[0][1]


def _claude_desktop_title_from_text(text, max_len=120):
    text = _strip_ccc_session_state_instruction(str(text or "")).strip()
    if not text:
        return ""
    return _prompt_fragment(text, max_len).strip()


def _claude_desktop_epoch_ms(value):
    if not value:
        return 0
    epoch = _iso_to_epoch(value) if isinstance(value, str) else None
    if epoch is None:
        try:
            epoch = float(value)
        except (TypeError, ValueError):
            return 0
        if epoch > 100000000000:
            return int(epoch)
    return int(epoch * 1000)


def _claude_session_desktop_summary(session_id, spawn_entry=None):
    sid = str(session_id or "").strip()
    entry = spawn_entry if isinstance(spawn_entry, dict) else {}
    now_ms = int(time.time() * 1000)
    started_epoch = _spawn_registry_entry_epoch(entry)
    started_ms = int(started_epoch * 1000) if started_epoch else 0
    summary = {
        "cwd": entry.get("cwd") or entry.get("repo_path") or "",
        "originCwd": entry.get("cwd") or entry.get("repo_path") or "",
        "title": (
            _claude_desktop_title_from_text(entry.get("prompt"))
            or _claude_desktop_title_from_text(entry.get("command_summary"))
            or _claude_desktop_title_from_text((entry.get("name") or "").replace("-", " "))
        ),
        "model": entry.get("model") or "",
        "createdAt": started_ms or now_ms,
        "lastActivityAt": started_ms or now_ms,
        "completedTurns": 0,
        "jsonl_path": "",
        "has_cli_transcript": False,
    }

    path = _claude_session_jsonl_path(sid)
    if not path:
        if summary["cwd"]:
            try:
                summary["cwd"] = _resolve_session_cwd(sid, summary["cwd"])
                summary["originCwd"] = summary["cwd"]
            except Exception:
                pass
        return summary
    summary["jsonl_path"] = str(path)
    summary["has_cli_transcript"] = True

    try:
        st = path.stat()
        stat_ms = int(st.st_mtime * 1000)
    except OSError:
        st = None
        stat_ms = now_ms

    first_prompt = ""
    first_ts_ms = 0
    last_ts_ms = 0
    completed_turns = 0
    try:
        with open(path, "r", encoding="utf-8", errors="replace") as fh:
            for line in fh:
                line = line.strip()
                if not line:
                    continue
                try:
                    ev = json.loads(line)
                except json.JSONDecodeError:
                    continue
                ts_ms = _claude_desktop_epoch_ms(ev.get("timestamp"))
                if ts_ms:
                    if not first_ts_ms:
                        first_ts_ms = ts_ms
                    last_ts_ms = ts_ms
                if not summary["cwd"] and ev.get("cwd"):
                    summary["cwd"] = ev.get("cwd") or ""
                    summary["originCwd"] = summary["cwd"]
                if not first_prompt:
                    first_prompt = _extract_user_prompt_text(ev) or ""
                if ev.get("type") == "assistant":
                    completed_turns += 1
                    msg = ev.get("message")
                    if isinstance(msg, dict) and msg.get("model"):
                        summary["model"] = msg.get("model") or summary["model"]
    except (OSError, UnicodeDecodeError):
        pass

    try:
        tail = _extract_tail_meta(path) or {}
    except Exception:
        tail = {}
    title = (
        tail.get("custom_title")
        or tail.get("agent_name")
        or tail.get("ai_title")
        or _claude_desktop_title_from_text(first_prompt)
        or summary["title"]
    )
    if title:
        summary["title"] = title
    if tail.get("model"):
        summary["model"] = tail.get("model") or summary["model"]
    if tail.get("last_meaningful_ts"):
        try:
            summary["lastActivityAt"] = int(float(tail["last_meaningful_ts"]) * 1000)
        except (TypeError, ValueError):
            pass
    elif last_ts_ms:
        summary["lastActivityAt"] = last_ts_ms
    elif stat_ms:
        summary["lastActivityAt"] = stat_ms
    if first_ts_ms:
        summary["createdAt"] = first_ts_ms
    elif started_ms:
        summary["createdAt"] = started_ms
    elif st:
        summary["createdAt"] = int(min(st.st_ctime, st.st_mtime) * 1000)
    summary["completedTurns"] = completed_turns
    if summary["cwd"]:
        try:
            summary["cwd"] = _resolve_session_cwd(sid, summary["cwd"])
            summary["originCwd"] = summary["cwd"]
        except Exception:
            pass
    return summary


def _write_claude_desktop_metadata(path, payload, last_activity_ms):
    try:
        path.parent.mkdir(parents=True, exist_ok=True)
        tmp = path.with_name(f"{path.name}.tmp-{os.getpid()}")
        tmp.write_text(
            json.dumps(payload, indent=2, ensure_ascii=False, sort_keys=True) + "\n",
            encoding="utf-8",
        )
        os.replace(tmp, path)
        if last_activity_ms:
            ts = max(0.0, float(last_activity_ms) / 1000.0)
            os.utime(path, (ts, ts))
    except (OSError, TypeError, ValueError):
        return False
    _bust_claude_desktop_metadata_cache()
    return True


def _ensure_claude_desktop_session_visible(session_id, spawn_entry=None):
    """Create or refresh Claude Desktop's sidebar metadata for a CLI session."""
    sid = str(session_id or "").strip()
    if not sid or not _SESSION_UUID_RE.match(sid):
        return False

    summary = _claude_session_desktop_summary(sid, spawn_entry=spawn_entry)
    existing_path = _claude_desktop_metadata_path_for_cli_session(sid)
    existing = _read_json_object(existing_path) if existing_path else {}
    existing = existing or {}
    if not summary.get("has_cli_transcript"):
        return False
    if not (summary.get("cwd") or existing.get("cwd")):
        return False
    if not (summary.get("title") or existing.get("title")):
        return False
    workspace_dir = _claude_desktop_workspace_for_summary(summary, existing_path)
    if not workspace_dir:
        return False
    path = existing_path or (workspace_dir / f"local_{sid}.json")
    app_session_id = existing.get("sessionId") or path.stem or f"local_{sid}"
    if path.name.startswith("local_") and not str(app_session_id).startswith("local_"):
        app_session_id = path.stem
    user_title = (
        existing.get("title")
        if existing.get("titleSource") == "user" and existing.get("title")
        else None
    )
    title = user_title or summary.get("title") or existing.get("title") or ""

    payload = dict(existing)
    payload.update({
        "sessionId": app_session_id,
        "cliSessionId": sid,
        "cwd": summary.get("cwd") or existing.get("cwd") or "",
        "originCwd": summary.get("originCwd") or existing.get("originCwd") or summary.get("cwd") or "",
        "createdAt": int(summary.get("createdAt") or existing.get("createdAt") or time.time() * 1000),
        "lastActivityAt": int(summary.get("lastActivityAt") or existing.get("lastActivityAt") or time.time() * 1000),
        "completedTurns": int(summary.get("completedTurns") or existing.get("completedTurns") or 0),
        "isArchived": bool(existing.get("isArchived", False)),
        "permissionMode": existing.get("permissionMode") or "default",
        "chromePermissionMode": existing.get("chromePermissionMode") or "skip_all_permission_checks",
        "alwaysAllowedReasons": existing.get("alwaysAllowedReasons") if isinstance(existing.get("alwaysAllowedReasons"), list) else [],
        "enabledMcpTools": existing.get("enabledMcpTools") if isinstance(existing.get("enabledMcpTools"), dict) else {},
        "remoteMcpServersConfig": existing.get("remoteMcpServersConfig") if isinstance(existing.get("remoteMcpServersConfig"), list) else [],
    })
    model = summary.get("model") or existing.get("model")
    if model:
        payload["model"] = model
    if title:
        payload["title"] = title
        payload["titleSource"] = existing.get("titleSource") or ("user" if user_title else "auto")
    elif "title" in payload and not payload["title"]:
        payload.pop("title", None)
        payload.pop("titleSource", None)

    if existing == payload and path.is_file():
        try:
            desired_ts = float(payload.get("lastActivityAt") or 0) / 1000.0
            if desired_ts and abs(path.stat().st_mtime - desired_ts) > 1.0:
                os.utime(path, (desired_ts, desired_ts))
                _bust_claude_desktop_metadata_cache()
        except (OSError, TypeError, ValueError):
            pass
        return True

    return _write_claude_desktop_metadata(path, payload, payload.get("lastActivityAt"))


_claude_desktop_visibility_retry_sids = set()
_claude_desktop_visibility_retry_lock = threading.Lock()


def _schedule_claude_desktop_visibility_retry(session_id, spawn_entry=None, attempts=60, delay=1.0):
    sid = str(session_id or "").strip()
    if not sid:
        return False
    with _claude_desktop_visibility_retry_lock:
        if sid in _claude_desktop_visibility_retry_sids:
            return False
        _claude_desktop_visibility_retry_sids.add(sid)

    entry = dict(spawn_entry or {})

    def worker():
        try:
            for _idx in range(max(1, int(attempts or 1))):
                if _ensure_claude_desktop_session_visible(sid, spawn_entry=entry):
                    return
                time.sleep(max(0.05, float(delay or 0.5)))
        except Exception:
            pass
        finally:
            with _claude_desktop_visibility_retry_lock:
                _claude_desktop_visibility_retry_sids.discard(sid)

    threading.Thread(
        target=worker,
        daemon=True,
        name=f"ccc-claude-desktop-visible-{sid[:8]}",
    ).start()
    return True


def _is_synthetic_claude_desktop_metadata(path, data):
    if not isinstance(data, dict):
        return False
    sid = str(data.get("cliSessionId") or "").strip()
    if not sid:
        return False
    if path.name != f"local_{sid}.json":
        return False
    if data.get("sessionId") not in (sid, f"local_{sid}"):
        return False
    if data.get("enabledMcpTools") not in ({}, None):
        return False
    if data.get("remoteMcpServersConfig") not in ([], None):
        return False
    if data.get("alwaysAllowedReasons") not in ([], None):
        return False
    return data.get("permissionMode") in (None, "default")


def _is_claude_desktop_transcript_unavailable_placeholder(path, data):
    if not isinstance(data, dict) or data.get("transcriptUnavailable") is not True:
        return False
    sid = str(data.get("sessionId") or "").strip()
    if not sid or path.name != f"{sid}.json":
        return False
    if data.get("enabledMcpTools") not in ({}, None):
        return False
    if data.get("remoteMcpServersConfig") not in ([], None):
        return False
    return data.get("permissionMode") in (None, "default")


def prune_unresumable_claude_desktop_metadata(dry_run=False):
    """Remove CCC-synthetic Desktop rows whose CLI transcript is unavailable."""
    pruned = []
    for path in _claude_desktop_metadata_files():
        data = _read_json_object(path)
        if not _is_synthetic_claude_desktop_metadata(path, data):
            continue
        sid = data.get("cliSessionId")
        if _claude_session_jsonl_path(sid):
            continue
        pruned.append(str(path))
        if dry_run:
            continue
        try:
            path.unlink()
        except OSError:
            pass
    root = _claude_desktop_sessions_root()
    if root.is_dir():
        try:
            placeholder_paths = [
                p for p in root.glob("*/*/*.json")
                if p.is_file() and not p.name.startswith("local_")
            ]
        except OSError:
            placeholder_paths = []
        for path in placeholder_paths:
            data = _read_json_object(path)
            if not _is_claude_desktop_transcript_unavailable_placeholder(path, data):
                continue
            pruned.append(str(path))
            if dry_run:
                continue
            try:
                path.unlink()
            except OSError:
                pass
    if pruned and not dry_run:
        _bust_claude_desktop_metadata_cache()
    return {"ok": True, "dry_run": bool(dry_run), "pruned": len(pruned), "paths": pruned}


def _fetch_issue_states(repo_path):
    """Bulk-fetch state+labels+title for all issues. Cached 5 min."""
    repo_path = resolve_repo_path(repo_path)
    cached = _issue_state_cache.get(repo_path) or {}
    if time.time() - cached.get("ts", 0) < 60 and cached.get("data"):
        return cached["data"]
    data = cached.get("data") or {}
    try:
        out = subprocess.run(
            ["gh", "issue", "list", "--state", "all", "--limit", "500",
             "--json", "number,title,state,labels"],
            capture_output=True, text=True, timeout=15, cwd=str(repo_path),
        )
        if out.returncode == 0:
            issues = json.loads(out.stdout)
            data = {
                str(i["number"]): {
                    "state": i.get("state") or "OPEN",
                    "labels": [l.get("name", "") for l in (i.get("labels") or [])],
                    "title": _strip_title_prefix(i.get("title", "")),
                }
                for i in issues
            }
            _issue_state_cache[repo_path] = {"ts": time.time(), "data": data}
    except (subprocess.TimeoutExpired, FileNotFoundError, json.JSONDecodeError):
        pass
    return data


def _bust_issue_state_cache(repo_path=None):
    """Force next _fetch_issue_states() to re-query gh. Call after any mutation
    (close/reopen/label change) so the UI doesn't serve 5-minute-stale state."""
    if repo_path:
        try:
            _issue_state_cache.pop(resolve_repo_path(repo_path), None)
        except RepoContextError:
            pass
    else:
        _issue_state_cache.clear()


# Backlog: full issue data (labels, body) for open issues
_backlog_issues_cache = {}  # repo_path -> {"ts": float, "data": list}


def _fetch_issue_titles(repo_path):
    """Bulk-fetch GitHub issue titles. Cached for 5 minutes."""
    repo_path = resolve_repo_path(repo_path)
    cached = _issue_titles_cache.get(repo_path) or {}
    if time.time() - cached.get("ts", 0) < 300 and cached.get("data"):
        return cached["data"]
    data = cached.get("data") or {}
    try:
        out = subprocess.run(
            ["gh", "issue", "list", "--state", "all", "--limit", "200",
             "--json", "number,title"],
            capture_output=True, text=True, timeout=10, cwd=str(repo_path),
        )
        if out.returncode == 0:
            issues = json.loads(out.stdout)
            data = {
                str(i["number"]): _strip_title_prefix(i["title"])
                for i in issues
            }
            _issue_titles_cache[repo_path] = {"ts": time.time(), "data": data}
    except (subprocess.TimeoutExpired, FileNotFoundError, json.JSONDecodeError):
        pass
    return data


# ---------------------------------------------------------------------------
# Cross-repo issues — Phase B of the multi-repo design.
#
# Aggregates `gh issue list` across every known repo (recent ∪ pinned), in
# parallel, with per-repo TTL cache. Lets the UI surface a flat "issues
# across all my work" list without needing the user to switch repos. Each
# returned issue carries its repo_path / repo_label so click-to-spawn can
# target the right cwd. Failures (no gh auth in some folder, missing dir,
# timeout) are isolated per-repo — one bad folder doesn't break the rest.
# ---------------------------------------------------------------------------

_CROSS_REPO_ISSUES_CACHE = {}  # repo_path → {issues, error, ts}
_CROSS_REPO_ISSUES_LOCK = threading.Lock()
_CROSS_REPO_ISSUES_TTL = 300  # 5 minutes — same as the per-repo cache


def _fetch_one_repo_issues(repo_path):
    """Fetch open + recently-closed issues for ONE repo. Cached per-repo
    by repo_path. Returns {"issues": list, "error": str|None, "ts": float}.
    Never raises — every failure mode lands in the `error` field so the
    aggregator can degrade gracefully."""
    cache_key = str(repo_path)
    now = time.time()
    with _CROSS_REPO_ISSUES_LOCK:
        cached = _CROSS_REPO_ISSUES_CACHE.get(cache_key)
        if cached and (now - cached["ts"]) < _CROSS_REPO_ISSUES_TTL:
            return cached

    issues = []
    error = None
    try:
        if not Path(repo_path).is_dir():
            error = "directory not found"
        elif not (Path(repo_path) / ".git").is_dir():
            error = "not a git repo"
        else:
            try:
                open_out = subprocess.run(
                    ["gh", "issue", "list", "--state", "open", "--limit", "100",
                     "--json", "number,title,labels,body,createdAt,updatedAt,state,stateReason,url"],
                    capture_output=True, text=True, timeout=10, cwd=str(repo_path),
                )
                if open_out.returncode == 0:
                    issues.extend(json.loads(open_out.stdout))
                else:
                    # Swallow common gh failures (no auth, no remote, etc.)
                    # into an error string. stderr first line is enough.
                    err = (open_out.stderr or "").strip().splitlines()
                    error = (err[0] if err else "gh exited non-zero")[:200]
            except subprocess.TimeoutExpired:
                error = "gh timed out (10s)"
            except FileNotFoundError:
                error = "gh CLI not installed"
            except json.JSONDecodeError:
                error = "gh returned malformed JSON"
            # Only attempt closed if open succeeded — otherwise we'd double-
            # report the same auth error.
            if not error:
                try:
                    closed_out = subprocess.run(
                        ["gh", "issue", "list", "--state", "closed", "--limit", "60",
                         "--json", "number,title,labels,body,createdAt,updatedAt,closedAt,state,stateReason,url"],
                        capture_output=True, text=True, timeout=10, cwd=str(repo_path),
                    )
                    if closed_out.returncode == 0:
                        issues.extend(json.loads(closed_out.stdout))
                    # Closed-failure is non-fatal — open list is the
                    # important one for backlog UX.
                except (subprocess.TimeoutExpired, FileNotFoundError, json.JSONDecodeError):
                    pass
    except OSError as e:
        error = f"OSError: {e}"[:200]

    result = {"issues": issues, "error": error, "ts": now}
    with _CROSS_REPO_ISSUES_LOCK:
        _CROSS_REPO_ISSUES_CACHE[cache_key] = result
    return result


def fetch_cross_repo_issues():
    """Walk known repos in parallel; return a tagged flat list + per-repo
    error map.

    Repo set: `_load_recent_repos() ∪ _load_custom_repos()` — same source
    the rail / dropdown uses. Each issue gets `repo_path` + `repo_label`
    grafted on so click-to-spawn knows the cwd; sorted by updatedAt desc.

    Returns:
        {
          "issues": [{...gh fields..., "repo_path", "repo_label"}, ...],
          "errors": {repo_path: error_string},
          "fetched_at": epoch,
        }
    """
    try:
        repos = list(dict.fromkeys(  # dedupe, preserve order
            _load_recent_repos() + _load_custom_repos()
        ))
    except Exception:
        repos = []
    if not repos:
        return {"issues": [], "errors": {}, "fetched_at": time.time()}

    out = []
    errors = {}
    # Parallelize: ~10 repos × 1–3s each → 1–3s total instead of 10–30s.
    # 8 workers is enough for typical fleets without spawning a thread storm.
    from concurrent.futures import ThreadPoolExecutor, as_completed
    with ThreadPoolExecutor(max_workers=min(8, len(repos))) as ex:
        futures = {ex.submit(_fetch_one_repo_issues, r): r for r in repos}
        for f in as_completed(futures):
            repo = futures[f]
            try:
                result = f.result()
            except Exception as e:
                errors[repo] = f"unexpected: {e}"[:200]
                continue
            if result.get("error"):
                errors[repo] = result["error"]
                # Even on error, surface any issues that *did* parse
                # before the error (defensive — shouldn't happen given
                # the early-return shape, but cheap).
            label = Path(repo).name
            for issue in result.get("issues") or []:
                # Tag with repo info so the UI knows where to spawn.
                issue["repo_path"] = repo
                issue["repo_label"] = label
                out.append(issue)

    # Sort by updatedAt desc (fall back to createdAt then 0).
    out.sort(
        key=lambda i: i.get("updatedAt") or i.get("createdAt") or "",
        reverse=True,
    )
    return {"issues": out, "errors": errors, "fetched_at": time.time()}


def _gh_pr_status_notes(pr):
    notes = []
    if pr.get("isDraft"):
        notes.append({"kind": "warning", "label": "draft", "title": "Draft PR"})
    mergeable = (pr.get("mergeable") or "").upper()
    if mergeable == "CONFLICTING":
        notes.append({"kind": "danger", "label": "conflicts", "title": "PR has merge conflicts"})
    elif mergeable in ("UNKNOWN", "BLOCKED"):
        notes.append({
            "kind": "warning",
            "label": mergeable.lower(),
            "title": f"Mergeability is {mergeable.lower()}",
        })
    for check in pr.get("statusCheckRollup") or []:
        name = (check.get("name") or check.get("workflowName") or "check").strip()
        conclusion = (check.get("conclusion") or "").upper()
        if conclusion not in {"FAILURE", "CANCELLED", "TIMED_OUT", "ACTION_REQUIRED"}:
            continue
        if "CLA" in name.upper():
            label = "CLA failing"
            title = f"{name} is failing"
        else:
            label = "check failed"
            title = f"{name} failed"
        notes.append({"kind": "danger", "label": label, "title": title})
    return notes


def fetch_cross_repo_prs():
    try:
        repos = list(dict.fromkeys(
            _load_recent_repos() + _load_custom_repos()
        ))
    except Exception:
        repos = []
    if not repos:
        return {"pull_requests": [], "errors": {}, "fetched_at": time.time()}

    out = []
    errors = {}
    from concurrent.futures import ThreadPoolExecutor, as_completed
    with ThreadPoolExecutor(max_workers=min(8, len(repos))) as ex:
        futures = {ex.submit(_open_prs_cached, r): r for r in repos}
        for f in as_completed(futures):
            repo = futures[f]
            try:
                prs = f.result()
            except Exception as e:
                errors[repo] = f"unexpected: {e}"[:200]
                continue
            label = Path(repo).name
            for pr in prs or []:
                pr["repo_path"] = repo
                pr["repo_label"] = label
                pr["status_notes"] = _gh_pr_status_notes(pr)
                out.append(pr)
    out.sort(
        key=lambda p: p.get("updatedAt") or p.get("createdAt") or "",
        reverse=True,
    )
    return {"pull_requests": out, "errors": errors, "fetched_at": time.time()}


def _iso_epoch_or_now(ts):
    if not ts:
        return time.time()
    try:
        return datetime.fromisoformat(str(ts).replace("Z", "+00:00")).timestamp()
    except (TypeError, ValueError):
        return time.time()


def _open_pr_archive_row(pr):
    repo_path = pr.get("repo_path") or ""
    number = int(pr.get("number") or 0)
    digest = hashlib.sha1(f"{repo_path}:{number}".encode("utf-8")).hexdigest()
    synthetic_id = f"00000000-0000-0000-0000-{digest[:12]}"
    title = pr.get("title") or f"PR #{number}"
    branch = pr.get("headRefName") or ""
    mtime = _iso_epoch_or_now(pr.get("updatedAt") or pr.get("createdAt"))
    return {
        "id": synthetic_id,
        "session_id": synthetic_id,
        "source": "github_pr",
        "engine": "github",
        "timestamp": "",
        "first_message": title,
        "display_name": f"#{number}: {title}",
        "name_overridden": False,
        "mtime": mtime,
        "size": 0,
        "is_live": False,
        "archived": False,
        "worktree_dirty": False,
        "has_commit": False,
        "has_push": True,
        "has_edit": False,
        "tail_pr_number": number,
        "tail_pr_url": pr.get("url") or "",
        "pr_state": "OPEN",
        "pr_is_draft": bool(pr.get("isDraft")),
        "pr_mergeable": pr.get("mergeable") or "",
        "pr_review_decision": pr.get("reviewDecision") or "",
        "pr_notes": pr.get("status_notes") or [],
        "sidecar_status": None,
        "sidecar_tool": None,
        "sidecar_file": None,
        "sidecar_ts": 0,
        "sidecar_in_flight": False,
        "sidecar_has_writes": False,
        "needs_approval": False,
        "needs_approval_message": "",
        "question_waiting": False,
        "question_text": "",
        "question_header": "",
        "question_preamble": "",
        "question_options": [],
        "question_option_details": [],
        "session_cwd": repo_path,
        "session_cwd_exists": Path(repo_path).is_dir() if repo_path else False,
        "session_cwd_is_worktree": False,
        "git_branch": branch,
        "branch": branch,
        "effective_branch": branch,
        "effective_kind": None,
        "folder_label": pr.get("repo_label") or (Path(repo_path).name if repo_path else "GitHub"),
        "folder_path": repo_path,
        "slug": _encode_project_slug(repo_path) if repo_path else "github-pr",
        "pinned_repo": False,
    }


def conversations_with_open_prs(convs):
    convs = list(convs or [])
    open_prs = fetch_cross_repo_prs().get("pull_requests") or []
    pr_by_url = {
        str(pr.get("url") or ""): pr
        for pr in open_prs
        if pr.get("url")
    }
    pr_by_key = {}
    for pr in open_prs:
        try:
            n = int(pr.get("number") or 0)
        except (TypeError, ValueError):
            n = 0
        repo_path = pr.get("repo_path") or ""
        if n and repo_path:
            pr_by_key[(repo_path, n)] = pr

    seen_urls = {
        str(c.get("tail_pr_url") or "")
        for c in convs
        if c.get("tail_pr_url")
    }
    seen_keys = set()
    for c in convs:
        try:
            n = int(c.get("tail_pr_number") or 0)
        except (TypeError, ValueError):
            n = 0
        repo_path = c.get("folder_path") or c.get("session_cwd") or ""
        if n and repo_path:
            seen_keys.add((repo_path, n))
        pr = pr_by_url.get(str(c.get("tail_pr_url") or "")) or pr_by_key.get((repo_path, n))
        if pr:
            c["pr_notes"] = pr.get("status_notes") or []
            c["pr_is_draft"] = bool(pr.get("isDraft"))
            c["pr_mergeable"] = pr.get("mergeable") or ""
            c["pr_review_decision"] = pr.get("reviewDecision") or ""

    for pr in open_prs:
        try:
            number = int(pr.get("number") or 0)
        except (TypeError, ValueError):
            number = 0
        if not number:
            continue
        repo_path = pr.get("repo_path") or ""
        url = pr.get("url") or ""
        if (url and url in seen_urls) or ((repo_path, number) in seen_keys):
            continue
        convs.append(_open_pr_archive_row(pr))
    convs.sort(key=lambda c: c.get("mtime") or c.get("modified") or 0, reverse=True)
    return convs


def _bust_backlog_issue_cache(repo_path=None):
    if repo_path:
        try:
            _backlog_issues_cache.pop(resolve_repo_path(repo_path), None)
        except RepoContextError:
            pass
    else:
        _backlog_issues_cache.clear()


def _fetch_backlog_issues(repo_path):
    """Fetch open + recently-closed GitHub issues with labels and body.
    Cached 5 minutes. Closed issues get a `state_reason` field so the UI
    can route them (completed -> Verified, not planned -> Archived).
    """
    repo_path = resolve_repo_path(repo_path)
    cached = _backlog_issues_cache.get(repo_path) or {}
    if time.time() - cached.get("ts", 0) < 300 and cached.get("data") is not None:
        return cached.get("data") or []
    merged = []
    try:
        open_out = subprocess.run(
            ["gh", "issue", "list", "--state", "open", "--limit", "100",
             "--json", "number,title,labels,body,createdAt,updatedAt,state,stateReason"],
            capture_output=True, text=True, timeout=10, cwd=str(repo_path),
        )
        if open_out.returncode == 0:
            merged.extend(json.loads(open_out.stdout))
    except (subprocess.TimeoutExpired, FileNotFoundError, json.JSONDecodeError):
        pass
    try:
        closed_out = subprocess.run(
            ["gh", "issue", "list", "--state", "closed", "--limit", "60",
             "--json", "number,title,labels,body,createdAt,updatedAt,closedAt,state,stateReason"],
            capture_output=True, text=True, timeout=10, cwd=str(repo_path),
        )
        if closed_out.returncode == 0:
            merged.extend(json.loads(closed_out.stdout))
    except (subprocess.TimeoutExpired, FileNotFoundError, json.JSONDecodeError):
        pass
    _backlog_issues_cache[repo_path] = {"ts": time.time(), "data": merged}
    return merged


def _parse_todo_md(repo_path):
    """Parse TODO.md for unchecked items (- [ ] lines)."""
    todo_path = Path(repo_path) / "TODO.md"
    items = []
    try:
        with open(todo_path, "r") as f:
            for line in f:
                stripped = line.strip()
                if stripped.startswith("- [ ]"):
                    text = stripped[5:].strip()
                    if text:
                        items.append(text)
    except (OSError, UnicodeDecodeError):
        pass
    return items


def _load_native_tasks():
    """Surface Claude Code's built-in TodoWrite output as backlog records.

    Claude Code persists per-session todos to ``~/.claude/tasks/<session_id>/<task_id>.json``.
    Each file is one task with shape ``{id, subject, description, activeForm,
    status, blocks, blockedBy}`` — ``status`` is one of ``pending``,
    ``in_progress``, ``completed``.

    To avoid spamming the kanban (a session with 6 todos shouldn't add 6 cards)
    we collapse each session_id to a single record:
      - Title prefers the in_progress task's ``subject``; falls back to first
        pending; otherwise the most recent completed (so finished sessions still
        show *what* they did).
      - Counts (``total``, ``in_progress_count``, ``pending_count``,
        ``completed_count``) are returned so the UI can show e.g. "3/6".
      - ``modified`` is the dir mtime so the card sorts by last-touched session.

    Sessions with zero parseable task files are skipped entirely.
    Files that aren't valid JSON objects are skipped without aborting the
    session record (one bad task shouldn't hide the rest).
    """
    tasks_root = Path.home() / ".claude" / "tasks"
    if not tasks_root.is_dir():
        return []
    records = []
    try:
        session_dirs = [d for d in tasks_root.iterdir() if d.is_dir()]
    except OSError:
        return []
    for sdir in session_dirs:
        session_id = sdir.name
        in_progress = []
        pending = []
        completed = []
        try:
            files = [f for f in sdir.iterdir() if f.is_file() and f.suffix == ".json"]
        except OSError:
            continue
        for tf in files:
            try:
                with open(tf, "r", encoding="utf-8") as fh:
                    raw = json.load(fh)
            except (OSError, UnicodeDecodeError, json.JSONDecodeError):
                continue
            # Schema is a single task object; tolerate the legacy "list of tasks"
            # form too, in case some Claude Code versions wrote arrays.
            if isinstance(raw, list):
                tasks = [t for t in raw if isinstance(t, dict)]
            elif isinstance(raw, dict):
                tasks = [raw]
            else:
                continue
            for task in tasks:
                status = (task.get("status") or "").lower()
                if status == "in_progress":
                    in_progress.append((tf.stat().st_mtime, task))
                elif status == "pending":
                    pending.append((tf.stat().st_mtime, task))
                elif status == "completed":
                    completed.append((tf.stat().st_mtime, task))
        total = len(in_progress) + len(pending) + len(completed)
        if total == 0:
            continue
        # Pick the headline task: in_progress > pending > most-recent completed
        if in_progress:
            headline = max(in_progress, key=lambda x: x[0])[1]
            headline_status = "in_progress"
        elif pending:
            headline = min(pending, key=lambda x: x[0])[1]
            headline_status = "pending"
        else:
            headline = max(completed, key=lambda x: x[0])[1]
            headline_status = "completed"
        title = (headline.get("subject") or headline.get("activeForm")
                 or headline.get("content") or "").strip()
        if not title:
            continue
        try:
            mtime = sdir.stat().st_mtime
        except OSError:
            mtime = 0
        records.append({
            "session_id": session_id,
            "title": title,
            "active_form": (headline.get("activeForm") or "").strip(),
            "description": (headline.get("description") or "").strip(),
            "status": headline_status,
            "in_progress_count": len(in_progress),
            "pending_count": len(pending),
            "completed_count": len(completed),
            "total": total,
            "modified": mtime,
            "source": "native_task",
        })
    return records


def _parse_parking_lot_md(repo_path):
    """Parse PARKING_LOT.md for `## heading` items; body = text until the next
    heading or `---` separator. Returns [{title, body}] in file order."""
    # Case-insensitive filename match for the two common spellings
    repo = Path(repo_path)
    candidates = [repo / "PARKING_LOT.md", repo / "parking-lot.md", repo / "parking_lot.md"]
    path = next((p for p in candidates if p.is_file()), None)
    if not path:
        return []
    items = []
    try:
        text = path.read_text(encoding="utf-8", errors="replace")
    except OSError:
        return []
    current_title = None
    current_body = []
    for line in text.splitlines():
        if line.startswith("## "):
            if current_title:
                items.append({"title": current_title, "body": "\n".join(current_body).strip()})
            current_title = line[3:].strip()
            current_body = []
            continue
        # `---` is a section separator — flush the current item but don't start a new one
        if line.strip() == "---":
            if current_title:
                items.append({"title": current_title, "body": "\n".join(current_body).strip()})
                current_title = None
                current_body = []
            continue
        if current_title is not None:
            current_body.append(line)
    if current_title:
        items.append({"title": current_title, "body": "\n".join(current_body).strip()})
    return items


def find_backlog_items(repo_path, progress=None):
    """Return backlog cards from GitHub issues + TODO.md."""
    repo_path = resolve_repo_path(repo_path)
    items = []

    # Source 1: GitHub Issues
    if progress:
        progress("github", state="running", detail="Querying open and recently closed issues.")
    backlog_issues = _fetch_backlog_issues(repo_path)
    if progress:
        progress(
            "github",
            state="done",
            count=len(backlog_issues),
            detail=f"{len(backlog_issues)} GitHub issue(s) fetched.",
        )
    for issue in backlog_issues:
        number = issue.get("number", 0)
        title = issue.get("title", "")
        body = issue.get("body", "") or ""
        labels = [l.get("name", "") for l in (issue.get("labels") or [])]
        # Parse createdAt ISO 8601 → unix timestamp
        created_ts = 0
        created_at = issue.get("createdAt", "")
        if created_at:
            try:
                from datetime import datetime, timezone
                # Format: "2026-04-12T05:39:47Z" — UTC
                dt = datetime.strptime(created_at, "%Y-%m-%dT%H:%M:%SZ").replace(tzinfo=timezone.utc)
                created_ts = dt.timestamp()
            except (ValueError, ImportError):
                pass
        state = (issue.get("state") or "OPEN").upper()
        reason = (issue.get("stateReason") or "").upper()  # COMPLETED, NOT_PLANNED, DUPLICATE, ""
        # AI-summary override — if the user has hit the ✨ button on this
        # issue we use the cached short title instead of the verbose GH one.
        ai_overrides = _load_issue_title_overrides()
        ai_entry = ai_overrides.get(str(number))
        ai_title = (ai_entry or {}).get("title")
        display_name = f"#{number}: {ai_title or title}"
        items.append({
            "id": f"backlog-issue-{number}",
            "session_id": f"backlog-issue-{number}",
            "display_name": display_name,
            "first_message": body[:200],
            # name_overridden=True signals the bulk button to skip on rerun
            # (same semantics as session-card cards).
            "name_overridden": bool(ai_title),
            "source": "backlog",
            "backlog_type": "github",
            "issue_number": str(number),
            "issue_labels": labels,
            "issue_created_at": created_at,
            "issue_state": state,
            "issue_state_reason": reason,
            "org": _detect_issue_org(body),
            "modified": created_ts,
            "size": 0,
            "branch": "",
            "is_live": False,
            "archived": False,
            "verified": False,
            "has_edit": False,
            "has_commit": False,
            "has_push": False,
            "last_event_type": None,
            "pending_tool": None,
            "pending_file": None,
            "sidecar_status": None,
            "sidecar_tool": None,
            "sidecar_file": None,
            "sidecar_has_writes": False,
            "sidecar_ts": 0,
        })

    # Source 2: TODO.md
    todo_items = _parse_todo_md(repo_path)
    if progress:
        progress(
            "todo",
            state="done",
            count=len(todo_items),
            detail=f"{len(todo_items)} unchecked TODO item(s).",
        )
    for i, text in enumerate(todo_items):
        items.append({
            "id": f"backlog-todo-{i}",
            "session_id": f"backlog-todo-{i}",
            "display_name": text[:80],
            "first_message": text,
            "source": "backlog",
            "backlog_type": "todo",
            "issue_number": "",
            "issue_labels": [],
            "modified": 0,
            "size": 0,
            "branch": "",
            "is_live": False,
            "archived": False,
            "verified": False,
            "has_edit": False,
            "has_commit": False,
            "has_push": False,
            "last_event_type": None,
            "pending_tool": None,
            "pending_file": None,
            "sidecar_status": None,
            "sidecar_tool": None,
            "sidecar_file": None,
            "sidecar_has_writes": False,
            "sidecar_ts": 0,
            "name_overridden": False,
        })

    # Source 3: PARKING_LOT.md — richer items (heading + body)
    parking_items = _parse_parking_lot_md(repo_path)
    if progress:
        progress(
            "parking",
            state="done",
            count=len(parking_items),
            detail=f"{len(parking_items)} parking-lot item(s).",
        )
    for i, it in enumerate(parking_items):
        title = it["title"]
        body = it["body"]
        items.append({
            "id": f"backlog-parking-{i}",
            "session_id": f"backlog-parking-{i}",
            "display_name": title[:120],
            "first_message": (title + "\n\n" + body) if body else title,
            "source": "backlog",
            "backlog_type": "parking",
            "issue_number": "",
            "issue_labels": [],
            "modified": 0,
            "size": 0,
            "branch": "",
            "is_live": False,
            "archived": False,
            "verified": False,
            "has_edit": False,
            "has_commit": False,
            "has_push": False,
            "last_event_type": None,
            "pending_tool": None,
            "pending_file": None,
            "sidecar_status": None,
            "sidecar_tool": None,
            "sidecar_file": None,
            "sidecar_has_writes": False,
            "sidecar_ts": 0,
            "name_overridden": False,
        })

    # Source 4: ~/.claude/tasks/<session_id>/*.json (native TodoWrite output)
    # Only surfaces sessions that aren't already represented as a live/inactive
    # conversation — that filtering happens at the `/api/sessions` merge step,
    # so here we just emit candidate cards.
    native_tasks = _load_native_tasks()
    if progress:
        progress(
            "native_tasks",
            state="done",
            count=len(native_tasks),
            detail=f"{len(native_tasks)} native task session(s).",
        )
    for nt in native_tasks:
        # Pad short subjects with the activeForm so the card body has signal.
        body_bits = [nt["title"]]
        if nt.get("description"):
            body_bits.append(nt["description"])
        if nt.get("active_form") and nt["active_form"] != nt["title"]:
            body_bits.append(nt["active_form"])
        body = "\n\n".join(b for b in body_bits if b)
        items.append({
            "id": f"backlog-task-{nt['session_id']}",
            "session_id": nt["session_id"],
            "display_name": nt["title"][:120],
            "first_message": body[:400],
            "source": "backlog",
            "backlog_type": "native_task",
            "issue_number": "",
            "issue_labels": [],
            "modified": nt.get("modified") or 0,
            "size": 0,
            "branch": "",
            "is_live": False,
            "archived": False,
            "verified": False,
            "has_edit": False,
            "has_commit": False,
            "has_push": False,
            "last_event_type": None,
            "pending_tool": None,
            "pending_file": None,
            "sidecar_status": None,
            "sidecar_tool": None,
            "sidecar_file": None,
            "sidecar_has_writes": False,
            "sidecar_ts": 0,
            "name_overridden": False,
            # Native-task-specific fields
            "task_status": nt["status"],
            "task_total": nt["total"],
            "task_in_progress": nt["in_progress_count"],
            "task_pending": nt["pending_count"],
            "task_completed": nt["completed_count"],
        })

    return items


# ---------------------------------------------------------------------------
# Conversation parsing (Claude Code interactive sessions)
# ---------------------------------------------------------------------------

def _safe_parse_message(msg):
    """Parse a message field that may be a dict or a Python repr string."""
    if isinstance(msg, dict):
        return msg
    if isinstance(msg, str):
        try:
            return json.loads(msg)
        except (json.JSONDecodeError, ValueError):
            pass
        try:
            return ast.literal_eval(msg)
        except (ValueError, SyntaxError):
            pass
    return {}


def _extract_text_from_content(content):
    """Extract plain text from a message content field (string or list).

    Image-only messages return "[image]" so conversation previews don't blank out.
    """
    if isinstance(content, str):
        return content.strip()
    if isinstance(content, list):
        texts = []
        has_image = False
        for item in content:
            if isinstance(item, dict):
                itype = item.get("type")
                if itype == "text":
                    t = item.get("text", "").strip()
                    if t:
                        texts.append(t)
                elif itype == "image":
                    has_image = True
            elif isinstance(item, str):
                texts.append(item.strip())
        joined = "\n".join(texts)
        if joined:
            return joined
        if has_image:
            return "[image]"
        return ""
    return ""


_IMAGE_CACHE_PATH_RE = re.compile(r"/image-cache/([0-9a-fA-F-]+)/([^/\s\"'\]]+\.(?:png|jpe?g|gif|webp))", re.IGNORECASE)


def _extract_images_from_content(content, line=None):
    """Return a list of image descriptors from a message content field.

    Each entry is one of:
      {"kind": "path", "session_id": str, "filename": str}
      {"kind": "base64", "media_type": str, "data": str, "idx": int}
      {"kind": "base64", "media_type": str, "line": int, "idx": int}

    When `line` is supplied, base64 image bodies are NOT inlined — a
    (line, idx) reference is emitted instead so the browser can lazy-fetch
    each image via /api/conv-image. This keeps multi-MB base64 blobs out of
    the parse payload (a single transcript with a few pasted screenshots can
    otherwise balloon to 10+ MB and stall the initial load). `idx` counts
    base64 images within the message so /api/conv-image can re-extract the
    Nth one deterministically. Call with line=None (the default) to inline
    the data, e.g. from /api/conv-image itself or transient queued events.
    """
    out = []
    b64_idx = 0
    if not isinstance(content, list):
        # Claude Code also sometimes emits text blocks containing
        # "[Image: source: /Users/.../.claude/image-cache/<sid>/<N>.png]".
        if isinstance(content, str):
            for m in _IMAGE_CACHE_PATH_RE.finditer(content):
                out.append({"kind": "path", "session_id": m.group(1), "filename": m.group(2)})
        return out
    for item in content:
        if not isinstance(item, dict):
            continue
        itype = item.get("type")
        if itype == "image":
            src = item.get("source") or {}
            stype = src.get("type")
            if stype == "base64":
                data = src.get("data") or ""
                mt = src.get("media_type") or "image/png"
                if data:
                    if line is not None:
                        out.append({"kind": "base64", "media_type": mt,
                                    "line": int(line), "idx": b64_idx})
                    else:
                        out.append({"kind": "base64", "media_type": mt,
                                    "data": data, "idx": b64_idx})
                    b64_idx += 1
            else:
                p = src.get("path") or src.get("file_path") or ""
                if isinstance(p, str):
                    m = _IMAGE_CACHE_PATH_RE.search(p)
                    if m:
                        out.append({"kind": "path", "session_id": m.group(1), "filename": m.group(2)})
        elif itype == "text":
            txt = item.get("text", "")
            if isinstance(txt, str) and "image-cache" in txt:
                for m in _IMAGE_CACHE_PATH_RE.finditer(txt):
                    out.append({"kind": "path", "session_id": m.group(1), "filename": m.group(2)})
    return out


# Concurrency guard for find_conversations(). The browser polls
# /api/conversations every 10 s (static/index.html:10540). On a cold
# repo switch with hundreds of sessions, the first call can take >2 min
# while subsequent polls pile up — each running the full
# _infer_effective_repo work in parallel against an empty cache. Past
# this threshold late entrants skip the inference (rows still render
# with the launch branch, just no drift detection on this pass).
_FIND_CONVS_LOCK = threading.Lock()
_FIND_CONVS_INFLIGHT = 0
_FIND_CONVS_INFLIGHT_MAX = 3


def find_conversations(repo_path, progress=None, include_old=True, live_sids=None):
    """Return list of conversation metadata dicts, newest first."""
    repo_path = resolve_repo_path(repo_path)
    repo = Path(repo_path)
    global _FIND_CONVS_INFLIGHT
    conversations = []
    # Concurrency guard: count this call into _FIND_CONVS_INFLIGHT and
    # skip the heavy effective-repo inference if we're piling up.
    with _FIND_CONVS_LOCK:
        _FIND_CONVS_INFLIGHT += 1
        _inflight_now = _FIND_CONVS_INFLIGHT
    _skip_inference = _inflight_now > _FIND_CONVS_INFLIGHT_MAX
    _n_eff_skipped_concurrency = 0
    _n_eff_skipped_no_drift = 0
    # Open a per-request budget for cwd-relocation filesystem walks (see
    # _relocate_missing_session_cwd). Without this a worktree-heavy repo
    # could spend ~40s walking the FS for deleted worktrees on cold cache.
    _relocation_budget_begin()

    def _dec_inflight():
        global _FIND_CONVS_INFLIGHT
        with _FIND_CONVS_LOCK:
            _FIND_CONVS_INFLIGHT -= 1
        _relocation_budget_end()
        # Best-effort persist of newly-resolved cwd entries so the next
        # cold start doesn't repay the walks. Never raise into the caller.
        try:
            _save_cwd_relocation_cache()
        except Exception:
            pass

    # Aggregate timers — gated on env var so prod stays silent.
    _PROFILE = os.environ.get("CCC_PROFILE_CONVS") == "1"
    _t_start = time.perf_counter() if _PROFILE else 0
    _t_cwd = 0.0; _n_cwd = 0
    _t_tail = 0.0; _n_tail = 0
    _t_top = 0.0; _n_top = 0; _n_top_misses = 0
    _t_eff = 0.0; _n_eff = 0; _n_eff_misses = 0
    _t_head = 0.0; _n_head = 0
    # Scan every project dir whose slug encodes back to this repo — both
    # the modern claude-code 2.x slug AND the legacy '/'-only slug, so
    # we don't drop historic sessions when claude-code's encoder changes.
    project_dirs = _candidate_conversation_dirs(repo)
    # Load pins early — even when the watched repo has no native slug dirs
    # (fresh worktree, just-cloned repo), we still want sessions pinned to
    # this repo to surface in the single-repo list.
    try:
        _repo_pins = _load_repo_pins()
    except Exception:
        _repo_pins = {}
    _this_repo = repo_path
    pinned_in_sids = {sid for sid, p in _repo_pins.items() if p == _this_repo}
    pinned_out_sids = {sid for sid, p in _repo_pins.items() if p and p != _this_repo}
    if live_sids is None:
        live_sids = set(_load_session_registry().keys())
    live_sids = set(live_sids or [])
    if not project_dirs and not pinned_in_sids and not live_sids:
        if progress:
            progress(
                "transcripts",
                state="done",
                count=0,
                total=0,
                detail="No Claude Code project folders matched this repo.",
            )
        _dec_inflight()
        return conversations
    name_overrides = _load_session_name_overrides()
    archived_set = set(_load_archived_conversations())
    pinned_list = _load_pinned_conversations()
    pinned_rank = _pinned_rank_map(pinned_list)
    verified_set = set(_load_verified_conversations())
    last_interactions = _load_last_interactions()
    # If the same session_id (file name) appears in multiple candidate
    # dirs (unlikely — claude-code uses one slug per process — but
    # possible if a repo path was historically encoded both ways), the
    # first one wins; project_dirs are ordered modern-first.
    seen_jsonl = set()
    jsonl_files = []
    # Shared across the per-row loop below so identical cwd ancestors
    # collapse to one `git rev-parse --show-toplevel` instead of one per
    # session — for repos with hundreds of sessions this is the
    # difference between a sub-second and a 17 s response.
    git_top_cache = {}
    for project_dir in project_dirs:
        for f in project_dir.iterdir():
            if not f.name.endswith(".jsonl") or not f.is_file():
                continue
            if f.name in seen_jsonl:
                continue
            seen_jsonl.add(f.name)
            jsonl_files.append(f)
    # Inject JSONLs for sessions pinned to this repo from other slug
    # dirs — so the single-repo list shows them as if launched here.
    if pinned_in_sids:
        projects_root = Path.home() / ".claude" / "projects"
        if projects_root.is_dir():
            try:
                for project_dir in projects_root.iterdir():
                    if not project_dir.is_dir():
                        continue
                    for sid in pinned_in_sids:
                        cand = project_dir / f"{sid}.jsonl"
                        if cand.is_file() and cand.name not in seen_jsonl:
                            seen_jsonl.add(cand.name)
                            jsonl_files.append(cand)
            except OSError:
                pass

    scan_required_sids = live_sids | pinned_in_sids
    jsonl_total_before_filter = len(jsonl_files)
    jsonl_files, scan_filter = _filter_conversation_jsonls(
        jsonl_files,
        include_old=include_old,
        always_include_sids=scan_required_sids,
        last_interactions=last_interactions,
    )
    if progress:
        progress(
            "repo",
            state="done",
                detail=f"{len(project_dirs)} transcript folder(s) for {repo.name}.",
        )
        detail = f"Found {jsonl_total_before_filter} JSONL transcript file(s)."
        if not include_old and len(jsonl_files) != jsonl_total_before_filter:
            skipped = scan_filter.get("skipped_old", 0)
            note = f" ({skipped} older file(s) deferred)" if skipped else ""
            detail = (
                f"Scanning {len(jsonl_files)} of {jsonl_total_before_filter} "
                f"JSONL transcript file(s).{note}"
            )
        progress(
            "transcripts",
            state="running",
            count=0,
            total=len(jsonl_files),
            detail=detail,
        )

    total_jsonl = len(jsonl_files)
    for idx, f in enumerate(jsonl_files, start=1):
        if progress and (idx == 1 or idx == total_jsonl or idx % 10 == 0):
            progress(
                "transcripts",
                state="running",
                count=idx,
                total=total_jsonl,
                detail=f"Reading transcript {idx} of {total_jsonl}.",
            )
        try:
            stat = f.stat()
        except OSError:
            continue

        # Skip sessions pinned to a different repo — they show up in the
        # destination repo's list (and the all-repos view) instead.
        # Cheap pre-check on the filename, which is `<session_id>.jsonl`.
        _stem = f.stem
        if _stem in pinned_out_sids:
            continue

        # Peek at first 20 lines to extract metadata. Cached by (mtime_ns, size)
        # like _extract_tail_meta — archived transcripts never change, so this
        # turns ~1390 head opens-and-parses into a handful (only changed files).
        session_id = None
        timestamp = None
        git_branch = None
        first_message = None
        head_cwd = None

        _t0 = time.perf_counter() if _PROFILE else 0
        try:
            _hst = f.stat()
            _head_key = (_hst.st_mtime_ns, _hst.st_size)
        except OSError:
            _head_key = None
        _hc = _conv_head_cache.get(str(f)) if _head_key is not None else None
        if _hc is not None and _hc[0] == _head_key:
            session_id, timestamp, git_branch, first_message, head_cwd = _hc[1]
            if _PROFILE:
                _t_head += time.perf_counter() - _t0
                _n_head += 1
        else:
            try:
                with open(f, "r") as fh:
                    for i, line in enumerate(fh):
                        if i >= 20:
                            break
                        line = line.strip()
                        if not line:
                            continue
                        try:
                            ev = json.loads(line)
                        except json.JSONDecodeError:
                            continue

                        ev_type = ev.get("type", "")
                        if not head_cwd:
                            head_cwd = ev.get("cwd")

                        if ev_type in ("file-history-snapshot", "progress", "system"):
                            continue

                        if ev_type == "user":
                            if ev.get("isMeta"):
                                continue
                            if not session_id:
                                session_id = ev.get("sessionId", "")
                            if not timestamp:
                                timestamp = ev.get("timestamp", "")
                            if not git_branch:
                                git_branch = ev.get("gitBranch", "")
                            if not first_message:
                                text = _extract_user_prompt_text(ev)
                                if text:
                                    first_message = text

                        if ev_type == "assistant" and not session_id:
                            session_id = ev.get("sessionId", "")
            except (OSError, UnicodeDecodeError):
                if _PROFILE:
                    _t_head += time.perf_counter() - _t0
                    _n_head += 1
                continue
            if _head_key is not None:
                _conv_head_cache[str(f)] = (
                    _head_key,
                    (session_id, timestamp, git_branch, first_message, head_cwd),
                )
            if _PROFILE:
                _t_head += time.perf_counter() - _t0
                _n_head += 1

        # Drop generated helper sessions before spending any more work on
        # them (tail scan, cwd lookup, etc.). first_message peek above already
        # strips <command-name> wrappers, so prompt-shape matching is enough.
        if _is_generated_helper_session(first_message):
            continue

        conv_id = f.name[:-6]  # remove .jsonl
        sid = session_id or conv_id
        if _PROFILE:
            _t0 = time.perf_counter()
            cwd = _resolve_session_cwd(sid, head_cwd) if head_cwd else find_session_cwd(sid)
            if head_cwd:
                _session_cwd_cache[sid] = cwd
            _t_cwd += time.perf_counter() - _t0; _n_cwd += 1
            _t0 = time.perf_counter()
            tail_meta = _extract_tail_meta(f)
            _t_tail += time.perf_counter() - _t0; _n_tail += 1
        else:
            cwd = _resolve_session_cwd(sid, head_cwd) if head_cwd else find_session_cwd(sid)
            if head_cwd:
                _session_cwd_cache[sid] = cwd
            tail_meta = _extract_tail_meta(f)
        override = name_overrides.get(sid) or name_overrides.get(conv_id)
        # Display value priority: side-car override > jsonl > None.
        # The sidecar is set ONLY by CCC's pencil rename — it's a
        # user-intent marker. Claude's `/rename` (which is sometimes
        # auto-fired by hooks/skills with no arg, producing a slugified
        # name from session context) writes a custom-title event to the
        # JSONL and would otherwise clobber the user's pick on the next
        # refresh. Putting the sidecar first means once the user touches
        # the title from the UI, it's pinned there until they explicitly
        # clear it (rename to empty).
        display_name = (
            override
            or tail_meta.get("custom_title")
            or tail_meta.get("agent_name")
            or tail_meta.get("ai_title")
            or _sibling_feature_title(first_message)
            or None
        )
        spawn_named = _tail_meta_spawn_named(tail_meta)
        # name_overridden means "user touched the name from the command center"
        # (used for teal visual marker). Decoupled from display value.
        name_overridden = bool(override)

        # Tool-call inference: when a session was launched in the shared
        # clone but all its Edit/Write paths land in a sibling worktree,
        # surface the *real* branch on the sidebar row. Cached on
        # (session_id, jsonl_mtime) so repeated /api/sessions polls
        # don't repay the JSONL walk for inactive sessions.
        eff_branch = None
        eff_kind = None
        eff_top = None
        try:
            if _PROFILE:
                _t0 = time.perf_counter()
                _miss_before = (str(Path(cwd).expanduser()) if cwd else None) not in git_top_cache if cwd else False
                cwd_top = _git_toplevel_for_path(cwd, git_top_cache) if cwd else None
                _t_top += time.perf_counter() - _t0
                _n_top += 1
                if _miss_before:
                    _n_top_misses += 1
            else:
                cwd_top = _git_toplevel_for_path(cwd, git_top_cache) if cwd else None
            # Two pre-skips before paying for _infer_effective_repo:
            # (1) concurrency guard — too many polls in flight, defer the
            #     expensive walk; the next poll will pick it up once the
            #     pile-up drains.
            # (2) no-drift hint — the session never issued `cd <path>` or
            #     `git -C <path>` AND its cwd already resolves to the
            #     requested repo, so there is nothing for inference to
            #     find. Set in _extract_tail_meta during its existing walk.
            _eff_module_hit = any(k[0] == sid for k in _EFFECTIVE_REPO_CACHE)
            _no_drift_possible = (
                not tail_meta.get("has_external_cd")
                and cwd_top
                and cwd_top == repo_path
            )
            if _skip_inference and not _eff_module_hit:
                _n_eff_skipped_concurrency += 1
                eff = None
            elif _no_drift_possible and not _eff_module_hit:
                _n_eff_skipped_no_drift += 1
                eff = None
            else:
                if _PROFILE:
                    _t0 = time.perf_counter()
                    _miss_eff = not _eff_module_hit
                eff = _infer_effective_repo(sid, literal_cwd=cwd, exclude_top=cwd_top)
                if _PROFILE:
                    _t_eff += time.perf_counter() - _t0
                    _n_eff += 1
                    if _miss_eff:
                        _n_eff_misses += 1
            if eff:
                eff_branch = eff.get("branch")
                eff_kind = eff.get("kind")
                eff_top = eff.get("top")
        except Exception:
            pass

        model = tail_meta.get("model") or ""
        latest_tok = tail_meta.get("latest_input_tokens") or 0
        if "[1m]" in model.lower() or latest_tok > 200_000:
            limit = 1_000_000
        else:
            limit = 200_000

        conversations.append({
            "id": conv_id,
            "session_id": sid,
            "source": "interactive",
            "engine": "claude",
            "timestamp": timestamp or "",
            "branch": git_branch or "",
            "first_message": (first_message or "")[:200],
            "display_name": display_name,
            "ai_title": (tail_meta.get("ai_title") or None),
            "latest_input_tokens": latest_tok,
            "live_context_tokens": tail_meta.get("live_context_tokens") or 0,
            "live_context_limit": tail_meta.get("live_context_limit") or 0,
            "live_context_percent": tail_meta.get("live_context_percent") or 0,
            "context_limit": limit,
            "spawn_named": spawn_named,
            "name_overridden": name_overridden,
            "last_prompt": (tail_meta.get("last_prompt") or "")[:200],
            "size": stat.st_size,
            # Use last meaningful event timestamp when available; fall back to mtime.
            # This prevents admin writes (custom-title etc.) from bumping "modified".
            # Emit "mtime" too (same value) so this per-repo payload matches the
            # archive builder's shape — both endpoints now carry both keys.
            "modified": tail_meta.get("last_meaningful_ts") or stat.st_mtime,
            "mtime": tail_meta.get("last_meaningful_ts") or stat.st_mtime,
            "modified_human": time.strftime(
                "%Y-%m-%d %H:%M",
                time.localtime(tail_meta.get("last_meaningful_ts") or stat.st_mtime),
            ),
            "session_cwd": cwd,
            "session_cwd_exists": bool(cwd and Path(cwd).is_dir()),
            # Cheap detection: a worktree's `.git` is a file, the shared
            # clone's `.git` is a directory. Lets the sidebar row render
            # a worktree-styled branch pill without paying for the full
            # workspace inference per row.
            "session_cwd_is_worktree": bool(
                cwd and (Path(cwd) / ".git").is_file()
            ),
            # Ground-truth uncommitted state from `git status --porcelain`,
            # cached on the session's last-event timestamp. Pairs with
            # has_edit && !has_commit (tool-event derived) on the client
            # — both surface as side-by-side pills on the row so we can
            # watch them for divergence.
            # Probe the EFFECTIVE worktree, not the literal session cwd:
            # sessions launched in the shared clone but editing a sibling
            # worktree had a misleading "git" chip — it was reflecting the
            # shared clone's dirtiness, not the worktree's. When inference
            # found a worktree, run `git status --porcelain` against that
            # worktree's path. Falls back to the literal cwd otherwise.
            "worktree_dirty": _worktree_dirty_cached(
                (eff_top if eff_kind == "worktree" and eff_top else cwd),
                tail_meta.get("last_meaningful_ts") or stat.st_mtime,
            ),
            # Tool-call-inferred effective branch/kind, populated above.
            # Lets the sidebar row reflect "where edits actually land"
            # for sessions launched in the shared clone but doing all
            # their work in a sibling worktree.
            "effective_branch": eff_branch,
            "effective_kind": eff_kind,
            # Session signals
            "has_edit": tail_meta.get("has_edit", False),
            "has_commit": tail_meta.get("has_commit", False),
            "has_push": tail_meta.get("has_push", False),
            "last_edit_pos": tail_meta.get("last_edit_pos", 0),
            "last_commit_pos": tail_meta.get("last_commit_pos", 0),
            "last_push_pos": tail_meta.get("last_push_pos", 0),
            "last_event_type": tail_meta.get("last_event_type"),
            "pending_tool": tail_meta.get("pending_tool"),
            "pending_file": tail_meta.get("pending_file"),
            "last_assistant_text": tail_meta.get("last_assistant_text"),
            "tail_issue_number": tail_meta.get("tail_issue_number"),
            "tail_pr_number": tail_meta.get("tail_pr_number"),
            "tail_pr_url": tail_meta.get("tail_pr_url"),
            # Subagent visibility — Task tool spawn counts + last few entries.
            # The list is capped to 8 entries on the parser side; the count
            # fields cover total / still-in-flight for the row chip.
            "subagent_count": tail_meta.get("subagent_count", 0),
            "subagent_in_flight_count": tail_meta.get("subagent_in_flight_count", 0),
            "subagent_recent": tail_meta.get("subagent_recent", []),
            # Resolved PR state — filled in below via a parallel prime
            # pass. See find_all_conversations for the broader rationale.
            "pr_state": None,
            "session_state": _parse_session_state(tail_meta.get("last_assistant_text")),
            "model": tail_meta.get("model"),
            "archived": sid in archived_set,
            "pinned": sid in pinned_rank,
            "pin_rank": pinned_rank.get(sid),
            "verified": sid in verified_set,
            # True when this row is showing here because the user pinned the
            # session to this repo (its underlying JSONL lives in another
            # repo's slug dir). Lets the UI render a 📌 indicator + unpin.
            "pinned_repo": sid in pinned_in_sids,
            # Last time the user interacted with this card via the UI.
            # None when they've never clicked/typed since this feature shipped.
            "last_interacted": last_interactions.get(sid) or last_interactions.get(conv_id),
        })

    # Registry-only live sessions have no JSONL yet, so the transcript scan
    # above cannot see them. Add matching rows for the current repo so the
    # sidebar can find them by UUID immediately after spawn.
    try:
        registry = _load_session_registry()
        for sid in live_sids:
            sid_jsonl_name = f"{sid}.jsonl"
            if sid_jsonl_name in seen_jsonl or sid in pinned_out_sids:
                continue
            meta = registry.get(sid)
            if not meta:
                continue
            cwd = meta.get("cwd") or ""
            cwd_top = _git_toplevel_for_path(cwd, git_top_cache) if cwd else None
            belongs_here = (
                sid in pinned_in_sids
                or cwd_top == repo_path
                or (cwd and _path_is_within(cwd, repo_path))
            )
            if not belongs_here:
                continue
            row = _live_registry_conversation_row(
                sid,
                meta,
                folder_path=repo_path,
                folder_label=_resolve_dir_case(repo_path),
                name_overrides=name_overrides,
                archived_set=archived_set,
                pinned_rank=pinned_rank,
                repo_pins=_repo_pins,
                resolve_worktree_dirty=True,
            )
            if row:
                conversations.append(row)
                seen_jsonl.add(sid_jsonl_name)
    except Exception:
        pass

    if progress:
        progress(
            "transcripts",
            state="done",
            count=total_jsonl,
            total=total_jsonl,
            detail=f"{len(conversations)} session(s) from {total_jsonl} transcript file(s).",
        )
        progress(
            "sessions",
            state="running",
            count=len(conversations),
            detail=f"{len(conversations)} interactive session(s) found; resolving PR state.",
        )

    # Parallel-resolve PR states for rows with a recorded PR URL — same
    # dance as find_all_conversations. The cache is shared across both
    # builders, so cross-folder mode benefits from single-repo warmups
    # (and vice versa).
    _prime_pr_states(c.get("tail_pr_url") for c in conversations)
    for c in conversations:
        url = c.get("tail_pr_url")
        if url:
            c["pr_state"] = _get_pr_state(url)
    if progress:
        progress(
            "sessions",
            state="done",
            count=len(conversations),
            detail=f"{len(conversations)} interactive session card(s) ready.",
        )
    # Primary sort: most recent activity first. Use whichever is later between
    # the user's last UI interaction and the session's last meaningful event,
    # so a card the user just typed into bubbles up immediately even before
    # Claude responds.
    conversations.sort(
        key=lambda x: x.get("last_interacted") or x.get("modified") or 0,
        reverse=True,
    )
    # Apply custom order (if any): listed sessions first in saved order,
    # unlisted (e.g. newly-created) sessions after, by mtime desc.
    order = _load_conversation_order()
    if order:
        by_sid = {c["session_id"]: c for c in conversations}
        by_id = {c["id"]: c for c in conversations}
        ordered = []
        seen = set()
        for key in order:
            c = by_sid.get(key) or by_id.get(key)
            if c and c["session_id"] not in seen:
                ordered.append(c)
                seen.add(c["session_id"])
        for c in conversations:
            if c["session_id"] not in seen:
                ordered.append(c)
        conversations = ordered
    _sort_pinned_conversations_first(conversations, pinned_list)
    if _PROFILE:
        _t_total = time.perf_counter() - _t_start
        print(
            f"  [profile] find_conversations rows={len(conversations)} "
            f"inflight={_inflight_now} "
            f"total={_t_total:.2f}s "
            f"head={_t_head:.2f}s/{_n_head} "
            f"cwd={_t_cwd:.2f}s/{_n_cwd} "
            f"tail={_t_tail:.2f}s/{_n_tail} "
            f"top={_t_top:.2f}s/{_n_top} (misses={_n_top_misses}) "
            f"eff={_t_eff:.2f}s/{_n_eff} (misses≈{_n_eff_misses}) "
            f"eff_skip_conc={_n_eff_skipped_concurrency} "
            f"eff_skip_drift={_n_eff_skipped_no_drift} "
            f"git_top_cache_size={len(git_top_cache)}",
            flush=True,
        )
    # Overlay the live-registry signal onto every row. The frontend's WIP
    # logic gates on c.is_live + c.pending_tool / sidecar_status; without
    # this overlay an active session shows no WIP chip in the sidebar.
    # Callers that go through find_all_sessions get the same overlay applied
    # at line ~7643 — it's idempotent. The /api/conversations endpoint
    # historically only had it via find_all_sessions, so direct callers
    # (e.g. the conversations handler at line ~17611) would silently lose
    # is_live; do it here so every caller sees the field.
    _reg_live_sids = live_sids if live_sids else set(_load_session_registry().keys())
    for c in conversations:
        sid = c.get("session_id")
        if sid is not None:
            c["is_live"] = sid in _reg_live_sids
    _dec_inflight()
    return conversations


def _read_sidecar_state(session_id):
    """Read sidecar state for a session. Returns dict or None."""
    path = SIDECAR_STATE_DIR / f"{session_id}.json"
    try:
        if path.exists():
            return json.loads(path.read_text())
    except (OSError, json.JSONDecodeError):
        pass
    return None


def _read_in_flight_state(session_id):
    """Return the PreToolUse in-flight marker for a session, or None.

    The marker is written when a tool starts and deleted by PostToolUse.
    Its presence means a tool is *currently* running; without it, the
    sidecar's `tool` field is just the most-recently-completed tool.
    """
    path = SIDECAR_STATE_DIR / f"{session_id}_in_flight.json"
    try:
        if path.exists():
            return json.loads(path.read_text())
    except (OSError, json.JSONDecodeError):
        pass
    return None


def _live_in_flight_or_none(session_id, inflight):
    """Drop a stale AskUserQuestion in-flight marker.

    A declined or interrupted AskUserQuestion (user hits Esc → the tool
    returns a tool_result with is_error and "Answer questions?") never
    fires PostToolUse, so pre-tool-use.py's in-flight marker is never
    cleared and lingers forever — the UI then shows a phantom "waiting for
    answer" box even though the agent already moved on. The transcript is
    authoritative: if the latest AskUserQuestion already has a matching
    tool_result it is no longer waiting, so the marker is stale and should
    be ignored. The scan only runs when an AskUserQuestion marker is
    present (rare), so this stays cheap on the per-poll read path.
    """
    if (inflight and inflight.get("tool") == "AskUserQuestion"
            and not _pending_ask_user_question_for_session(session_id)):
        return None
    return inflight


def _read_notification_state(session_id):
    """Return the Notification hook marker for a session, or None.

    The marker is written when Claude Code emits a `Notification` event
    (typically a permission prompt — "Claude needs your permission to
    use Bash"). PostToolUse clears it once the tool actually runs, so
    its presence is a precise "human input required" signal rather than
    the timing-based heuristic the dashboard previously relied on.
    """
    path = SIDECAR_STATE_DIR / f"{session_id}_needs_approval.json"
    try:
        if path.exists():
            return json.loads(path.read_text())
    except (OSError, json.JSONDecodeError):
        pass
    return None


def _cleanup_stale_sidecars(live_session_ids):
    """Remove sidecar files for sessions that are no longer live."""
    if not SIDECAR_STATE_DIR.is_dir():
        return
    for f in SIDECAR_STATE_DIR.iterdir():
        if not f.is_file():
            continue
        name = f.stem
        # Strip suffixes to get session_id (`_writes` flag, `_in_flight`
        # marker, `_needs_approval` marker).
        if name.endswith("_writes"):
            sid = name[:-len("_writes")]
        elif name.endswith("_in_flight"):
            sid = name[:-len("_in_flight")]
        elif name.endswith("_needs_approval"):
            sid = name[:-len("_needs_approval")]
        else:
            sid = name
        if sid not in live_session_ids:
            try:
                f.unlink()
            except OSError:
                pass


def _ask_payload_from_state(state):
    if not isinstance(state, dict):
        return {}
    options = []
    option_details = []
    raw_details = state.get("option_details")
    if isinstance(raw_details, list):
        for opt in raw_details:
            if isinstance(opt, dict):
                label = opt.get("label") or ""
                description = opt.get("description") or ""
            else:
                label = str(opt or "")
                description = ""
            if label:
                option_details.append({"label": label, "description": description})
                options.append(label)
    if not options:
        for opt in state.get("options") or []:
            if isinstance(opt, dict):
                label = opt.get("label") or ""
                description = opt.get("description") or ""
                if label:
                    option_details.append({"label": label, "description": description})
            else:
                label = str(opt or "")
            if label:
                options.append(label)
    return {
        "header": state.get("header") or "",
        "question": state.get("question") or "",
        "preamble": state.get("preamble") or "",
        "options": options,
        "option_details": option_details,
        "summary": state.get("summary") or state.get("file") or "",
    }


def _ask_option_tokens(value):
    tokens = []
    for token in re.findall(r"[a-z0-9]+", str(value or "").lower()):
        if len(token) > 3 and token.endswith("s"):
            token = token[:-1]
        if token in {"and", "or", "the", "for", "with"}:
            continue
        tokens.append(token)
    return set(tokens)


def _ask_payload_option_details(payload, transcript_payload):
    existing = payload.get("option_details") or []
    if any((opt.get("description") if isinstance(opt, dict) else "") for opt in existing):
        return existing
    transcript_details = transcript_payload.get("option_details") or []
    if not transcript_details:
        return existing
    options = payload.get("options") or []
    if not options:
        return transcript_details

    by_label = {
        opt.get("label"): opt
        for opt in transcript_details
        if isinstance(opt, dict) and opt.get("label")
    }
    merged = []
    for label in options:
        detail = by_label.get(label)
        descriptions = []
        if detail and detail.get("description"):
            descriptions.append(detail.get("description"))
        else:
            label_tokens = _ask_option_tokens(label)
            candidates = []
            for candidate in transcript_details:
                if not isinstance(candidate, dict):
                    continue
                candidate_label = candidate.get("label") or ""
                candidate_desc = candidate.get("description") or ""
                candidate_tokens = _ask_option_tokens(candidate_label)
                if not label_tokens or not candidate_tokens or not candidate_desc:
                    continue
                overlap = len(label_tokens & candidate_tokens)
                score = (2 * overlap) / max(1, len(label_tokens) + len(candidate_tokens))
                if overlap >= 2 and score >= 0.45:
                    candidates.append((score, overlap, candidate_desc))
            for _, _, desc in sorted(candidates, reverse=True)[:2]:
                if desc not in descriptions:
                    descriptions.append(desc)
        merged.append({"label": label, "description": " ".join(descriptions)})
    return merged if any(opt.get("description") for opt in merged) else existing


def _enrich_ask_payload_from_transcript(session_id, payload):
    """Fill missing rich question details from the JSONL transcript.

    Older hook markers only stored option labels. The transcript still has
    descriptions, so use it to upgrade active prompts without changing the
    legacy question_options response shape.
    """
    if not session_id:
        return payload or {}
    payload = dict(payload or {})
    if payload.get("summary") and payload.get("option_details") and payload.get("preamble"):
        return payload
    transcript_payload = _pending_ask_user_question_for_session(session_id) or {}
    if not transcript_payload:
        transcript_payload = _latest_ask_user_question_payload_for_session(
            session_id,
            header=payload.get("header") or "",
            question=payload.get("question") or "",
        ) or {}
    if not transcript_payload:
        return payload
    option_details = _ask_payload_option_details(payload, transcript_payload)
    if option_details:
        payload["option_details"] = option_details
    for key in ("header", "question", "preamble", "options", "option_details", "summary"):
        if not payload.get(key) and transcript_payload.get(key):
            payload[key] = transcript_payload.get(key)
    return payload


def _add_sidecar_fields(entry):
    """Add sidecar fields to a session entry, reading state if available.

    Prefer the in-flight marker (a tool currently running) over the sidecar's
    most-recently-completed tool — the in-flight tool is what users want to
    see on the kanban card while they wait.
    """
    sid = entry.get("session_id", "")
    is_live = entry.get("is_live")
    sc = _read_sidecar_state(sid) if is_live else None
    inflight = _live_in_flight_or_none(sid, _read_in_flight_state(sid)) if is_live else None
    notif = _read_notification_state(sid) if is_live else None
    entry["sidecar_status"] = sc.get("status") if sc else None
    entry["sidecar_has_writes"] = sc.get("has_writes", False) if sc else False
    entry["question_waiting"] = False
    entry["question_text"] = ""
    entry["question_header"] = ""
    entry["question_preamble"] = ""
    entry["question_options"] = []
    entry["question_option_details"] = []
    if inflight:
        tool = inflight.get("tool")
        file_ref = inflight.get("file")
        entry["sidecar_tool"] = tool
        entry["sidecar_file"] = _shell_command_activity_label(file_ref) if tool == "Bash" else file_ref
        entry["sidecar_ts"] = inflight.get("started_at", 0)
        entry["sidecar_in_flight"] = True
        if inflight.get("tool") == "AskUserQuestion":
            ask_payload = _enrich_ask_payload_from_transcript(
                sid, _ask_payload_from_state(inflight)
            )
            entry["question_waiting"] = True
            entry["question_text"] = ask_payload.get("question") or ""
            entry["question_header"] = ask_payload.get("header") or ""
            entry["question_preamble"] = ask_payload.get("preamble") or ""
            entry["question_options"] = ask_payload.get("options") or []
            entry["question_option_details"] = ask_payload.get("option_details") or []
            if not entry.get("sidecar_file"):
                entry["sidecar_file"] = ask_payload.get("summary") or ""
    else:
        tool = sc.get("tool") if sc else None
        file_ref = sc.get("file") if sc else None
        entry["sidecar_tool"] = tool
        entry["sidecar_file"] = _shell_command_activity_label(file_ref) if tool == "Bash" else file_ref
        entry["sidecar_ts"] = sc.get("timestamp", 0) if sc else 0
        entry["sidecar_in_flight"] = False
        if sc and sc.get("tool") == "AskUserQuestion":
            ask_payload = _enrich_ask_payload_from_transcript(
                sid, _ask_payload_from_state(sc)
            )
            entry["question_text"] = ask_payload.get("question") or ""
            entry["question_header"] = ask_payload.get("header") or ""
            entry["question_preamble"] = ask_payload.get("preamble") or ""
            entry["question_options"] = ask_payload.get("options") or []
            entry["question_option_details"] = ask_payload.get("option_details") or []
    # Notification hook signal — precise "Claude is asking for permission"
    # marker, replaces the brittle pending_tool/age heuristic on the UI side.
    entry["needs_approval"] = bool(notif)
    entry["needs_approval_message"] = notif.get("message", "") if notif else ""


def find_all_sessions(repo_path, progress=None, include_old=True):
    """Return a unified list of sessions: interactive conversations + pkood
    agents + ~/.claude/tasks backlog cards.

    Each entry has a 'source' field: 'interactive' | 'pkood' | 'task'.
    Sources are merged, custom-ordered, and sorted by mtime.
    """
    repo_path = resolve_repo_path(repo_path)
    global _SESSION_ISSUES_CACHE
    _SESSION_ISSUES_CACHE = _load_session_issues()
    registry = _load_session_registry()
    live_sids = set(registry.keys())
    # Get conversations and tag them
    if progress:
        progress("sessions", state="running", count=0, detail="Reading interactive sessions.")
    conversations = find_conversations(
        repo_path,
        progress=progress,
        include_old=include_old,
        live_sids=live_sids,
    )
    if progress:
        progress(
            "sessions",
            state="running",
            count=len(conversations),
            detail=f"{len(conversations)} interactive session(s); checking live registry.",
        )
    live_spawns = [s for s in _spawned_sessions if _poll_spawn_entry(s) is None]
    spawned_pids = {s["pid"] for s in live_spawns}
    spawned_engine_by_pid = {s["pid"]: s.get("engine", "claude") for s in live_spawns}
    for c in conversations:
        c["source"] = "interactive"
        sid = c.get("session_id")
        c["is_live"] = _archive_session_is_live(sid) if sid else False
        reg_pid = (registry.get(c["session_id"]) or {}).get("pid")
        c["spawn_pid"] = reg_pid if reg_pid in spawned_pids else None
        if c["spawn_pid"]:
            c["engine"] = spawned_engine_by_pid.get(c["spawn_pid"], "claude")

    if progress:
        progress("codex", state="running", detail="Reading Codex threads.")
    try:
        conversations.extend(find_codex_conversations(
            repo_path=repo_path,
            include_old=include_old,
            repo_only=True,
            progress=progress,
        ))
    except Exception as exc:
        if progress:
            progress("codex", state="error", detail=f"Codex thread scan failed: {exc}")

    if progress:
        progress("gemini", state="running", detail="Reading Gemini sessions.")
    try:
        conversations.extend(find_gemini_conversations(
            repo_path=repo_path,
            include_old=include_old,
            repo_only=True,
            progress=progress,
        ))
    except Exception as exc:
        if progress:
            progress("gemini", state="error", detail=f"Gemini session scan failed: {exc}")

    if progress:
        progress("cursor", state="running", detail="Reading Cursor sessions.")
    try:
        conversations.extend(find_cursor_conversations(
            repo_path=repo_path,
            include_old=include_old,
            repo_only=True,
            progress=progress,
        ))
    except Exception as exc:
        if progress:
            progress("cursor", state="error", detail=f"Cursor session scan failed: {exc}")

    if progress:
        progress("antigravity", state="running", detail="Reading Antigravity sessions.")
    try:
        conversations.extend(find_antigravity_conversations(
            repo_path=repo_path,
            include_old=include_old,
            repo_only=True,
            progress=progress,
        ))
    except Exception as exc:
        if progress:
            progress("antigravity", state="error", detail=f"Antigravity session scan failed: {exc}")

    # Add pkood agents — and merge in their linked claude-session card, if any.
    # Pkood spawns a claude process in a tmux pty, which produces a regular
    # ~/.claude/projects/*/*.jsonl file. Without dedup the kanban would show
    # two cards per agent: a pkood card (input works, via /api/pkood/inject)
    # and a claude-session card (input broken — no Terminal tab backs the
    # pty). We resolve the link in find_pkood_agents() via a cwd+timestamp
    # heuristic; here we absorb the jsonl card's signals into the pkood card
    # and drop the duplicate.
    if progress:
        progress("agents", state="running", detail="Checking pkood agents.")
    pkood_agents = find_pkood_agents()
    if progress:
        progress(
            "agents",
            state="done",
            count=len(pkood_agents),
            detail=f"{len(pkood_agents)} pkood agent(s) found.",
        )
    # Only dedup live pkood agents. Dead ones leave their jsonl visible as
    # a regular interactive card so the user can still `claude --resume` the
    # underlying session — the pkood card alone can't be resumed.
    linked_sids = {
        a["claude_session_id"]
        for a in pkood_agents
        if a.get("claude_session_id") and a.get("is_live")
    }
    if linked_sids:
        by_sid = {c["session_id"]: c for c in conversations if c.get("source") == "interactive"}
        for agent in pkood_agents:
            if not agent.get("is_live"):
                continue
            csid = agent.get("claude_session_id")
            if not csid:
                continue
            twin = by_sid.get(csid)
            if not twin:
                continue
            # Keep the pkood identity (id, session_id, source) so the frontend
            # routes input via /api/pkood/inject — but pull in the richer
            # signals the jsonl tail scan produced.
            for field in (
                "first_message", "last_prompt", "branch",
                "has_edit", "has_commit", "has_push",
                "last_edit_pos", "last_commit_pos", "last_push_pos",
                "last_event_type", "pending_tool", "pending_file",
                "last_assistant_text", "tail_issue_number", "session_state",
                "timestamp",
            ):
                if field in twin and twin[field] not in (None, "", False) and not agent.get(field):
                    agent[field] = twin[field]
            # Prefer the jsonl's display_name when pkood's is just the agent_id
            # slug (e.g. the pkood card would show "mgr-schedule" but the jsonl
            # may have a user-renamed title).
            if twin.get("display_name") and not agent.get("name_overridden"):
                agent["display_name"] = twin["display_name"]
                agent["name_overridden"] = twin.get("name_overridden", False)
            # Prefer the jsonl's mtime for freshness sorting — pkood's
            # update_ts can lag behind the actual last assistant event.
            if twin.get("modified") and twin["modified"] > (agent.get("modified") or 0):
                agent["modified"] = twin["modified"]
                agent["modified_human"] = twin.get("modified_human", agent.get("modified_human", ""))
            # Preserve the linked cwd when the jsonl knows it and we didn't.
            if not agent.get("session_cwd") and twin.get("session_cwd"):
                agent["session_cwd"] = twin["session_cwd"]
                agent["session_cwd_exists"] = twin.get("session_cwd_exists", False)
        # Drop the now-redundant interactive twins
        conversations = [
            c for c in conversations
            if not (c.get("source") == "interactive" and c.get("session_id") in linked_sids)
        ]
    for agent in pkood_agents:
        conversations.append(agent)

    # Add backlog items (GitHub issues + TODO.md), skipping those with active sessions
    _issue_pattern = re.compile(r"(?:issue|fix)[/-](\d+)")
    active_issue_nums = set()
    for c in conversations:
        # Check branch for issue-N or fix/N patterns
        branch = c.get("branch", "") or ""
        for m in _issue_pattern.finditer(branch):
            active_issue_nums.add(m.group(1))
        # Check display_name for #N or issue-N patterns
        dname = c.get("display_name", "") or ""
        for m in re.finditer(r"#(\d+)", dname):
            active_issue_nums.add(m.group(1))
        for m in _issue_pattern.finditer(dname):
            active_issue_nums.add(m.group(1))
        # Also check first_message (the prompt) for #N
        fm = c.get("first_message", "") or ""
        for m in re.finditer(r"#(\d+)", fm):
            active_issue_nums.add(m.group(1))
        for m in _issue_pattern.finditer(fm):
            active_issue_nums.add(m.group(1))
    # Native-task cards key off session_id, not issue number — collect the
    # set of session_ids already represented so we don't double-up.
    existing_sids = {c.get("session_id") for c in conversations if c.get("session_id")}
    if progress:
        progress("cards", state="running", count=len(conversations), detail="Merging sessions with backlog cards.")
    backlog_added = 0
    for item in find_backlog_items(repo_path, progress=progress):
        inum = item.get("issue_number", "")
        if inum and inum in active_issue_nums:
            continue  # Active session already covers this issue
        if (item.get("backlog_type") == "native_task"
                and item.get("session_id") in existing_sids):
            continue  # The session is already on the board; don't dup
        conversations.append(item)
        backlog_added += 1
    if progress:
        progress(
            "cards",
            state="running",
            count=len(conversations),
            detail=f"Added {backlog_added} backlog card(s); enriching issue state.",
        )

    # Sidecar: clean up stale files, then enrich every entry
    _cleanup_stale_sidecars(live_sids)
    if progress:
        progress("issue_states", state="running", detail="Loading linked issue states.")
    issue_states = _fetch_issue_states(repo_path)
    if progress:
        progress(
            "issue_states",
            state="done",
            count=len(issue_states),
            detail=f"{len(issue_states)} linked issue state(s) cached.",
        )
    desktop_meta = _load_desktop_app_metadata()
    for c in conversations:
        if c.get("source") not in ("codex", "gemini", "cursor", "antigravity"):
            _add_sidecar_fields(c)
        # Desktop-app metadata decoration: use human-friendly title if present,
        # and flag the session as having been touched by the desktop app.
        dm = desktop_meta.get(c.get("session_id"))
        if dm:
            c["desktop_app"] = True
            if dm.get("model") and not c.get("model"):
                c["model"] = dm["model"]
            if dm.get("cwd") and not c.get("session_cwd"):
                c["session_cwd"] = dm["cwd"]
                c["session_cwd_exists"] = Path(dm["cwd"]).is_dir()
                c["session_cwd_is_worktree"] = bool((Path(dm["cwd"]) / ".git").is_file())
            if dm.get("title") and not c.get("name_overridden"):
                # Only replace auto-slug / CLI-generated names; never overwrite a user rename.
                raw_name = (c.get("display_name") or "").strip()
                looks_like_slug = bool(re.match(r"^[a-z0-9\-]+$", raw_name))
                if not raw_name or looks_like_slug or raw_name.lower().startswith("issue-"):
                    c["display_name"] = dm["title"]
        # Link to GitHub issue (from side-car mapping or heuristic)
        if c.get("source") != "backlog":
            c["linked_issue"] = _detect_issue_number_for_session(c)
            # If linked to a real issue, enrich display_name with the issue title
            if c.get("linked_issue"):
                titles = _fetch_issue_titles(repo_path)
                title = titles.get(c["linked_issue"])
                if title:
                    raw_name = (c.get("display_name") or "").strip().lower()
                    # Replace generic slugs like "issue-110" with the real title
                    if not raw_name or raw_name == f"issue-{c['linked_issue']}" or raw_name.startswith("fix-github-issue"):
                        c["display_name"] = f"#{c['linked_issue']}: {title}"
        # Attach GitHub state/labels if a linked issue is known
        inum = c.get("linked_issue") or c.get("issue_number")
        if inum:
            st = issue_states.get(str(inum))
            if st:
                c["gh_state"] = st["state"]  # "OPEN" / "CLOSED"
                c["gh_labels"] = st["labels"]
                c["gh_in_progress"] = "claude-in-progress" in st["labels"]
        # Backlog cards: mark WIP from their own labels
        if c.get("source") == "backlog":
            c["gh_state"] = "OPEN"
            c["gh_in_progress"] = "claude-in-progress" in (c.get("issue_labels") or [])

    # Sort by latest activity desc (using user-interaction timestamp when it's
    # more recent than the session's mtime), then apply custom order. Pkood
    # and backlog cards lack `last_interacted` and fall back to `modified` —
    # the max() handles missing keys uniformly.
    conversations.sort(
        key=lambda x: x.get("last_interacted") or x.get("modified") or 0,
        reverse=True,
    )
    order = _load_conversation_order()
    if order:
        by_sid = {c["session_id"]: c for c in conversations}
        by_id = {c["id"]: c for c in conversations}
        ordered = []
        seen = set()
        for key in order:
            c = by_sid.get(key) or by_id.get(key)
            if c and c["session_id"] not in seen:
                ordered.append(c)
                seen.add(c["session_id"])
        for c in conversations:
            if c["session_id"] not in seen:
                ordered.append(c)
        conversations = ordered

    try:
        _pinned_list = _load_pinned_conversations()
    except Exception:
        _pinned_list = []
    _apply_pinned_conversation_fields(conversations, _pinned_list)
    _sort_pinned_conversations_first(conversations, _pinned_list)

    if progress:
        progress(
            "cards",
            state="done",
            count=len(conversations),
            detail=f"{len(conversations)} card(s) ready for the board.",
        )

    # Auto-verify: sessions with has_push linked to closed GH issues get verified.
    # Runs inline (cheap — just reads cached issue states + verified list).
    try:
        auto_verify_closed_issues(repo_path)
    except Exception:
        pass

    return conversations


def _resolve_conversation_path(conversation_id, repo_path=None):
    """Return the JSONL path for a session.

    Resolution order:
      1. Slugs for the supplied repo path, when present.
      2. Global walk of ~/.claude/projects/*/ for session-derived calls.
      3. A canonical repo path when supplied, otherwise a harmless missing path.
    """
    name = conversation_id + ".jsonl"
    if repo_path:
        for d in _conversation_dirs(repo_path):
            cand = d / name
            if cand.is_file():
                return cand
    if PROJECTS_ROOT.is_dir():
        try:
            for project_dir in PROJECTS_ROOT.iterdir():
                if not project_dir.is_dir():
                    continue
                cand = project_dir / name
                if cand.is_file():
                    return cand
        except OSError:
            pass
    if repo_path:
        return _canonical_conversation_path(repo_path, conversation_id)
    return PROJECTS_ROOT / "_missing" / name


def _resolve_conversation_reader(conversation_id, repo_path=None):
    claude_path = _resolve_conversation_path(conversation_id, repo_path=repo_path)
    if claude_path.is_file():
        return claude_path, _parse_conversation_event
    codex_path = _resolve_codex_rollout_path(conversation_id)
    if codex_path and codex_path.is_file():
        return codex_path, _parse_codex_event
    cursor_path = _cursor_transcript_path(conversation_id)
    if cursor_path and cursor_path.is_file():
        return cursor_path, _parse_cursor_event
    antigravity_path = _antigravity_transcript_path(conversation_id)
    if antigravity_path and antigravity_path.is_file():
        return antigravity_path, _parse_antigravity_event
    return claude_path, _parse_conversation_event


def _registry_only_conversation_stub(conversation_id, after_line=0):
    sid = str(conversation_id or "").strip()
    if not sid:
        return None
    try:
        meta = _load_session_registry().get(sid)
    except Exception:
        meta = None
    if not meta:
        return None

    spawn_entry = _spawn_registry_entry_for_session(sid, engine="claude") or {}
    prompt = _strip_ccc_session_state_instruction(
        spawn_entry.get("command_summary") or ""
    ).strip()
    ts_epoch = (
        _registry_epoch_seconds(meta.get("updatedAt"))
        or _registry_epoch_seconds(meta.get("startedAt"))
        or 0
    )
    ts = (
        datetime.fromtimestamp(ts_epoch, timezone.utc).isoformat().replace("+00:00", "Z")
        if ts_epoch else ""
    )

    raw_events = []
    if prompt:
        raw_events.append({
            "line": 1,
            "ts": ts,
            "type": "user_text",
            "text": prompt,
            "images": [],
        })
    raw_events.append({
        "line": len(raw_events) + 1,
        "ts": ts,
        "type": "assistant",
        "message_id": f"registry-only-{sid}",
        "blocks": [{
            "kind": "text",
            "text": "Live Claude process is registered, but no transcript JSONL has been written yet.",
        }],
    })

    try:
        after = int(after_line or 0)
    except (TypeError, ValueError):
        after = 0
    events = [ev for ev in raw_events if ev.get("line", 0) > after]
    events.extend(_get_queued_events_for_session(sid))
    return {"events": events, "last_line": len(raw_events)}


# Per-conversation parse cache. Keyed on (conv_id, after_line, jsonl_mtime).
# Conversations are append-only files — once the JSONL's mtime is unchanged,
# the parsed result for a given after_line offset is bit-identical. The cache
# turns the click→render path on already-opened convs from ~170 ms (full
# parse of a ~750 KB JSONL) into a hash-table lookup. Bounded so a long
# session of clicking around different convs doesn't grow unbounded.
_CONV_PARSE_CACHE = {}
_CONV_PARSE_CACHE_LOCK = threading.Lock()
_CONV_PARSE_CACHE_MAX = 96


_CONV_PATH_CACHE = {}
_CONV_PATH_CACHE_LOCK = threading.Lock()


def _conv_parse_jsonl_mtime(conversation_id, repo_path=None):
    """Return a (mtime_ns, size) tuple for the JSONL backing this
    conversation, or (0, 0) if we can't resolve it. Used as a cache key;
    nanosecond precision + size catches the case where a new event lands
    in the same second as a cache write (st_mtime float has 1s resolution
    on macOS/Linux, which let pre-baked response bytes from before the
    final event be served back, dropping the trailing message). The (sid
    → path) cache is preserved across calls; only the stat is re-run.
    """
    try:
        with _CONV_PATH_CACHE_LOCK:
            path = _CONV_PATH_CACHE.get(conversation_id)
        if path is not None:
            p = Path(path)
            try:
                st = p.stat()
                return (st.st_mtime_ns, st.st_size)
            except OSError:
                # File moved/deleted — drop the stale entry and re-resolve.
                with _CONV_PATH_CACHE_LOCK:
                    _CONV_PATH_CACHE.pop(conversation_id, None)
                path = None
        if _is_gemini_session(conversation_id):
            resolved = _resolve_gemini_chat_path(conversation_id)
        elif _is_cursor_session(conversation_id):
            resolved = _cursor_transcript_path(conversation_id)
        elif _is_antigravity_session(conversation_id):
            resolved = _antigravity_transcript_path(conversation_id)
        else:
            resolved, _ = _resolve_conversation_reader(conversation_id, repo_path=repo_path)
        if resolved and Path(resolved).is_file():
            with _CONV_PATH_CACHE_LOCK:
                _CONV_PATH_CACHE[conversation_id] = str(resolved)
            st = Path(resolved).stat()
            return (st.st_mtime_ns, st.st_size)
    except Exception:
        pass
    return (0, 0)


_CONV_TAIL_DEFAULT = 150  # lines pulled for the initial tail window on open


def _parse_conversation_windowed(conversation_id, filepath, tail, before, parser=None):
    """Parse only a window of a conversation JSONL instead of the whole file.

    Two modes:
      tail=N            -> the last N lines (initial open of a long file)
      before=L (+ tail) -> the N lines immediately before line L ("load earlier")

    The full file is still *read* (cheap — a 22MB read is ~14ms), but json.loads
    + the per-event parser run only on the windowed lines, which is where the
    cost is. Returns the normal {events,last_line} plus `first_line` and
    `truncated_before` so the UI knows whether earlier history remains.

    Claude (stateless) and codex are supported. Codex carries a running token
    usage across lines; we accumulate it from usage events *within the window*,
    so it reflects the most recent usage seen in the slice (the context-% pill
    self-corrects on the next turn) rather than the whole file.
    """
    parser = parser or _parse_conversation_event
    is_codex = parser is _parse_codex_event
    window = tail if tail else _CONV_TAIL_DEFAULT
    buf = collections.deque(maxlen=window)
    total = 0
    try:
        with open(filepath, "r") as f:
            for line in f:
                total += 1
                if before is not None and total >= before:
                    # still need to keep counting for last_line
                    continue
                buf.append((total, line))
    except FileNotFoundError:
        return {"events": [], "last_line": 0, "first_line": 0, "truncated_before": False}

    events = []
    codex_token_usage = None
    for ln, line in buf:
        line = line.strip()
        if not line:
            continue
        try:
            ev = json.loads(line)
        except json.JSONDecodeError:
            continue
        if is_codex:
            usage = _codex_token_usage_from_event(ev)
            if usage:
                codex_token_usage = usage
                continue
            parsed = parser(ev, ln, codex_token_usage)
        else:
            parsed = parser(ev, ln)
        if parsed:
            events.append(parsed)

    first_line = events[0]["line"] if events else (buf[0][0] if buf else total)
    result = {
        "events": events,
        "last_line": total,
        "first_line": first_line,
        "truncated_before": first_line > 1,
    }
    if before is None:
        # The live tail also carries any optimistic queued events, same as the
        # full-parse path; an earlier-history window must not.
        out = list(events)
        out.extend(_get_queued_events_for_session(conversation_id))
        result["events"] = out
    return result


def parse_conversation(conversation_id, after_line=0, repo_path=None, use_cache=True,
                       tail=None, before=None):
    """Parse a conversation JSONL file into structured events.

    `use_cache=True` (default) checks the in-memory parse cache keyed on the
    JSONL's mtime — see _CONV_PARSE_CACHE. Set False for callers that need a
    guaranteed re-parse.

    `tail`/`before` request a windowed parse (last N lines / the window before
    a line) instead of the whole file — see _parse_conversation_windowed. Only
    honored for claude transcripts (stateless parser); other engines full-parse.
    """
    windowed = bool(tail) or (before is not None)
    if use_cache and not windowed:
        mtime = _conv_parse_jsonl_mtime(conversation_id, repo_path=repo_path)
        if mtime[0] > 0:
            key = (conversation_id, int(after_line), mtime)
            with _CONV_PARSE_CACHE_LOCK:
                hit = _CONV_PARSE_CACHE.get(key)
            if hit is not None:
                events_copy = list(hit.get("events") or [])
                events_copy.extend(_get_queued_events_for_session(conversation_id))
                return {"events": events_copy, "last_line": hit.get("last_line", 0)}
    # Route via the memoized engine detector instead of probing gemini then
    # antigravity unconditionally — _is_gemini_session scans the whole gemini
    # store (~160ms cold), which every codex/claude open was paying for nothing.
    # _detect_session_engine checks codex first and is cached.
    engine = _detect_session_engine(conversation_id)
    if engine == "gemini":
        result = _parse_gemini_conversation(conversation_id, after_line=after_line)
        _conv_parse_cache_put(conversation_id, after_line, repo_path, result)
        events_copy = list(result.get("events") or [])
        events_copy.extend(_get_queued_events_for_session(conversation_id))
        return {"events": events_copy, "last_line": result.get("last_line", 0)}
    if engine == "antigravity":
        result = _parse_antigravity_conversation(conversation_id, after_line=after_line)
        _conv_parse_cache_put(conversation_id, after_line, repo_path, result)
        events_copy = list(result.get("events") or [])
        events_copy.extend(_get_queued_events_for_session(conversation_id))
        return {"events": events_copy, "last_line": result.get("last_line", 0)}
    filepath, parser = _resolve_conversation_reader(conversation_id, repo_path=repo_path)
    if parser is _parse_conversation_event and not Path(filepath).is_file():
        stub = _registry_only_conversation_stub(conversation_id, after_line=after_line)
        if stub is not None:
            return stub
    # Windowed open: claude (stateless) and codex (token-usage accumulated
    # within the window) can parse a slice correctly. Gemini/antigravity use
    # whole-file parsers above and fall through to the full parse below.
    if windowed and parser in (_parse_conversation_event, _parse_codex_event) \
            and Path(filepath).is_file():
        return _parse_conversation_windowed(conversation_id, filepath, tail, before, parser)
    events = []
    line_num = 0
    is_codex = parser is _parse_codex_event
    codex_token_usage = None
    is_cursor = parser is _parse_cursor_event
    # Cursor JSONLs record no per-event timestamp (only `role` + `message`)
    # so every event ended up with ts="", and the browser fell back to
    # nowStamp() — making every row claim "just now" regardless of actual
    # age. We don't have true per-event times, so the closest honest
    # approximation is to interpolate between the file's birthtime (first
    # event) and mtime (last event); cursor sessions are streamed
    # append-only so position-in-file ≈ position-in-time. Falls back to
    # mtime-everywhere when birthtime isn't available.
    cursor_ts_start = 0.0  # epoch seconds
    cursor_ts_end = 0.0
    if is_cursor:
        try:
            st = Path(filepath).stat()
            cursor_ts_end = float(st.st_mtime)
            cursor_ts_start = float(getattr(st, "st_birthtime", st.st_mtime) or st.st_mtime)
            # Defensive: if birthtime > mtime (clock skew, restored file),
            # just collapse to mtime everywhere.
            if cursor_ts_start > cursor_ts_end:
                cursor_ts_start = cursor_ts_end
        except (OSError, ValueError, OverflowError):
            cursor_ts_start = cursor_ts_end = 0.0

    def _cursor_ts_iso(epoch):
        try:
            return datetime.fromtimestamp(float(epoch), tz=timezone.utc).isoformat().replace("+00:00", "Z")
        except (TypeError, ValueError, OverflowError, OSError):
            return ""

    try:
        with open(filepath, "r") as f:
            for line in f:
                line_num += 1
                if line_num <= after_line:
                    if is_codex:
                        try:
                            ev = json.loads(line.strip())
                        except json.JSONDecodeError:
                            ev = None
                        if ev:
                            usage = _codex_token_usage_from_event(ev)
                            if usage:
                                codex_token_usage = usage
                    continue
                line = line.strip()
                if not line:
                    continue
                try:
                    ev = json.loads(line)
                except json.JSONDecodeError:
                    continue

                if is_codex:
                    usage = _codex_token_usage_from_event(ev)
                    if usage:
                        codex_token_usage = usage
                        continue
                    parsed = parser(ev, line_num, codex_token_usage)
                else:
                    parsed = parser(ev, line_num)
                if parsed:
                    events.append(parsed)
    except FileNotFoundError:
        stub = _registry_only_conversation_stub(conversation_id, after_line=after_line)
        if stub is not None:
            return stub

    # Cursor: fill empty ts by interpolating between file birthtime and
    # mtime. With one event the only honest answer is mtime; with two or
    # more, linearly spread between start and end so the UI shows
    # distinct, monotonically-increasing times instead of N copies of
    # "just now".
    if is_cursor and cursor_ts_end > 0:
        missing_idx = [i for i, e in enumerate(events) if not e.get("ts")]
        m = len(missing_idx)
        if m == 1:
            events[missing_idx[0]]["ts"] = _cursor_ts_iso(cursor_ts_end)
        elif m > 1:
            span = cursor_ts_end - cursor_ts_start
            for k, idx in enumerate(missing_idx):
                frac = k / (m - 1)
                events[idx]["ts"] = _cursor_ts_iso(cursor_ts_start + span * frac)

    result = {"events": events, "last_line": line_num}
    _conv_parse_cache_put(conversation_id, after_line, repo_path, result)
    events_copy = list(events)
    events_copy.extend(_get_queued_events_for_session(conversation_id))
    return {"events": events_copy, "last_line": line_num}



def _conv_parse_cache_put(conversation_id, after_line, repo_path, result):
    """Stash a parse result under (sid, after_line, current jsonl mtime)."""
    mtime = _conv_parse_jsonl_mtime(conversation_id, repo_path=repo_path)
    if mtime[0] <= 0:
        return
    key = (conversation_id, int(after_line), mtime)
    with _CONV_PARSE_CACHE_LOCK:
        if len(_CONV_PARSE_CACHE) >= _CONV_PARSE_CACHE_MAX:
            # Drop the oldest entry — Python 3.7+ dicts preserve insertion
            # order, so popping the first key is FIFO eviction. Fine for
            # this use case; recency-weighting isn't worth the bookkeeping.
            try:
                _CONV_PARSE_CACHE.pop(next(iter(_CONV_PARSE_CACHE)))
            except StopIteration:
                pass
        _CONV_PARSE_CACHE[key] = result


# Pre-serialized response bytes for /api/conversations/<id>?after=N. The
# parse-cache above saves the line-walk; this cache saves the json.dumps
# (~60 ms for a 700 KB conv) AND the gzip (~15 ms) on top. A click on a
# conversation the user already opened once becomes a sub-5 ms socket
# write. Keys are (sid, after_line, jsonl_mtime); values are {"raw": bytes,
# "gzip": bytes|None}. Bounded so memory doesn't blow up.
_CONV_BYTES_CACHE = {}
_CONV_BYTES_CACHE_LOCK = threading.Lock()
_CONV_BYTES_CACHE_MAX = 48


def _session_has_pending_input(session_id):
    """True when inject/resume queues still hold unsent text for this session."""
    if not session_id:
        return False
    with _pending_resume_lock:
        if _pending_resume_queue.get(session_id):
            return True
    with _pending_terminal_input_lock:
        if _pending_terminal_input_queue.get(session_id):
            return True
    return False


def _conv_response_bytes_get(conversation_id, after_line):
    mtime = _conv_parse_jsonl_mtime(conversation_id)
    if mtime[0] <= 0:
        return None
    # Queued injects are not in the JSONL yet; a pre-baked response from
    # before the queue grew would omit them until mtime changes.
    if _session_has_pending_input(conversation_id):
        return None
    key = (conversation_id, int(after_line), mtime)
    with _CONV_BYTES_CACHE_LOCK:
        return _CONV_BYTES_CACHE.get(key)


def _conv_response_bytes_put(conversation_id, after_line, raw, gz):
    mtime = _conv_parse_jsonl_mtime(conversation_id)
    if mtime[0] <= 0:
        return
    key = (conversation_id, int(after_line), mtime)
    with _CONV_BYTES_CACHE_LOCK:
        if len(_CONV_BYTES_CACHE) >= _CONV_BYTES_CACHE_MAX:
            try:
                _CONV_BYTES_CACHE.pop(next(iter(_CONV_BYTES_CACHE)))
            except StopIteration:
                pass
        _CONV_BYTES_CACHE[key] = {"raw": raw, "gzip": gz}


# Regex for files-from-conversation extraction. Two patterns: HTTP(S)
# URLs, and absolute Unix paths anchored to whitespace/quote/paren so
# we don't pull tokens out of the middle of code identifiers.
_FFC_URL_RE = re.compile(r"https?://[^\s<>\"'`)\]]+")
_FFC_PATH_RE = re.compile(r"(?:^|(?<=[\s\"'`(\[]))(/[^\s\"'`<>)\]]+)")
_FFC_PATH_TRAIL_PUNCT = ".,;:!?)]}>'\""
_FFC_MAX_ENTRIES = 500


def _ffc_clean_match(s, is_url):
    """Strip trailing punctuation that the regex pulled in. URLs lose
    `).,;` etc. Paths the same. Returns the cleaned string or '' if
    cleaning leaves nothing useful."""
    if not s:
        return ""
    while s and s[-1] in _FFC_PATH_TRAIL_PUNCT:
        s = s[:-1]
    return s


def _ffc_iter_targets(text):
    """Yield (target, kind) for every URL/path mention in `text`.
    Does NOT filter by extension — caller (the extractor) does that."""
    if not isinstance(text, str) or not text:
        return
    for m in _FFC_URL_RE.finditer(text):
        cleaned = _ffc_clean_match(m.group(0), is_url=True)
        if cleaned:
            yield (cleaned, "url")
    for m in _FFC_PATH_RE.finditer(text):
        cleaned = _ffc_clean_match(m.group(1), is_url=False)
        if cleaned:
            yield (cleaned, "path")


def _ffc_flatten_strings(value):
    """Walk a tool_use input dict yielding every nested string. Used
    to scan entire `Bash{command: …}` / `Edit{old_string: …}` payloads,
    not just the surface fields, so a path buried in a long bash
    command is still caught."""
    if isinstance(value, str):
        yield value
    elif isinstance(value, dict):
        for v in value.values():
            yield from _ffc_flatten_strings(v)
    elif isinstance(value, list):
        for v in value:
            yield from _ffc_flatten_strings(v)


_PROMPT_SECRET_RE = re.compile(
    r"(?i)\b(?:sk-[a-z0-9_-]{16,}|gsk_[a-z0-9_-]{16,}|xox[abprs]-[a-z0-9-]{16,})\b"
)


def _prompt_fragment(text, max_len=240):
    """Normalize one UI-safe prompt fragment for status chips."""
    if not isinstance(text, str):
        return ""
    text = re.sub(r"\s+", " ", text).strip()
    if not text:
        return ""
    text = _PROMPT_SECRET_RE.sub("[redacted]", text)
    if len(text) > max_len:
        return text[: max_len - 3].rstrip() + "..."
    return text


def _shell_preview_parts(command):
    parts = []
    buf = []
    quote = ""
    escaped = False
    i = 0
    while i < len(command):
        ch = command[i]
        if quote:
            buf.append(ch)
            if escaped:
                escaped = False
            elif ch == "\\":
                escaped = True
            elif ch == quote:
                quote = ""
            i += 1
            continue
        if ch in ("'", '"'):
            quote = ch
            buf.append(ch)
            i += 1
            continue
        if command.startswith("&&", i) or command.startswith("||", i):
            segment = "".join(buf).strip()
            if segment:
                parts.append(("segment", segment))
            parts.append(("op", command[i:i + 2]))
            buf = []
            i += 2
            continue
        if ch == ";":
            segment = "".join(buf).strip()
            if segment:
                parts.append(("segment", segment))
            parts.append(("op", ";"))
            buf = []
            i += 1
            continue
        buf.append(ch)
        i += 1
    segment = "".join(buf).strip()
    if segment:
        parts.append(("segment", segment))
    return parts


def _shell_preview_wrapper_segment(segment):
    text = re.sub(r"\s+", " ", segment or "").strip()
    text = re.sub(r"(?:^|\s+)2>\s*/dev/null\b", "", text).strip()
    if text in ("true", ":"):
        return True
    if re.fullmatch(r"(?:(?:command|builtin)\s+)?(?:setopt|unsetopt)\s+[-A-Za-z0-9_\s]+", text):
        return True
    if re.fullmatch(r"(?:(?:command|builtin)\s+)?shopt\s+-[su]\s+[-A-Za-z0-9_\s]+", text):
        return True
    return False


def _shell_command_preview(command, max_len=1000):
    """Return a readable shell command preview for live activity chips."""
    if not isinstance(command, str):
        return ""
    raw = _PROMPT_SECRET_RE.sub("[redacted]", re.sub(r"\s+", " ", command).strip())
    if not raw:
        return ""
    kept = []
    for kind, value in _shell_preview_parts(raw):
        if kind == "segment":
            if _shell_preview_wrapper_segment(value):
                continue
            if kept and kept[-1][0] == "op":
                kept.append((kind, value))
            elif not kept or kept[-1][0] != "segment":
                kept.append((kind, value))
            else:
                kept.append(("op", ";"))
                kept.append((kind, value))
            continue
        if kept and kept[-1][0] == "segment":
            kept.append((kind, value))
    while kept and kept[-1][0] == "op":
        kept.pop()
    cleaned = " ".join(value for _, value in kept).strip() or raw
    return _prompt_fragment(cleaned, max_len)


def _redacted_shell_command_text(command, max_len=8000):
    """Preserve a shell command's formatting while redacting obvious secrets."""
    if not isinstance(command, str):
        return ""
    text = command.replace("\r\n", "\n").replace("\r", "\n").strip()
    if not text:
        return ""
    text = _PROMPT_SECRET_RE.sub("[redacted]", text)
    if len(text) > max_len:
        return text[: max_len - 3].rstrip() + "..."
    return text


def _iter_shell_comment_texts(command):
    text = _redacted_shell_command_text(command, max_len=12000)
    if "#" not in text:
        return

    quote = ""
    escaped = False
    line_start = 0
    i = 0
    while i < len(text):
        ch = text[i]
        if quote:
            if escaped:
                escaped = False
            elif ch == "\\" and quote == '"':
                escaped = True
            elif ch == quote:
                quote = ""
            if ch in "\r\n":
                line_start = i + 1
            i += 1
            continue

        if ch in ("'", '"'):
            quote = ch
            i += 1
            continue
        if ch == "\\":
            i += 2
            continue
        if ch in "\r\n":
            line_start = i + 1
            i += 1
            continue
        if ch == "#" and (i == line_start or text[i - 1].isspace()):
            prefix = text[line_start:i].strip()
            if not prefix and i + 1 < len(text) and text[i + 1] == "!":
                i += 1
                continue
            end = i + 1
            while end < len(text) and text[end] not in "\r\n":
                end += 1
            yield text[i + 1:end]
            i = end
            continue
        i += 1


def _clean_shell_inline_comment_note(note, max_len=180):
    text = _PROMPT_SECRET_RE.sub("[redacted]", re.sub(r"\s+", " ", note or "").strip())
    text = text.strip(" -#")
    if not text or not re.search(r"[A-Za-z]", text):
        return ""
    if re.match(r"(?i)^(?:shellcheck|noqa|pylint|eslint|prettier|type:\s)", text):
        return ""

    text = re.split(r"\s+(?:&&|\|\||;|\|)\s+", text, maxsplit=1)[0].strip()
    command_tail = re.search(
        r"\s+(?:curl|python[0-9.]*|node|npm|pnpm|yarn|bun|deno|git|gh|rg|grep|"
        r"sed|awk|jq|cat|cd|uv|pytest|make)\s+(?:-|/|\$|['\"]|[A-Za-z0-9_.-]+)",
        text,
    )
    if command_tail and command_tail.start() >= 16:
        text = text[:command_tail.start()].rstrip(" .:-")

    return _prompt_fragment(text, max_len)


def _shell_inline_comment_summary(command, max_len=240):
    """Return a human note from an inline shell comment, if one is present."""
    if not isinstance(command, str) or "#" not in command:
        return ""
    for comment in _iter_shell_comment_texts(command):
        note = _clean_shell_inline_comment_note(comment)
        if note:
            return _prompt_fragment("Shell command: " + note, max_len)
    return ""


def _extract_shell_heredoc(command):
    """Return {head, body, tag} for a simple shell heredoc command."""
    if not isinstance(command, str) or "<<" not in command:
        return None
    text = _redacted_shell_command_text(command, max_len=12000)
    m = re.search(
        r"<<-?\s*(?P<quote>['\"]?)(?P<tag>[A-Za-z_][A-Za-z0-9_.-]*)(?P=quote)",
        text,
    )
    if not m:
        return None

    head = text[:m.start()].strip()
    rest = text[m.end():]
    if rest.startswith("\n"):
        rest = rest[1:]
    elif rest.startswith("\r\n"):
        rest = rest[2:]
    else:
        # The live sidecar stores older commands as whitespace-collapsed
        # previews. Treat whatever follows the marker as the body so we can
        # still derive a useful label.
        rest = rest.strip()

    tag = m.group("tag")
    closing = re.search(r"(?m)^[ \t]*" + re.escape(tag) + r"[ \t]*$", rest)
    body = rest[:closing.start()] if closing else rest
    body = re.sub(r"\s+" + re.escape(tag) + r"\s*$", "", body).strip()
    if not body:
        return None
    return {"head": head, "body": body, "tag": tag}


def _shell_script_label(head):
    preview = _shell_command_preview(head, max_len=160)
    try:
        words = shlex.split(preview)
    except ValueError:
        words = preview.split()
    exe = os.path.basename(words[0]) if words else ""
    low = exe.lower()
    if low.startswith("python"):
        return "Python script"
    if low == "node":
        return "Node script"
    if low in ("bun", "deno"):
        return low.capitalize() + " script"
    if low in ("bash", "sh", "zsh"):
        return "Shell script"
    if low == "ruby":
        return "Ruby script"
    if low == "perl":
        return "Perl script"
    if low == "php":
        return "PHP script"
    if low == "osascript":
        return "AppleScript"
    return "Inline script"


def _clean_script_note(note, max_len=120):
    note = _PROMPT_SECRET_RE.sub("[redacted]", re.sub(r"\s+", " ", note or "").strip())
    if not note:
        return ""
    note = re.split(
        r"\s+(?:[A-Za-z_][A-Za-z0-9_]*\s*=|for\s+[A-Za-z_][A-Za-z0-9_]*\s+in\b|"
        r"if\s+|while\s+|with\s+|def\s+|class\s+|print\s*\()",
        note,
        maxsplit=1,
    )[0].strip(" -#")
    return _prompt_fragment(note, max_len)


def _script_comment_notes(body):
    notes = []
    for line in str(body or "").splitlines():
        stripped = line.strip()
        if stripped.startswith("#") and not stripped.startswith("#!"):
            note = _clean_script_note(stripped.lstrip("# "))
            if note:
                notes.append(note)
    if notes:
        return notes
    for m in re.finditer(r"(?:^|\s)#\s*([^#\n]+)", str(body or "")):
        note = _clean_script_note(m.group(1))
        if note:
            notes.append(note)
    return notes


def _script_print_notes(body):
    notes = []
    for m in re.finditer(r"\bprint\s*\(\s*f?(['\"])([^'\"]{1,160})\1", str(body or "")):
        note = _clean_script_note(m.group(2), max_len=100)
        if note:
            notes.append(note)
    return notes


def _script_path_basenames(body):
    out = []
    for m in re.finditer(r"['\"](/[^'\"\n]+)['\"]", str(body or "")):
        base = os.path.basename(m.group(1).rstrip("/"))
        if base and base not in out:
            out.append(base)
    return out


def _script_action_phrases(body):
    text = str(body or "")
    low = text.lower()
    actions = []
    if re.search(r"\bshutil\.copy(?:2|file)?\b|\bcopyfile\s*\(", text):
        actions.append("backs up a file" if re.search(r"\.bak|backup|preedit", low) else "copies a file")
    if re.search(r"\bjson\.loads?\b", text):
        actions.append("reads JSON")
    if re.search(r"\bjson\.dumps?\b", text):
        actions.append("writes JSON")
    if re.search(r"\bsubprocess\.run\b|\bos\.system\b", text):
        actions.append("runs a subprocess")
    deduped = []
    for action in actions:
        if action not in deduped:
            deduped.append(action)
    return deduped


def _shell_heredoc_summary(command, max_len=240):
    here = _extract_shell_heredoc(command)
    if not here:
        return ""
    label = _shell_script_label(here.get("head", ""))
    body = here.get("body", "")
    actions = _script_action_phrases(body)
    comments = _script_comment_notes(body)
    prints = _script_print_notes(body)
    basenames = _script_path_basenames(body)

    parts = []
    parts.extend(actions[:2])
    if comments:
        parts.append(comments[0])
    elif prints:
        parts.append(prints[0])
    elif basenames:
        parts.append("uses " + ", ".join(basenames[:2]))

    detail = "; ".join(p for p in parts if p)
    if basenames and detail and not any(base in detail for base in basenames[:1]):
        detail += " (" + basenames[0] + ")"
    if not detail:
        line_count = len([ln for ln in body.splitlines() if ln.strip()])
        detail = f"{line_count} line" + ("" if line_count == 1 else "s")
    return _prompt_fragment(label + ": " + detail, max_len)


def _shell_command_activity_label(command, max_len=1000):
    """Return a concise label for command activity surfaces."""
    semantic = _shell_heredoc_summary(command, max_len=max_len)
    if semantic:
        return semantic
    semantic = _shell_inline_comment_summary(command, max_len=max_len)
    if semantic:
        return semantic
    return _shell_command_preview(command, max_len=max_len)


def _ask_user_question_payload(tool_input, max_options=3):
    """Return a compact summary of Claude Code's AskUserQuestion input."""
    if not isinstance(tool_input, dict):
        return {}
    questions = tool_input.get("questions")
    if not isinstance(questions, list) or not questions:
        return {}
    first = questions[0]
    if not isinstance(first, dict):
        return {}

    header = _prompt_fragment(first.get("header"), 80)
    question = _prompt_fragment(first.get("question"), 160)
    options = []
    option_details = []
    for opt in first.get("options") or []:
        if isinstance(opt, dict):
            label = opt.get("label")
            description = _prompt_fragment(opt.get("description"), 240)
        else:
            label = opt
            description = ""
        label = _prompt_fragment(label, 80)
        if label:
            options.append(label)
            option_details.append({"label": label, "description": description})

    parts = []
    if header:
        parts.append(header + ":")
    if question:
        parts.append(question)
    if options:
        shown = options[:max_options]
        suffix = "; ..." if len(options) > len(shown) else ""
        parts.append("Options: " + "; ".join(shown) + suffix)
    summary = _prompt_fragment(" ".join(parts), 240)
    if not summary:
        return {}
    return {
        "header": header,
        "question": question,
        "options": options,
        "option_details": option_details,
        "summary": summary,
    }


def _ask_user_question_structured(tool_input):
    """Full per-question header/question/options for rich client rendering.

    AskUserQuestion's `questions` array may carry up to 4 questions in a
    single tool call. Return all of them so the UI can stack each as its
    own block — earlier versions only kept `questions[0]` and silently
    dropped the rest.
    """
    if not isinstance(tool_input, dict):
        return {}
    questions = tool_input.get("questions")
    if not isinstance(questions, list) or not questions:
        return {}
    out_questions = []
    for q in questions:
        if not isinstance(q, dict):
            continue
        header = _prompt_fragment(q.get("header"), 120)
        question = _prompt_fragment(q.get("question"), 400)
        options = []
        for opt in q.get("options") or []:
            if isinstance(opt, dict):
                label = _prompt_fragment(opt.get("label"), 120)
                description = _prompt_fragment(opt.get("description"), 240)
            else:
                label = _prompt_fragment(opt, 120)
                description = ""
            if label:
                options.append({"label": label, "description": description})
        if header or question or options:
            out_questions.append({
                "header": header,
                "question": question,
                "options": options,
            })
    if not out_questions:
        return {}
    return {"questions": out_questions}


def _tool_use_detail(name, tool_input, max_len=200):
    if not isinstance(tool_input, dict):
        tool_input = {}
    if name == "AskUserQuestion":
        return _ask_user_question_payload(tool_input).get("summary", "")
    if name == "Bash":
        return _shell_command_preview(tool_input.get("command", ""), max_len=max_len)
    detail = (
        tool_input.get("file_path")
        or tool_input.get("pattern")
        or tool_input.get("command", "")
        or tool_input.get("query", "")
        or tool_input.get("prompt", "")
        or ""
    )
    return _prompt_fragment(detail, max_len)


def _pending_ask_user_question_for_session(session_id):
    """Return the latest unanswered AskUserQuestion payload for a session."""
    filepath = _resolve_conversation_path(session_id)
    pending = {}
    order = []
    last_assistant_text = ""
    try:
        with open(filepath, "r", encoding="utf-8", errors="replace") as f:
            for raw in f:
                raw = raw.strip()
                if not raw:
                    continue
                try:
                    ev = json.loads(raw)
                except json.JSONDecodeError:
                    continue
                t = ev.get("type", "")
                msg = _safe_parse_message(ev.get("message", {}))
                content = msg.get("content")
                if t == "assistant" and isinstance(content, list):
                    local_text = []
                    saw_question = False
                    for block in content:
                        if not isinstance(block, dict):
                            continue
                        if block.get("type") == "text":
                            text = _prompt_fragment(block.get("text"), 1200)
                            if text:
                                local_text.append(text)
                            continue
                        if block.get("type") != "tool_use" or block.get("name") != "AskUserQuestion":
                            continue
                        payload = _ask_user_question_payload(block.get("input") or {})
                        if not payload:
                            continue
                        preamble = "\n\n".join(local_text).strip() or last_assistant_text
                        if preamble:
                            payload["preamble"] = _prompt_fragment(preamble, 1200)
                        tu_id = block.get("id") or f"line:{len(order)}"
                        pending[tu_id] = payload
                        order.append(tu_id)
                        saw_question = True
                    assistant_text = "\n\n".join(local_text).strip()
                    if assistant_text and not saw_question:
                        last_assistant_text = assistant_text
                    elif saw_question:
                        last_assistant_text = ""
                elif t == "user" and pending:
                    if isinstance(content, list):
                        saw_tool_result = False
                        for item in content:
                            if not isinstance(item, dict) or item.get("type") != "tool_result":
                                continue
                            saw_tool_result = True
                            tu_id = item.get("tool_use_id")
                            if tu_id in pending:
                                pending.pop(tu_id, None)
                        if saw_tool_result:
                            continue
                    # A plain follow-up from the user answers or supersedes
                    # the visible prompt, so do not leave stale questions up.
                    pending.clear()
                    last_assistant_text = ""
                elif t == "user":
                    last_assistant_text = ""
    except FileNotFoundError:
        return None

    for tu_id in reversed(order):
        payload = pending.get(tu_id)
        if payload:
            return payload
    return None


def _latest_ask_user_question_payload_for_session(session_id, header="", question=""):
    """Return the latest matching AskUserQuestion payload, answered or not."""
    filepath = _resolve_conversation_path(session_id)
    header = _prompt_fragment(header, 120)
    question = _prompt_fragment(question, 400)
    latest = None
    last_assistant_text = ""
    try:
        with open(filepath, "r", encoding="utf-8", errors="replace") as f:
            for raw in f:
                raw = raw.strip()
                if not raw:
                    continue
                try:
                    ev = json.loads(raw)
                except json.JSONDecodeError:
                    continue
                t = ev.get("type", "")
                if t == "user":
                    last_assistant_text = ""
                if t != "assistant":
                    continue
                msg = _safe_parse_message(ev.get("message", {}))
                content = msg.get("content")
                if not isinstance(content, list):
                    continue
                local_text = []
                saw_question = False
                for block in content:
                    if not isinstance(block, dict):
                        continue
                    if block.get("type") == "text":
                        text = _prompt_fragment(block.get("text"), 1200)
                        if text:
                            local_text.append(text)
                        continue
                    if block.get("type") != "tool_use" or block.get("name") != "AskUserQuestion":
                        continue
                    payload = _ask_user_question_payload(block.get("input") or {})
                    if not payload:
                        continue
                    if header and payload.get("header") != header:
                        continue
                    if question and payload.get("question") != question:
                        continue
                    preamble = "\n\n".join(local_text).strip() or last_assistant_text
                    if preamble:
                        payload["preamble"] = _prompt_fragment(preamble, 1200)
                    latest = payload
                    saw_question = True
                assistant_text = "\n\n".join(local_text).strip()
                if assistant_text and not saw_question:
                    last_assistant_text = assistant_text
                elif saw_question:
                    last_assistant_text = ""
    except FileNotFoundError:
        return None
    return latest


def _extract_files_from_conversation(conversation_id):
    """Walk the JSONL once and return a grouped, de-duped, capped
    payload of file-like artifacts mentioned anywhere in the
    conversation — tool_use inputs, assistant/user text, tool_results.
    Categorization is by extension whitelist (FILE_CATEGORIES);
    everything else (code, scripts, unknown extensions) is dropped.
    Returns {"count": int, "truncated": bool, "groups": {cat: [row…]}}.

    Cheap to call: single linear pass, no I/O beyond the JSONL read.
    """
    if _is_gemini_session(conversation_id):
        return _extract_files_from_gemini_conversation(conversation_id)
    if _is_codex_session(conversation_id):
        return _extract_files_from_codex_conversation(conversation_id)
    if _is_cursor_session(conversation_id):
        return _extract_files_from_cursor_conversation(conversation_id)
    if _is_antigravity_session(conversation_id):
        return _extract_files_from_antigravity_conversation(conversation_id)

    filepath = _resolve_conversation_path(conversation_id)
    seen = {}  # target -> {label, target, kind, category, first_line}
    line_num = 0
    truncated = False

    def consider(target, kind, line):
        nonlocal truncated
        if not target or target in seen:
            return
        category = _categorize_file_target(target)
        if not category:
            return
        if len(seen) >= _FFC_MAX_ENTRIES:
            truncated = True
            return
        # Label: basename for paths, URL last-path-segment (or host) for URLs.
        if kind == "url":
            try:
                parsed = urllib.parse.urlsplit(target)
                tail = parsed.path.rstrip("/").rsplit("/", 1)[-1]
                label = tail or parsed.netloc or target
            except ValueError:
                label = target
        else:
            label = os.path.basename(target) or target
        seen[target] = {
            "label": label,
            "target": target,
            "kind": kind,
            "category": category,
            "first_line": line,
        }

    try:
        with open(filepath, "r") as f:
            for line in f:
                line_num += 1
                line = line.strip()
                if not line:
                    continue
                try:
                    ev = json.loads(line)
                except json.JSONDecodeError:
                    continue

                msg = ev.get("message")
                if not isinstance(msg, dict):
                    continue
                content = msg.get("content")
                if isinstance(content, str):
                    for target, kind in _ffc_iter_targets(content):
                        consider(target, kind, line_num)
                    continue
                if not isinstance(content, list):
                    continue

                for block in content:
                    if not isinstance(block, dict):
                        continue
                    btype = block.get("type")
                    if btype == "text":
                        for target, kind in _ffc_iter_targets(block.get("text", "")):
                            consider(target, kind, line_num)
                    elif btype == "tool_use":
                        # Direct fields first (so file_path with an exotic
                        # character the path-regex misses still lands).
                        inp = block.get("input")
                        if isinstance(inp, dict):
                            for fld in ("file_path", "notebook_path", "path"):
                                v = inp.get(fld)
                                if isinstance(v, str) and v.startswith("/"):
                                    consider(v, "path", line_num)
                        # Then deep scan every nested string.
                        for s in _ffc_flatten_strings(inp):
                            for target, kind in _ffc_iter_targets(s):
                                consider(target, kind, line_num)
                    elif btype == "tool_result":
                        rc = block.get("content")
                        texts = []
                        if isinstance(rc, str):
                            texts.append(rc)
                        elif isinstance(rc, list):
                            for sub in rc:
                                if isinstance(sub, dict) and sub.get("type") == "text":
                                    texts.append(sub.get("text", ""))
                        for t in texts:
                            for target, kind in _ffc_iter_targets(t):
                                consider(target, kind, line_num)
    except FileNotFoundError:
        return {"count": 0, "truncated": False, "groups": {}}

    # Group + sort by first_line ascending within each category.
    groups = {}
    for row in seen.values():
        cat = row["category"]
        groups.setdefault(cat, []).append(row)
    for rows in groups.values():
        rows.sort(key=lambda r: r["first_line"])

    return {"count": len(seen), "truncated": truncated, "groups": groups}


def _extract_files_from_codex_conversation(thread_id):
    path = _resolve_codex_rollout_path(thread_id)
    if not path:
        return {"count": 0, "truncated": False, "groups": {}}
    seen = {}
    truncated = False

    def consider(target, kind, line):
        nonlocal truncated
        if not target or target in seen:
            return
        category = _categorize_file_target(target)
        if not category:
            return
        if len(seen) >= _FFC_MAX_ENTRIES:
            truncated = True
            return
        if kind == "url":
            try:
                parsed = urllib.parse.urlsplit(target)
                tail = parsed.path.rstrip("/").rsplit("/", 1)[-1]
                label = tail or parsed.netloc or target
            except ValueError:
                label = target
        else:
            label = os.path.basename(target) or target
        seen[target] = {
            "label": label,
            "target": target,
            "kind": kind,
            "category": category,
            "first_line": line,
        }

    def consider_text(text, line):
        if not isinstance(text, str) or not text:
            return
        for target, kind in _ffc_iter_targets(text):
            consider(target, kind, line)

    line_num = 0
    try:
        with open(path, "r", encoding="utf-8", errors="replace") as f:
            for line in f:
                line_num += 1
                line = line.strip()
                if not line:
                    continue
                try:
                    ev = json.loads(line)
                except json.JSONDecodeError:
                    continue
                payload = ev.get("payload") if isinstance(ev.get("payload"), dict) else {}
                ptype = payload.get("type")
                if ev.get("type") == "event_msg":
                    consider_text(payload.get("message"), line_num)
                    consider_text(payload.get("last_agent_message"), line_num)
                elif ev.get("type") == "response_item":
                    if ptype == "function_call":
                        args = _codex_args(payload.get("arguments"))
                        for fld in ("path", "file_path", "filename"):
                            val = args.get(fld) if isinstance(args, dict) else None
                            if isinstance(val, str) and val.startswith("/"):
                                consider(val, "path", line_num)
                        for raw in _ffc_flatten_strings(args):
                            consider_text(raw, line_num)
                    elif ptype == "function_call_output":
                        consider_text(payload.get("output"), line_num)
    except OSError:
        pass

    groups = {}
    for row in seen.values():
        groups.setdefault(row["category"], []).append(row)
    for rows in groups.values():
        rows.sort(key=lambda r: r["first_line"])
    return {"count": len(seen), "truncated": truncated, "groups": groups}


def _extract_files_from_gemini_conversation(session_id):
    """Gemini version of the extractor. Operates on a single JSON object
    rather than a line-by-line JSONL."""
    path = _resolve_gemini_chat_path(session_id)
    data = _load_gemini_chat(path) if path else None
    if not data:
        return {"count": 0, "truncated": False, "groups": {}}

    seen = {}
    truncated = False

    def consider(target, kind, idx):
        nonlocal truncated
        if not target or target in seen:
            return
        category = _categorize_file_target(target)
        if not category:
            return
        if len(seen) >= _FFC_MAX_ENTRIES:
            truncated = True
            return
        if kind == "url":
            try:
                parsed = urllib.parse.urlsplit(target)
                tail = parsed.path.rstrip("/").rsplit("/", 1)[-1]
                label = tail or parsed.netloc or target
            except ValueError:
                label = target
        else:
            label = os.path.basename(target) or target
        seen[target] = {
            "label": label,
            "target": target,
            "kind": kind,
            "category": category,
            "first_line": idx + 1,
        }

    messages = data.get("messages") or []
    for idx, msg in enumerate(messages):
        if not isinstance(msg, dict):
            continue

        # Surface text (user/assistant)
        text = _gemini_message_text(msg)
        if text:
            for target, kind in _ffc_iter_targets(text):
                consider(target, kind, idx)

        # Tool calls and results
        for call in msg.get("toolCalls") or []:
            if not isinstance(call, dict):
                continue
            # Scan arguments
            for s in _ffc_flatten_strings(call.get("args")):
                for target, kind in _ffc_iter_targets(s):
                    consider(target, kind, idx)
            # Scan results
            output = _gemini_tool_output(call)
            if output:
                for target, kind in _ffc_iter_targets(output):
                    consider(target, kind, idx)

    # Group + sort by first_line ascending within each category.
    groups = {}
    for row in seen.values():
        cat = row["category"]
        groups.setdefault(cat, []).append(row)
    for rows in groups.values():
        rows.sort(key=lambda r: r["first_line"])

    return {"count": len(seen), "truncated": truncated, "groups": groups}


def _parse_conversation_event(ev, line_num):
    """Parse a single conversation JSONL event."""
    ev_type = ev.get("type", "")
    ts = ev.get("timestamp", "") or ""

    # Skip non-message types
    if ev_type in ("file-history-snapshot", "progress"):
        return None

    if ev_type == "system":
        if ev.get("subtype") == "compact_boundary":
            meta = ev.get("compactMetadata")
            if not isinstance(meta, dict):
                meta = {}
            return {
                "line": line_num,
                "ts": ts,
                "type": "system",
                "subtype": "compact_boundary",
                "session": ev.get("sessionId", ""),
                "compact": {
                    "trigger": meta.get("trigger") or "",
                    "pre_tokens": _codex_int(meta.get("preTokens")),
                    "post_tokens": _codex_int(meta.get("postTokens")),
                    "duration_ms": _codex_int(meta.get("durationMs")),
                },
            }
        if ev.get("subtype") == "local_command":
            content = ev.get("content", "")
            if content.startswith("<local-command-stdout>"):
                m = re.search(r"<local-command-stdout>(.*?)</local-command-stdout>", content, re.DOTALL)
                text = m.group(1).strip() if m else content.strip()
                return {
                    "line": line_num,
                    "ts": ts,
                    "type": "assistant",
                    "message_id": "local-cmd-out-" + ev.get("uuid", ""),
                    "blocks": [{"kind": "text", "text": "🖥️ " + text}]
                }
            elif content.startswith("<local-command-stderr>"):
                m = re.search(r"<local-command-stderr>(.*?)</local-command-stderr>", content, re.DOTALL)
                text = m.group(1).strip() if m else content.strip()
                return {
                    "line": line_num,
                    "ts": ts,
                    "type": "assistant",
                    "message_id": "local-cmd-err-" + ev.get("uuid", ""),
                    "blocks": [{"kind": "text", "text": "⚠️ " + text}]
                }
            else:
                return {
                    "line": line_num,
                    "ts": ts,
                    "type": "user_text",
                    "text": content,
                    "images": []
                }
        return None

    if ev_type == "user":
        if ev.get("isMeta"):
            return None
        msg = _safe_parse_message(ev.get("message", {}))
        content = msg.get("content", "")
        text = _extract_text_from_content(content)
        if _is_transcript_control_text(text):
            # Slash-command invocations look like
            #   <command-message>dev</command-message>\n<command-name>/dev</command-name>
            # Without surfacing them the transcript pane looks like the agent
            # just started running tools out of nowhere — the user has no
            # record of what they typed. Show the command name as a
            # synthetic user_text turn so the pane mirrors what the user did.
            head = (text or "").lstrip()
            if head.startswith("<command-name>") or head.startswith("<command-message>"):
                m = re.search(r"<command-name>([^<]+)</command-name>", head)
                cmd_name = m.group(1).strip() if m else ""
                if not cmd_name:
                    m2 = re.search(r"<command-message>([^<]+)</command-message>", head)
                    if m2:
                        raw = m2.group(1).strip()
                        cmd_name = raw if raw.startswith("/") else ("/" + raw)
                if cmd_name:
                    return {"line": line_num, "ts": ts, "type": "user_text", "text": cmd_name, "images": []}
            return None
        images = _extract_images_from_content(content, line=line_num)
        if text or images:
            # Preview placeholder "[image]" shouldn't leak into the rendered message.
            display_text = "" if (text == "[image]" and images) else text
            return {"line": line_num, "ts": ts, "type": "user_text", "text": display_text, "images": images}
        # Check for tool results in content list. Capture the result text so
        # the UI can render it inline under the matching tool_call (Claude
        # Desktop-style "Bash $ npm test \n <stdout>" preview).
        if isinstance(content, list):
            for item in content:
                if isinstance(item, dict) and item.get("type") == "tool_result":
                    result_content = item.get("content")
                    result_text = ""
                    if isinstance(result_content, str):
                        result_text = result_content
                    elif isinstance(result_content, list):
                        # tool_result content can be a list of text/image blocks
                        parts = []
                        for sub in result_content:
                            if isinstance(sub, dict) and sub.get("type") == "text":
                                parts.append(sub.get("text", ""))
                        result_text = "\n".join(p for p in parts if p)
                    # Truncate aggressively — the UI is for glancing, not deep inspection.
                    if len(result_text) > 800:
                        result_text = result_text[:800] + "\n…"
                    return {
                        "line": line_num, "ts": ts, "type": "tool_result",
                        "text": result_text,
                        "tool_use_id": item.get("tool_use_id", ""),
                        "is_error": bool(item.get("is_error")),
                    }
        return None

    queued = _extract_queued_command_prompt(ev)
    if queued:
        return {
            "line": line_num,
            "ts": ts,
            "type": "user_text",
            "text": queued.get("text", ""),
            "images": queued.get("images", []),
        }

    if ev_type == "assistant":
        msg = _safe_parse_message(ev.get("message", {}))
        blocks = []
        for block in msg.get("content", []):
            if not isinstance(block, dict):
                continue
            btype = block.get("type", "")
            if btype == "tool_use":
                inp = block.get("input", {})
                name = block.get("name", "?")
                raw_command = inp.get("command", "") if isinstance(inp, dict) and name == "Bash" else ""
                if raw_command:
                    detail = _shell_command_activity_label(raw_command, max_len=1200)
                else:
                    detail_max = 1200 if name == "Bash" else 240
                    detail = _tool_use_detail(name, inp, max_len=detail_max)
                tool_block = {
                    "kind": "tool_use",
                    "name": name,
                    "detail": detail,
                    "id": block.get("id", ""),
                }
                if raw_command:
                    command_text = _redacted_shell_command_text(raw_command, max_len=12000)
                    if command_text and (
                        "\n" in command_text
                        or len(command_text) > 160
                        or re.sub(r"\s+", " ", command_text).strip() != detail
                    ):
                        tool_block["command"] = command_text
                        here = _extract_shell_heredoc(raw_command)
                        tool_block["command_kind"] = _shell_script_label(here.get("head", "")) if here else "Shell command"
                if name == "AskUserQuestion":
                    ask = _ask_user_question_structured(inp)
                    if ask:
                        tool_block["question"] = ask
                blocks.append(tool_block)
            elif btype == "text":
                txt = block.get("text", "").strip()
                if txt:
                    blocks.append({"kind": "text", "text": txt})
            elif btype == "thinking":
                thinking = block.get("thinking", "").strip()
                # Extended-thinking blocks are often signature-only in the
                # persisted transcript: the reasoning text is stripped and only
                # a cryptographic signature survives. Emit a marker block in
                # that case so the UI can still show "thinking happened this
                # turn" rather than silently dropping it.
                signature = (block.get("signature") or "").strip()
                if thinking:
                    # Was a 300-char preview — too short now that the thinking
                    # block is shown (collapsed/expandable) in the UI. Send a
                    # generous slice so the expanded view is readable without
                    # shipping unbounded reasoning on every turn.
                    preview = thinking[:4000] + ("..." if len(thinking) > 4000 else "")
                    blocks.append({"kind": "thinking", "text": preview, "signature_only": False})
                elif signature:
                    blocks.append({"kind": "thinking", "text": "", "signature_only": True})

        if blocks:
            out_ev = {
                "line": line_num,
                "ts": ts,
                "type": "assistant",
                "message_id": msg.get("id", ""),
                "blocks": blocks,
            }
            # Per-turn token usage: surface a "X in | Y out" chip at the end of
            # every assistant turn (interactive transcripts have no `result`
            # event, so without this they show no token count at all). tokens_in
            # is the full input processed this turn (uncached + cache read +
            # cache creation) so it reflects the real context size.
            usage = msg.get("usage")
            if isinstance(usage, dict):
                tin = (int(usage.get("input_tokens") or 0)
                       + int(usage.get("cache_read_input_tokens") or 0)
                       + int(usage.get("cache_creation_input_tokens") or 0))
                tout = int(usage.get("output_tokens") or 0)
                if tin or tout:
                    out_ev["tokens_in"] = tin
                    out_ev["tokens_out"] = tout
            return out_ev

    if ev_type == "result":
        cost = ev.get("cost_usd", "?")
        dur = ev.get("duration_ms", "?")
        r = ev.get("result")
        if isinstance(r, dict):
            cost = r.get("cost_usd", cost)
            dur = r.get("duration_ms", dur)
        out = {
            "line": line_num,
            "ts": ts,
            "type": "result",
            "cost_usd": cost,
            "duration_ms": dur,
        }
        # Pass through the error signal so the UI can say *why* a turn stopped
        # (usage/quota limit, max turns, API error) instead of a blanket
        # "Done". The result text on an error carries the reason; clip it.
        subtype = ev.get("subtype")
        if subtype:
            out["subtype"] = subtype
        if ev.get("is_error"):
            out["is_error"] = True
            err = r if isinstance(r, str) else ev.get("result")
            if isinstance(err, str) and err.strip():
                out["error"] = err.strip()[:400]
        return out

    return None


# ---------------------------------------------------------------------------
# Spawned headless Claude sessions
# ---------------------------------------------------------------------------

def _slugify(text, max_len=40):
    """Turn a prompt into a filesystem-safe slug."""
    slug = re.sub(r"[^a-z0-9]+", "-", text.lower()).strip("-")
    return slug[:max_len].rstrip("-")


def _create_worktree_for_spawn(source_cwd, slug):
    """Create `<source-parent>/<source-name>-wt/<slug>/` as a git worktree
    on a fresh `feat/<slug>` branch off `source_cwd`'s current HEAD, and
    return its absolute path.

    Layout: all worktrees of a repo nest under a single sibling directory
    `<repo>-wt/` so they don't sprawl across the parent. Still sibling to
    the source (not nested inside the repo) so editors / `find` calls
    don't recurse into worktrees from inside the repo. Read paths
    discover worktrees in BOTH the legacy `<repo>-wt-<slug>` layout and
    the new `<repo>-wt/<slug>` layout because the project-slug encoder
    collapses `/` and `-` to the same character.

    Returns (path, branch) on success, raises RuntimeError on any failure
    (not-a-repo, dirty index, branch collision, etc.) so the caller can
    surface a clean error to the spawn API. Caller is responsible for
    deciding whether to fall back to no-worktree mode or fail the spawn.
    """
    p = Path(source_cwd).expanduser().resolve()
    if not p.is_dir():
        raise RuntimeError(f"source cwd does not exist: {p}")
    # Resolve to the toplevel so worktree creation works whether the
    # caller pointed at the repo root or a subdir within it.
    try:
        r = subprocess.run(
            ["git", "-C", str(p), "rev-parse", "--show-toplevel"],
            capture_output=True, text=True, timeout=3, check=True,
        )
    except (subprocess.SubprocessError, OSError) as e:
        raise RuntimeError(f"source cwd is not a git repo: {e}")
    toplevel = Path(r.stdout.strip())
    parent = toplevel.parent
    base_name = toplevel.name
    # Pick the first non-existing variant of `<base>-wt/<slug>[-N]/`.
    wt_root = parent / f"{base_name}-wt"
    try:
        wt_root.mkdir(exist_ok=True)
    except OSError as e:
        raise RuntimeError(f"could not create worktree parent {wt_root}: {e}")
    candidate = wt_root / slug
    suffix = 2
    while candidate.exists():
        candidate = wt_root / f"{slug}-{suffix}"
        suffix += 1
    branch = f"feat/{slug}"
    # If the branch already exists, append the same numeric suffix the
    # path got so they stay aligned.
    branch_check = subprocess.run(
        ["git", "-C", str(toplevel), "rev-parse", "--verify", branch],
        capture_output=True, text=True, timeout=3,
    )
    if branch_check.returncode == 0:
        # Branch exists — pick a fresh one matching the path suffix.
        branch_suffix = 2
        while True:
            cand_branch = f"feat/{slug}-{branch_suffix}"
            check = subprocess.run(
                ["git", "-C", str(toplevel), "rev-parse", "--verify", cand_branch],
                capture_output=True, text=True, timeout=3,
            )
            if check.returncode != 0:
                branch = cand_branch
                break
            branch_suffix += 1
    add = subprocess.run(
        ["git", "-C", str(toplevel), "worktree", "add", str(candidate), "-b", branch],
        capture_output=True, text=True, timeout=15,
    )
    if add.returncode != 0:
        raise RuntimeError(f"git worktree add failed: {add.stderr.strip() or add.stdout.strip()}")
    return str(candidate), branch


def _run_worktree_init_hook(worktree_path, parent_repo, session_name, log_fh):
    """If `<worktree_path>/.ccc/worktree-init` exists and is executable,
    run it once before launching the session in that worktree.

    Tolerant by design: missing hook is silently skipped; a failing hook
    appends its stderr/stdout to the session's spawn log but never blocks
    the spawn — the session can still start in the worktree, and the user
    sees the failure in the log. See `.ccc/worktree-init.example` for the
    contract (env vars + idempotency expectations).
    """
    hook = Path(worktree_path) / ".ccc" / "worktree-init"
    try:
        if not (hook.is_file() and os.access(str(hook), os.X_OK)):
            return
    except OSError:
        return
    env = os.environ.copy()
    env["CCC_WORKTREE_PATH"] = str(worktree_path)
    env["CCC_PARENT_REPO"] = str(parent_repo or "")
    env["CCC_SESSION_NAME"] = session_name or ""
    log_fh.write(f"[worktree-init] running {hook}\n")
    log_fh.flush()
    try:
        result = subprocess.run(
            [str(hook)],
            cwd=str(worktree_path),
            env=env,
            capture_output=True, text=True, timeout=120,
        )
    except (subprocess.SubprocessError, OSError) as e:
        log_fh.write(f"[worktree-init] failed to invoke: {e}\n")
        log_fh.flush()
        return
    if result.stdout:
        log_fh.write(result.stdout)
        if not result.stdout.endswith("\n"):
            log_fh.write("\n")
    if result.stderr:
        log_fh.write(result.stderr)
        if not result.stderr.endswith("\n"):
            log_fh.write("\n")
    log_fh.write(f"[worktree-init] exit {result.returncode}\n")
    log_fh.flush()


# ---------------------------------------------------------------------------
# Codex CLI binary resolution
# ---------------------------------------------------------------------------
# Tested against codex-cli 0.125.0-alpha.3, the version currently shipping
# inside /Applications/Codex.app.

CODEX_APP_BUNDLE_PATH = "/Applications/Codex.app/Contents/Resources/codex"
CODEX_STATE_DB = Path.home() / ".codex" / "state_5.sqlite"
CODEX_SESSIONS_ROOT = Path.home() / ".codex" / "sessions"
_CODEX_META_VERSION = 3
_CODEX_APP_SERVER_LOCK = threading.Condition()
_CODEX_APP_SERVER_PROC = None
_CODEX_APP_SERVER_READER = None
_CODEX_APP_SERVER_INITIALIZED = False
_CODEX_APP_SERVER_INITIALIZING = False
_CODEX_APP_SERVER_NEXT_ID = 1
_CODEX_APP_SERVER_RESPONSES = {}


def _resolve_codex_bin():
    """Locate a usable Codex CLI binary.

    Priority order:
      1. $CCC_CODEX_BIN (env override) — if set and executable.
      2. `shutil.which("codex")` — picks up Homebrew / Cargo / npm-global.
      3. /Applications/Codex.app/Contents/Resources/codex (macOS Codex
         desktop app's bundled CLI).

    Returns a dict so the caller and the availability endpoint can share
    one shape:
      {available: True,  bin: "<abs path>", source: "env|path|bundle"}
      {available: False, reason: "<human readable>", bin: None}
    """
    env_bin = os.environ.get("CCC_CODEX_BIN")
    if env_bin:
        if os.path.isfile(env_bin) and os.access(env_bin, os.X_OK):
            return {"available": True, "bin": env_bin, "source": "env"}
        return {
            "available": False,
            "bin": None,
            "code": "codex_unavailable",
            "reason": f"CCC_CODEX_BIN is set to {env_bin!r} but it isn't an executable file",
        }
    which_bin = shutil.which("codex")
    if which_bin:
        return {"available": True, "bin": which_bin, "source": "path"}
    if os.path.isfile(CODEX_APP_BUNDLE_PATH) and os.access(CODEX_APP_BUNDLE_PATH, os.X_OK):
        return {"available": True, "bin": CODEX_APP_BUNDLE_PATH, "source": "bundle"}
    return {
        "available": False,
        "bin": None,
        "code": "codex_unavailable",
        "reason": (
            "Codex CLI not found. Install Codex.app, "
            "`npm i -g @openai/codex`, or set CCC_CODEX_BIN."
        ),
    }


def _codex_app_server_reader(proc):
    """Collect JSON-RPC responses from the long-lived Codex app-server."""
    global _CODEX_APP_SERVER_PROC, _CODEX_APP_SERVER_INITIALIZED, _CODEX_APP_SERVER_INITIALIZING
    try:
        for line in proc.stdout:
            line = (line or "").strip()
            if not line:
                continue
            try:
                payload = json.loads(line)
            except json.JSONDecodeError:
                continue
            if "id" not in payload:
                continue
            with _CODEX_APP_SERVER_LOCK:
                _CODEX_APP_SERVER_RESPONSES[payload.get("id")] = payload
                _CODEX_APP_SERVER_LOCK.notify_all()
    finally:
        with _CODEX_APP_SERVER_LOCK:
            if _CODEX_APP_SERVER_PROC is proc:
                _CODEX_APP_SERVER_PROC = None
                _CODEX_APP_SERVER_INITIALIZED = False
                _CODEX_APP_SERVER_INITIALIZING = False
            _CODEX_APP_SERVER_LOCK.notify_all()


def _codex_app_server_request_to_proc(proc, method, params=None, timeout=20):
    """Send one JSON-RPC request to an already-started Codex app-server."""
    with _CODEX_APP_SERVER_LOCK:
        global _CODEX_APP_SERVER_NEXT_ID
        req_id = _CODEX_APP_SERVER_NEXT_ID
        _CODEX_APP_SERVER_NEXT_ID += 1
        try:
            proc.stdin.write(json.dumps({
                "jsonrpc": "2.0",
                "id": req_id,
                "method": method,
                "params": params or {},
            }) + "\n")
            proc.stdin.flush()
        except (BrokenPipeError, OSError) as e:
            return {"ok": False, "error": str(e), "fallback": "exec"}

        deadline = time.time() + timeout
        while time.time() < deadline:
            response = _CODEX_APP_SERVER_RESPONSES.pop(req_id, None)
            if response is not None:
                return response
            remaining = max(0.05, deadline - time.time())
            _CODEX_APP_SERVER_LOCK.wait(min(0.5, remaining))
        return {
            "ok": False,
            "error": f"Codex app-server request timed out: {method}",
            "fallback": "exec",
        }


def _codex_context_window_args():
    """Opt every Codex invocation into the model's full 1M context window.

    gpt-5.x default to a 272K working window but advertise a 1M max in their
    model metadata ("context_window": 272000, "max_context_window": 1000000),
    so raising `model_context_window` to 1M is supported (within max), not a
    foot-gun. Passed as a global `-c` override on spawn, resume, and the
    app-server so the window is consistent across a session's whole life.
    Set CCC_CODEX_CONTEXT_1M=0 to fall back to the model default.
    """
    if os.environ.get("CCC_CODEX_CONTEXT_1M", "1").lower() in ("0", "false", "no"):
        return []
    return ["-c", "model_context_window=1000000"]


def _codex_app_server_request(method, params=None, timeout=20):
    """Send one JSON-RPC request to Codex app-server.

    The app-server is the only local Codex interface that can append input to
    a loaded thread; `codex exec resume` can only start a one-shot process.
    """
    proc = _ensure_codex_app_server()
    if proc is None:
        return {
            "ok": False,
            "error": "Codex app-server is unavailable",
            "fallback": "exec",
        }
    return _codex_app_server_request_to_proc(proc, method, params=params, timeout=timeout)


def _ensure_codex_app_server():
    """Start and initialize a persistent Codex app-server if needed."""
    global _CODEX_APP_SERVER_PROC, _CODEX_APP_SERVER_READER
    global _CODEX_APP_SERVER_INITIALIZED, _CODEX_APP_SERVER_INITIALIZING
    with _CODEX_APP_SERVER_LOCK:
        while _CODEX_APP_SERVER_INITIALIZING:
            _CODEX_APP_SERVER_LOCK.wait(0.5)
            proc = _CODEX_APP_SERVER_PROC
            if proc is not None and proc.poll() is None and _CODEX_APP_SERVER_INITIALIZED:
                return proc
            if not _CODEX_APP_SERVER_INITIALIZING:
                break
        proc = _CODEX_APP_SERVER_PROC
        if proc is not None and proc.poll() is None and _CODEX_APP_SERVER_INITIALIZED:
            return proc
        if proc is not None and proc.poll() is None:
            try:
                proc.terminate()
            except OSError:
                pass
        _CODEX_APP_SERVER_PROC = None
        _CODEX_APP_SERVER_INITIALIZED = False
        _CODEX_APP_SERVER_INITIALIZING = False

        resolved = _resolve_codex_bin()
        if not resolved.get("available"):
            return None
        try:
            proc = subprocess.Popen(
                [resolved["bin"], *_codex_context_window_args(), "app-server", "--listen", "stdio://"],
                stdin=subprocess.PIPE,
                stdout=subprocess.PIPE,
                stderr=subprocess.DEVNULL,
                text=True,
                bufsize=1,
                start_new_session=True,
            )
        except (FileNotFoundError, OSError):
            return None
        _CODEX_APP_SERVER_PROC = proc
        _CODEX_APP_SERVER_INITIALIZING = True
        _CODEX_APP_SERVER_READER = threading.Thread(
            target=_codex_app_server_reader,
            args=(proc,),
            daemon=True,
            name="codex-app-server-reader",
        )
        _CODEX_APP_SERVER_READER.start()

    init = _codex_app_server_request_to_proc(
        proc,
        "initialize",
        {
            "clientInfo": {
                "name": "claude-command-center",
                "title": "Claude Command Center",
                "version": __version__,
            },
            "capabilities": {"experimentalApi": True},
        },
        timeout=10,
    )
    if init.get("result") is not None:
        with _CODEX_APP_SERVER_LOCK:
            if _CODEX_APP_SERVER_PROC is proc and proc.poll() is None:
                _CODEX_APP_SERVER_INITIALIZED = True
                _CODEX_APP_SERVER_INITIALIZING = False
                _CODEX_APP_SERVER_LOCK.notify_all()
                return proc
    try:
        proc.terminate()
    except OSError:
        pass
    with _CODEX_APP_SERVER_LOCK:
        if _CODEX_APP_SERVER_PROC is proc:
            _CODEX_APP_SERVER_PROC = None
            _CODEX_APP_SERVER_INITIALIZED = False
            _CODEX_APP_SERVER_INITIALIZING = False
        _CODEX_APP_SERVER_LOCK.notify_all()
    return None


def _codex_app_server_shutdown():
    """Terminate the CCC-owned Codex app-server process on server exit."""
    global _CODEX_APP_SERVER_PROC, _CODEX_APP_SERVER_INITIALIZED, _CODEX_APP_SERVER_INITIALIZING
    with _CODEX_APP_SERVER_LOCK:
        proc = _CODEX_APP_SERVER_PROC
        _CODEX_APP_SERVER_PROC = None
        _CODEX_APP_SERVER_INITIALIZED = False
        _CODEX_APP_SERVER_INITIALIZING = False
        _CODEX_APP_SERVER_LOCK.notify_all()
    if proc is not None and proc.poll() is None:
        try:
            proc.terminate()
        except OSError:
            pass


def _codex_app_server_is_live():
    """True iff CCC's own Codex app-server subprocess is up and initialized.

    This reflects whether CCC is currently driving Codex via the JSON-RPC
    stdio app-server (the path that can append input to a loaded thread and
    run thread/compact) versus having no live app-server (in which case a
    Codex action would lazily spawn one or fall back to one-shot `codex exec`).
    Read-only: it does NOT start the server (so it stays cheap for polling).
    """
    proc = _CODEX_APP_SERVER_PROC
    return bool(
        proc is not None
        and proc.poll() is None
        and _CODEX_APP_SERVER_INITIALIZED
    )


def _codex_user_input(text, image_paths=None):
    items = [{"type": "text", "text": str(text or "")}]
    for image_path in image_paths or []:
        if image_path:
            items.append({"type": "localImage", "path": str(image_path)})
    return items


def _codex_latest_active_turn(thread):
    turns = (thread or {}).get("turns") or []
    for turn in reversed(turns):
        if isinstance(turn, dict) and turn.get("status") == "inProgress" and turn.get("id"):
            return turn
    return None


def _codex_error_text(response):
    if not isinstance(response, dict):
        return "Codex app-server returned no response"
    err = response.get("error")
    if not isinstance(err, dict):
        return ""
    message = str(err.get("message") or "Codex app-server request failed")
    data = err.get("data")
    if data is not None:
        return f"{message}: {data}"
    return message


def _codex_error_is_not_steerable(response):
    text = _codex_error_text(response)
    return "activeTurnNotSteerable" in text or "not steerable" in text.lower()


def _codex_response_succeeded(response):
    return isinstance(response, dict) and "result" in response and not response.get("error")


def _codex_turn_params(thread_id, text, cwd=None, model=None, image_paths=None):
    params = {
        "threadId": thread_id,
        "input": _codex_user_input(text, image_paths=image_paths),
    }
    if cwd:
        params["cwd"] = cwd
        params["runtimeWorkspaceRoots"] = [cwd]
    if model:
        params["model"] = model
    # Match the existing `codex exec --dangerously-bypass-approvals-and-sandbox`
    # behavior used by CCC-spawned Codex runs.
    params["approvalPolicy"] = "never"
    params["sandboxPolicy"] = {"type": "dangerFullAccess"}
    return params


def _codex_resume_or_steer_via_app_server(
    session_id,
    text,
    cwd=None,
    model=None,
    image_paths=None,
    allow_start=True,
):
    if os.environ.get("CCC_CODEX_APP_SERVER", "1").lower() in ("0", "false", "no"):
        return {"ok": False, "fallback": "exec", "error": "Codex app-server disabled"}
    resume_params = {
        "threadId": session_id,
        "excludeTurns": False,
    }
    if cwd:
        resume_params["cwd"] = cwd
    if model:
        resume_params["model"] = model
    resumed = _codex_app_server_request("thread/resume", resume_params, timeout=20)
    if resumed.get("error"):
        return {"ok": False, "fallback": "exec", "error": _codex_error_text(resumed)}
    thread = ((resumed.get("result") or {}).get("thread") or {})
    active_turn = _codex_latest_active_turn(thread)
    status = (thread.get("status") or {}).get("type")
    if status == "active" and active_turn:
        started = _codex_app_server_request(
            "turn/start",
            {
                "threadId": session_id,
                "input": _codex_user_input(text, image_paths=image_paths),
            },
            timeout=20,
        )
        if _codex_response_succeeded(started):
            turn = ((started.get("result") or {}).get("turn") or {})
            return {
                "ok": True,
                "queued": True,
                "via": "codex-app-queued",
                "turn_id": turn.get("id"),
                "session_id": session_id,
            }
        if _codex_error_is_not_steerable(started):
            return {
                "ok": False,
                "fallback": "queue",
                "error": _codex_error_text(started),
            }
        return {"ok": False, "fallback": "exec", "error": _codex_error_text(started)}
    if status == "active":
        return {
            "ok": False,
            "fallback": "queue",
            "error": "Codex app-server reports an active turn without a steerable turn id",
        }
    if not allow_start:
        return {
            "ok": False,
            "fallback": "queue",
            "error": "Codex CLI resume is still running and app-server did not expose a steerable turn",
        }

    started = _codex_app_server_request(
        "turn/start",
        _codex_turn_params(session_id, text, cwd=cwd, model=model, image_paths=image_paths),
        timeout=20,
    )
    if _codex_response_succeeded(started):
        turn = ((started.get("result") or {}).get("turn") or {})
        return {
            "ok": True,
            "via": "codex-app-turn",
            "turn_id": turn.get("id"),
            "session_id": session_id,
        }
    if _codex_error_is_not_steerable(started):
        return {
            "ok": False,
            "fallback": "queue",
            "error": _codex_error_text(started),
        }
    return {"ok": False, "fallback": "exec", "error": _codex_error_text(started)}


def _codex_steer_via_app_server(session_id, text, cwd=None, model=None, image_paths=None):
    if os.environ.get("CCC_CODEX_APP_SERVER", "1").lower() in ("0", "false", "no"):
        return {
            "ok": False,
            "via": "codex-steer",
            "code": "codex_steer_unavailable",
            "error": "Codex app-server disabled",
        }
    resume_params = {
        "threadId": session_id,
        "excludeTurns": False,
    }
    if cwd:
        resume_params["cwd"] = cwd
    if model:
        resume_params["model"] = model
    resumed = _codex_app_server_request("thread/resume", resume_params, timeout=20)
    if resumed.get("error"):
        return {
            "ok": False,
            "via": "codex-steer",
            "code": "codex_steer_unavailable",
            "error": _codex_error_text(resumed),
        }
    thread = ((resumed.get("result") or {}).get("thread") or {})
    active_turn = _codex_latest_active_turn(thread)
    status = (thread.get("status") or {}).get("type")
    if status != "active" or not active_turn:
        return {
            "ok": False,
            "via": "codex-steer",
            "code": "codex_no_active_turn",
            "error": "No running Codex turn to steer",
        }
    steered = _codex_app_server_request(
        "turn/steer",
        {
            "threadId": session_id,
            "expectedTurnId": active_turn["id"],
            "input": _codex_user_input(text, image_paths=image_paths),
        },
        timeout=20,
    )
    if _codex_response_succeeded(steered):
        return {
            "ok": True,
            "via": "codex-steer",
            "turn_id": (steered["result"] or {}).get("turnId") or active_turn["id"],
            "session_id": session_id,
        }
    return {
        "ok": False,
        "via": "codex-steer",
        "code": "codex_steer_failed",
        "error": _codex_error_text(steered) or "Codex steer failed",
    }


def _backup_codex_rollout_before_compact(session_id):
    """Copy the Codex thread's rollout JSONL to
    ~/.claude/command-center/compact-backups/ before `thread/compact/start`
    rewrites it. Returns the backup path or None on failure. Best-effort.

    Codex compaction is lossy — the app-server replaces the loaded thread's
    history with a compacted summary and rewrites the rollout on disk. Without
    a snapshot the pre-compact transcript is gone permanently. Mirrors the
    Claude `_backup_jsonl_before_compact` pattern and reuses its backup dir.
    """
    try:
        src = _resolve_codex_rollout_path(session_id)
        if not src:
            return None
        src = Path(src)
        if not src.is_file():
            return None
        backup_dir = Path.home() / ".claude" / "command-center" / "compact-backups"
        backup_dir.mkdir(parents=True, exist_ok=True)
        stamp = datetime.now().strftime("%Y%m%dT%H%M%S")
        dest = backup_dir / f"codex-{session_id}-{stamp}.jsonl"
        shutil.copy2(str(src), str(dest))
        # Keep at most 10 backups per thread — older ones rotate out.
        backups = sorted(backup_dir.glob(f"codex-{session_id}-*.jsonl"))
        for stale in backups[:-10]:
            try:
                stale.unlink()
            except OSError:
                pass
        return str(dest)
    except Exception as e:
        print(f"  [compact-backup] codex backup failed for {session_id}: {e}", file=sys.stderr)
        return None


def _codex_compact_via_app_server(session_id, cwd=None, model=None):
    """Compact a Codex thread via the app-server `thread/compact/start` RPC.

    Resumes the thread (loading it into the CCC-owned app-server) and then calls
    `thread/compact/start` with the schema-correct params (`{threadId}`).
    Compaction is lossy, so the caller is expected to have already backed up the
    rollout. Returns a result dict mirroring the other Codex app-server helpers
    (`{ok, via, ...}` / `{ok: False, error, ...}`). Handles "app-server
    unavailable" gracefully.
    """
    sid = (session_id or "").strip()
    if not sid:
        return {"ok": False, "via": "codex-compact", "error": "missing session_id"}
    if os.environ.get("CCC_CODEX_APP_SERVER", "1").lower() in ("0", "false", "no"):
        return {
            "ok": False,
            "via": "codex-compact",
            "code": "codex_compact_unavailable",
            "error": "Codex app-server disabled",
        }
    # The thread must be loaded into this app-server before it can be compacted.
    resume_params = {"threadId": sid, "excludeTurns": False}
    if cwd:
        resume_params["cwd"] = cwd
    if model:
        resume_params["model"] = model
    resumed = _codex_app_server_request("thread/resume", resume_params, timeout=20)
    if resumed.get("error"):
        return {
            "ok": False,
            "via": "codex-compact",
            "code": "codex_compact_unavailable",
            "error": _codex_error_text(resumed),
        }
    if resumed.get("ok") is False and "result" not in resumed:
        # `_codex_app_server_request` short-circuit (unavailable / timeout).
        return {
            "ok": False,
            "via": "codex-compact",
            "code": "codex_compact_unavailable",
            "error": resumed.get("error") or "Codex app-server unavailable",
        }
    compacted = _codex_app_server_request(
        "thread/compact/start", {"threadId": sid}, timeout=60
    )
    if _codex_response_succeeded(compacted):
        return {
            "ok": True,
            "via": "codex-compact",
            "session_id": sid,
        }
    if compacted.get("ok") is False and "result" not in compacted:
        return {
            "ok": False,
            "via": "codex-compact",
            "code": "codex_compact_unavailable",
            "error": compacted.get("error") or "Codex app-server unavailable",
        }
    return {
        "ok": False,
        "via": "codex-compact",
        "code": "codex_compact_failed",
        "error": _codex_error_text(compacted) or "Codex compact failed",
    }


def _codex_state_db_candidates():
    """Existing Codex state DB paths, newest known schema first."""
    base = Path.home() / ".codex"
    candidates = [CODEX_STATE_DB]
    try:
        if base.is_dir():
            for p in sorted(base.glob("state*.sqlite"), key=lambda x: x.name, reverse=True):
                if p not in candidates:
                    candidates.append(p)
    except OSError:
        pass
    return [p for p in candidates if p.is_file()]


def _jsonl_line_ending(line):
    if line.endswith("\r\n"):
        return "\r\n"
    if line.endswith("\n"):
        return "\n"
    return ""


def _mark_codex_rollout_user_visible(thread_id, rollout_path):
    sid = str(thread_id or "").strip()
    if not sid or not rollout_path:
        return False
    try:
        path = Path(rollout_path).expanduser().resolve()
    except (OSError, RuntimeError, ValueError):
        return False
    if not path.is_file():
        return False
    try:
        original_stat = path.stat()
    except OSError:
        return False
    try:
        lines = path.read_text(encoding="utf-8").splitlines(keepends=True)
    except OSError:
        return False

    changed = False
    for idx, line in enumerate(lines):
        text = line.strip()
        if not text:
            continue
        try:
            obj = json.loads(text)
        except json.JSONDecodeError:
            continue
        if obj.get("type") != "session_meta":
            continue
        payload = obj.get("payload")
        if not isinstance(payload, dict):
            return False
        meta_id = str(payload.get("id") or "").strip()
        if meta_id and meta_id != sid:
            return False
        source = payload.get("source")
        thread_source = payload.get("thread_source")
        if source and source not in ("exec", "cli", "vscode"):
            return False
        if thread_source and thread_source != "user":
            return False
        if source != "vscode":
            payload["source"] = "vscode"
            changed = True
        if thread_source != "user":
            payload["thread_source"] = "user"
            changed = True
        if not changed:
            return True
        ending = _jsonl_line_ending(line)
        lines[idx] = json.dumps(obj, ensure_ascii=False, separators=(",", ":")) + ending
        break
    else:
        return False

    try:
        tmp = path.with_name(f"{path.name}.tmp-{os.getpid()}")
        tmp.write_text("".join(lines), encoding="utf-8")
        os.replace(tmp, path)
        os.utime(path, ns=(original_stat.st_atime_ns, original_stat.st_mtime_ns))
    except OSError:
        return False
    return True


def _codex_row_updated_epoch(row):
    if not isinstance(row, dict):
        return None
    for key, scale in (("updated_at_ms", 1000.0), ("updated_at", 1.0)):
        try:
            raw = row.get(key)
            if raw is None:
                continue
            value = float(raw) / scale
            if value > 0:
                return value
        except (TypeError, ValueError):
            continue
    return None


def _restore_codex_rollout_mtime_from_row(row):
    path = _codex_rollout_path_from_row(row)
    ts = _codex_row_updated_epoch(row)
    if not path or ts is None:
        return False
    try:
        p = Path(path).expanduser().resolve()
        if not p.is_file():
            return False
        os.utime(p, (ts, ts))
        return True
    except (OSError, RuntimeError, ValueError):
        return False


def _mark_codex_thread_user_visible(thread_id, update_rollout=True):
    """Mark a CCC-created Codex exec thread as visible in Codex.app.

    Codex Desktop starts sidebar-visible threads with `thread_source='user'`.
    Its sidebar also treats IDE-originated rows as `source='vscode'`; plain
    `codex exec` rows can otherwise stay hidden. Codex can rebuild SQLite from
    the rollout JSONL, so we patch the rollout metadata when it is safe too.
    """
    sid = str(thread_id or "").strip()
    if not sid:
        return False
    for db in _codex_state_db_candidates():
        con = None
        try:
            con = sqlite3.connect(f"file:{db}?mode=rw", uri=True, timeout=0.25)
            cols = {
                row[1]
                for row in con.execute("PRAGMA table_info(threads)").fetchall()
            }
            if "id" not in cols or "thread_source" not in cols:
                continue
            selected = ["thread_source"]
            if "source" in cols:
                selected.append("source")
            if "rollout_path" in cols:
                selected.append("rollout_path")
            row = con.execute(
                f"SELECT {', '.join(selected)} FROM threads WHERE id = ?",
                (sid,),
            ).fetchone()
            if not row:
                continue
            values_by_col = dict(zip(selected, row))
            current = values_by_col.get("thread_source")
            source = values_by_col.get("source", "vscode")
            if current and current != "user":
                return False
            if source and source not in ("exec", "cli", "vscode"):
                return False
            if update_rollout:
                _mark_codex_rollout_user_visible(
                    sid,
                    values_by_col.get("rollout_path"),
                )
            assignments = []
            values = []
            if current != "user":
                assignments.append("thread_source = ?")
                values.append("user")
            if "source" in cols and source != "vscode":
                assignments.append("source = ?")
                values.append("vscode")
            if assignments:
                values.append(sid)
                con.execute(
                    f"UPDATE threads SET {', '.join(assignments)} WHERE id = ?",
                    tuple(values),
                )
                con.commit()
            return True
        except sqlite3.Error:
            continue
        finally:
            if con is not None:
                try:
                    con.close()
                except sqlite3.Error:
                    pass
    return False


def _codex_fetch_threads(where="", params=(), limit=None):
    """Read rows from Codex's local thread index without creating files.

    Codex stores durable conversation metadata in ~/.codex/state_*.sqlite,
    with each row pointing at a rollout JSONL. We open SQLite in read-only URI
    mode so a dashboard scan cannot create a missing DB or mutate state.
    """
    for db in _codex_state_db_candidates():
        try:
            con = sqlite3.connect(f"file:{db}?mode=ro", uri=True, timeout=0.25)
            con.row_factory = sqlite3.Row
        except sqlite3.Error:
            continue
        try:
            cols = {
                row["name"]
                for row in con.execute("PRAGMA table_info(threads)").fetchall()
            }
            if not cols:
                continue
            wanted = [
                "id", "rollout_path", "created_at", "updated_at",
                "created_at_ms", "updated_at_ms", "source", "model_provider",
                "cwd", "title", "tokens_used", "has_user_event", "archived",
                "archived_at", "git_sha", "git_branch", "git_origin_url",
                "cli_version", "first_user_message", "agent_nickname",
                "agent_role", "memory_mode", "model", "reasoning_effort",
                "thread_source",
            ]
            selected = [c for c in wanted if c in cols]
            if "id" not in selected:
                return []
            order_terms = []
            if "updated_at_ms" in cols:
                order_terms.append("updated_at_ms")
            if "updated_at" in cols:
                order_terms.append("updated_at * 1000")
            if "created_at_ms" in cols:
                order_terms.append("created_at_ms")
            if "created_at" in cols:
                order_terms.append("created_at * 1000")
            order = f"COALESCE({', '.join(order_terms)}) DESC" if order_terms else "id DESC"
            sql = f"SELECT {', '.join(selected)} FROM threads"
            if where:
                sql += f" WHERE {where}"
            sql += f" ORDER BY {order}"
            if limit:
                sql += " LIMIT ?"
                params = tuple(params) + (int(limit),)
            rows = [dict(r) for r in con.execute(sql, tuple(params)).fetchall()]
            return rows
        except sqlite3.Error:
            continue
        finally:
            try:
                con.close()
            except sqlite3.Error:
                pass
    return []


def _codex_thread_row(thread_id):
    if not thread_id:
        return None
    rows = _codex_fetch_threads("id = ?", (thread_id,), limit=1)
    return rows[0] if rows else None


def _codex_ts_seconds(row, prefix="updated"):
    ms = row.get(f"{prefix}_at_ms")
    if ms:
        try:
            return float(ms) / 1000.0
        except (TypeError, ValueError):
            pass
    val = row.get(f"{prefix}_at")
    if val:
        try:
            val = float(val)
            return val / 1000.0 if val > 100000000000 else val
        except (TypeError, ValueError):
            pass
    return 0.0


def _codex_rollout_path_from_row(row):
    if not row:
        return None
    raw = row.get("rollout_path") or ""
    if raw:
        p = Path(os.path.expanduser(raw))
        if p.is_file():
            return p
    tid = row.get("id") or ""
    if tid and CODEX_SESSIONS_ROOT.is_dir():
        try:
            matches = list(CODEX_SESSIONS_ROOT.glob(f"**/*{tid}*.jsonl"))
        except OSError:
            matches = []
        if matches:
            matches.sort(key=lambda p: p.stat().st_mtime if p.exists() else 0, reverse=True)
            return matches[0]
    return None


def _resolve_codex_rollout_path(thread_id):
    row = _codex_thread_row(thread_id)
    return _codex_rollout_path_from_row(row)


def _is_codex_session(session_id):
    return bool(_codex_thread_row(session_id))


def _codex_tool_name(name):
    return (name or "").rsplit(".", 1)[-1]


def _codex_args(raw):
    if isinstance(raw, dict):
        return raw
    if isinstance(raw, str) and raw:
        try:
            parsed = json.loads(raw)
            return parsed if isinstance(parsed, dict) else {}
        except (json.JSONDecodeError, ValueError):
            return {}
    return {}


def _codex_tool_detail(name, args):
    lname = _codex_tool_name(name)
    if lname == "exec_command":
        return _shell_command_activity_label(args.get("cmd") or args.get("command") or "")
    if lname == "write_stdin":
        return args.get("chars") or args.get("session_id") or ""
    for key in ("path", "file_path", "filename", "query", "pattern", "prompt", "message"):
        val = args.get(key)
        if isinstance(val, str) and val:
            return val
    return ""


def _codex_tool_command(name, args):
    lname = _codex_tool_name(name)
    if lname == "exec_command":
        cmd = args.get("cmd") or args.get("command") or ""
        return cmd if isinstance(cmd, str) else ""
    return ""


def _codex_tool_workdir(name, args):
    lname = _codex_tool_name(name)
    if lname == "exec_command":
        workdir = args.get("workdir") or ""
        return workdir if isinstance(workdir, str) else ""
    return ""


def _codex_event_epoch(ev):
    ts = ev.get("timestamp") or ""
    payload = ev.get("payload") if isinstance(ev.get("payload"), dict) else {}
    ts = ts or payload.get("timestamp") or payload.get("started_at") or payload.get("completed_at") or ""
    if not ts:
        return 0.0
    try:
        return datetime.fromisoformat(str(ts).replace("Z", "+00:00")).timestamp()
    except (TypeError, ValueError):
        return 0.0


def _codex_event_timestamp(ev):
    payload = ev.get("payload") if isinstance(ev.get("payload"), dict) else {}
    return ev.get("timestamp") or payload.get("timestamp") or payload.get("started_at") or ""


_SHELL_ASSIGNMENT_RE = re.compile(r"^[A-Za-z_][A-Za-z0-9_]*=")
_SHELL_WRAPPERS = {"command", "builtin", "exec", "noglob"}
_SHELLS = {"sh", "bash", "zsh"}
_GIT_OPTS_WITH_VALUE = {
    "-C",
    "-c",
    "--git-dir",
    "--work-tree",
    "--namespace",
    "--config-env",
    "--exec-path",
    "--super-prefix",
}
_GIT_OPTS_WITH_VALUE_PREFIXES = (
    "-C",
    "-c",
    "--git-dir=",
    "--work-tree=",
    "--namespace=",
    "--config-env=",
    "--exec-path=",
    "--super-prefix=",
)
_ENV_OPTS_WITH_VALUE = {"-u", "--unset", "-C", "--chdir", "-S", "--split-string"}
_SUDO_OPTS_WITH_VALUE = {"-u", "-g", "-h", "-p", "-C", "-T"}


def _shell_words(cmd):
    """Tokenize shell-ish command text without treating quoted text as code."""
    src = cmd or ""
    if "<<" not in src:
        src = src.replace("\n", " ; ")
    try:
        lex = shlex.shlex(src, posix=True, punctuation_chars=";&|")
        lex.whitespace_split = True
        return list(lex)
    except (TypeError, ValueError):
        try:
            return shlex.split(src)
        except ValueError:
            return src.split()


def _shell_segments(cmd):
    segment = []
    for tok in _shell_words(cmd):
        if tok and all(ch in ";&|" for ch in tok):
            if segment:
                yield segment
                segment = []
            continue
        segment.append(tok)
    if segment:
        yield segment


def _is_shell_assignment(tok):
    return bool(_SHELL_ASSIGNMENT_RE.match(tok or ""))


def _skip_sudo_options(tokens, i):
    while i < len(tokens) and tokens[i].startswith("-"):
        opt = tokens[i]
        if opt in _SUDO_OPTS_WITH_VALUE and i + 1 < len(tokens):
            i += 2
        else:
            i += 1
    return i


def _skip_env_options(tokens, i):
    while i < len(tokens):
        opt = tokens[i]
        if _is_shell_assignment(opt):
            i += 1
        elif opt in _ENV_OPTS_WITH_VALUE and i + 1 < len(tokens):
            i += 2
        elif opt.startswith("--unset=") or opt.startswith("--chdir="):
            i += 1
        elif opt.startswith("-"):
            i += 1
        else:
            break
    return i


def _shell_command_start(tokens):
    i = 0
    while i < len(tokens):
        tok = tokens[i]
        if _is_shell_assignment(tok) or tok in _SHELL_WRAPPERS:
            i += 1
            continue
        base = os.path.basename(tok)
        if base == "sudo":
            i = _skip_sudo_options(tokens, i + 1)
            continue
        if base == "env":
            i = _skip_env_options(tokens, i + 1)
            continue
        break
    return i


def _shell_nested_command(tokens, start):
    if start >= len(tokens) or os.path.basename(tokens[start]) not in _SHELLS:
        return None
    i = start + 1
    while i < len(tokens):
        tok = tokens[i]
        if tok == "--":
            i += 1
            continue
        if tok.startswith("-") and "c" in tok[1:]:
            return tokens[i + 1] if i + 1 < len(tokens) else None
        i += 1
    return None


def _resolve_shell_path(path, base_cwd=None):
    if not path:
        return None
    expanded = os.path.expanduser(path)
    if os.path.isabs(expanded):
        return os.path.abspath(expanded)
    base = os.path.expanduser(base_cwd) if base_cwd else os.getcwd()
    return os.path.abspath(os.path.join(base, expanded))


def _git_invocation(tokens, start, base_cwd=None):
    if start >= len(tokens) or os.path.basename(tokens[start]) != "git":
        return None
    used_dash_c = False
    dash_c_path = None
    i = start + 1
    while i < len(tokens):
        opt = tokens[i]
        if opt == "--":
            i += 1
            break
        if opt in _GIT_OPTS_WITH_VALUE and i + 1 < len(tokens):
            used_dash_c = used_dash_c or opt == "-C"
            if opt == "-C":
                dash_c_path = _resolve_shell_path(tokens[i + 1], base_cwd)
            i += 2
            continue
        if any(opt.startswith(prefix) and opt != prefix for prefix in _GIT_OPTS_WITH_VALUE_PREFIXES):
            used_dash_c = used_dash_c or opt.startswith("-C")
            if opt.startswith("-C"):
                dash_c_path = _resolve_shell_path(opt[2:], base_cwd)
            i += 1
            continue
        if opt.startswith("-"):
            i += 1
            continue
        break
    subcmd = tokens[i] if i < len(tokens) else ""
    return {
        "subcmd": subcmd,
        "subcmd_index": i,
        "used_dash_c": used_dash_c,
        "dash_c_path": dash_c_path,
    }


def _gh_pr_create(tokens, start):
    if start >= len(tokens) or os.path.basename(tokens[start]) != "gh":
        return False
    i = start + 1
    while i < len(tokens) and tokens[i].startswith("-"):
        opt = tokens[i]
        if opt in ("-R", "--repo", "--hostname") and i + 1 < len(tokens):
            i += 2
        else:
            i += 1
    return tokens[i:i + 2] == ["pr", "create"]


def _shell_command_signals(cmd, base_cwd=None, _depth=0):
    """Return edit/commit/push/pr/external-cd flags for a shell command."""
    cmd = cmd or ""
    worktree_path = None
    worktree_branch = None
    subcommands = set()
    pr_create = False
    external_cd = False
    for toks in _shell_segments(cmd):
        start = _shell_command_start(toks)
        if start >= len(toks):
            continue

        nested = _shell_nested_command(toks, start)
        if nested and _depth < 2:
            child = _shell_command_signals(nested, base_cwd=base_cwd, _depth=_depth + 1)
            subcommands.update(k for k in ("commit", "push") if child[k])
            pr_create = pr_create or child["pr"]
            external_cd = external_cd or child["external_cd"]
            worktree_path = child.get("worktree_path") or worktree_path
            worktree_branch = child.get("worktree_branch") or worktree_branch
            continue

        exe = os.path.basename(toks[start])
        if exe == "cd":
            target = toks[start + 1] if start + 1 < len(toks) else ""
            external_cd = external_cd or target.startswith("/") or target.startswith("~")
            continue

        git = _git_invocation(toks, start, base_cwd=base_cwd)
        if git:
            subcmd = git["subcmd"]
            if subcmd in ("commit", "push"):
                subcommands.add(subcmd)
            external_cd = external_cd or git["used_dash_c"]
            if subcmd == "worktree" and git["subcmd_index"] + 1 < len(toks):
                if toks[git["subcmd_index"] + 1] == "add":
                    branch = None
                    path = None
                    k = git["subcmd_index"] + 2
                    while k < len(toks):
                        part = toks[k]
                        if part in ("-b", "-B") and k + 1 < len(toks):
                            branch = toks[k + 1]
                            k += 2
                            continue
                        if part in ("--reason", "--lock") and k + 1 < len(toks):
                            k += 2
                            continue
                        if part == "--":
                            k += 1
                            continue
                        if part.startswith("-"):
                            k += 1
                            continue
                        path = part
                        break
                    if path:
                        path_base = git.get("dash_c_path") or base_cwd
                        worktree_path = _resolve_shell_path(path, path_base)
                        worktree_branch = branch or worktree_branch
            continue

        pr_create = pr_create or _gh_pr_create(toks, start)

    edit_like = bool(re.search(
        r"\b(apply_patch|tee|sed\s+-i|perl\s+-pi)\b|"
        r"(?:^|[\s;&|])cat\s+>|write_text\s*\(|"
        r"(?:^|[\s;&|])(?:printf|echo)\b[^;\n]*>\s*\S+",
        cmd,
    ))
    return {
        "edit": edit_like,
        "commit": "commit" in subcommands,
        "push": "push" in subcommands,
        "pr": pr_create,
        "external_cd": external_cd,
        "worktree_path": worktree_path,
        "worktree_branch": worktree_branch,
    }


def _codex_command_signals(cmd, base_cwd=None):
    return _shell_command_signals(cmd, base_cwd=base_cwd)


_CODEX_SUMMARY_BRANCH_RE = re.compile(r"(?im)^\s*(?:[-*]\s*)?Branch:\s*`?([^\r\n`]+?)`?\s*$")
_CODEX_SUMMARY_WORKTREE_RE = re.compile(r"(?im)^\s*(?:[-*]\s*)?Worktree:\s*`?([^\r\n`]+?)`?\s*$")


def _extract_codex_summary_signals(text, pr_url_re):
    """Extract final-summary PR/worktree fields from Codex prose."""
    out = {}
    if not isinstance(text, str) or not text:
        return out
    mp = pr_url_re.search(text)
    if mp:
        out["tail_pr_number"] = int(mp.group(2))
        out["tail_pr_url"] = (
            "https://github.com/" + mp.group(1) + "/pull/" + mp.group(2)
        )
    mb = _CODEX_SUMMARY_BRANCH_RE.search(text)
    if mb:
        branch = mb.group(1).strip().strip("`")
        if branch:
            out["tail_branch"] = branch
    mw = _CODEX_SUMMARY_WORKTREE_RE.search(text)
    if mw:
        worktree = mw.group(1).strip().strip("`")
        if worktree:
            out["tail_worktree_path"] = worktree
    return out


def _extract_codex_thread_id_from_log(log_path):
    if not log_path:
        return None
    try:
        with open(log_path, "r", encoding="utf-8", errors="replace") as f:
            for line in f:
                line = line.strip()
                if not line or not line.startswith("{"):
                    continue
                try:
                    ev = json.loads(line)
                except json.JSONDecodeError:
                    continue
                if ev.get("type") == "thread.started" and ev.get("thread_id"):
                    return ev["thread_id"]
    except OSError:
        return None
    return None


def _codex_sidebar_backfill_window_days():
    raw = os.environ.get("CCC_CODEX_SIDEBAR_BACKFILL_DAYS", "7")
    try:
        days = float(raw)
    except (TypeError, ValueError):
        days = 7.0
    return days if days > 0 else 7.0


def _spawn_registry_entry_epoch(entry):
    raw = (entry or {}).get("spawned_at") or (entry or {}).get("started")
    if not raw:
        return 0.0
    text = str(raw).strip()
    try:
        return datetime.strptime(text, "%Y%m%dT%H%M%S").timestamp()
    except ValueError:
        pass
    try:
        return datetime.fromisoformat(text.replace("Z", "+00:00")).timestamp()
    except ValueError:
        return 0.0


def _codex_registry_entry_epoch(entry):
    return _spawn_registry_entry_epoch(entry)


def _recent_codex_thread_repo_paths(days=None, now=None, limit=1000):
    if days is None:
        days = _codex_sidebar_backfill_window_days()
    try:
        now = float(now if now is not None else time.time())
    except (TypeError, ValueError):
        now = time.time()
    cutoff = now - (float(days) * 86400.0)
    out = []
    rows = _codex_fetch_threads(limit=limit)
    for row in rows:
        ts = _codex_ts_seconds(row, "updated") or _codex_ts_seconds(row, "created")
        if ts and ts < cutoff:
            break
        cwd = row.get("cwd") or ""
        if not cwd:
            continue
        try:
            repo = (
                _git_toplevel_for_existing_dir(cwd)
                or _nearest_marked_repo_dir(cwd)
                or str(Path(cwd).expanduser().resolve())
            )
        except (OSError, RuntimeError, ValueError):
            continue
        if repo:
            out.append(repo)
    return out


def _recent_codex_ccc_log_paths(repo_paths=None, days=None, now=None, max_logs=2000):
    """Recent CCC Codex spawn/resume logs, bounded to known repos."""
    if days is None:
        days = _codex_sidebar_backfill_window_days()
    try:
        max_logs = max(1, int(max_logs or 2000))
    except (TypeError, ValueError):
        max_logs = 2000
    try:
        now = float(now if now is not None else time.time())
    except (TypeError, ValueError):
        now = time.time()
    cutoff = now - (float(days) * 86400.0)
    raw_paths = []
    try:
        for entry in _load_spawn_registry():
            if entry.get("engine") == "codex" and entry.get("log"):
                raw_paths.append(entry.get("log"))
    except Exception:
        pass
    if repo_paths is None:
        try:
            repo_paths = [
                *_known_repo_paths(),
                *_recent_codex_thread_repo_paths(days=days, now=now),
            ]
        except Exception:
            repo_paths = []
    for repo_path in repo_paths or []:
        try:
            log_dir = repo_log_dir(repo_path)
        except Exception:
            continue
        if not log_dir.is_dir():
            continue
        for pattern in ("spawn-codex-*.log", "resume-codex-*.log"):
            try:
                raw_paths.extend(log_dir.glob(pattern))
            except OSError:
                continue

    seen = set()
    recent = []
    for raw in raw_paths:
        try:
            p = Path(raw).expanduser().resolve()
            key = str(p)
            if key in seen:
                continue
            seen.add(key)
            st = p.stat()
        except (OSError, ValueError, RuntimeError):
            continue
        if st.st_mtime < cutoff:
            continue
        recent.append((st.st_mtime, p))
    recent.sort(key=lambda item: item[0], reverse=True)
    return [p for _, p in recent[:max_logs]]


def _codex_sidebar_project_root_for_thread(row):
    cwd = (row or {}).get("cwd") or ""
    if not cwd:
        return None
    try:
        root = (
            _git_toplevel_for_existing_dir(cwd)
            or _nearest_marked_repo_dir(cwd)
            or str(Path(cwd).expanduser().resolve())
        )
    except (OSError, RuntimeError, ValueError):
        return None
    try:
        p = Path(root).expanduser().resolve()
    except (OSError, RuntimeError, ValueError):
        return None
    return str(p) if p.is_dir() else None


def _codex_sidebar_project_roots_from_values(repo_paths):
    roots = []
    seen = set()
    for repo in repo_paths or []:
        try:
            root = str(Path(repo).expanduser().resolve())
        except (OSError, RuntimeError, ValueError):
            continue
        if root in seen or not Path(root).is_dir():
            continue
        seen.add(root)
        roots.append(root)
    return roots


def _codex_global_state_path():
    return Path.home() / ".codex" / ".codex-global-state.json"


def _read_codex_global_state():
    try:
        data = json.loads(_codex_global_state_path().read_text(encoding="utf-8"))
    except (OSError, json.JSONDecodeError):
        return None
    return data if isinstance(data, dict) else None


def _codex_global_state_string_list(data, key):
    values = (data or {}).get(key)
    if not isinstance(values, list):
        return []
    return [str(x) for x in values if isinstance(x, str) and x.strip()]


def _codex_saved_workspace_roots():
    return _codex_global_state_string_list(
        _read_codex_global_state(),
        "electron-saved-workspace-roots",
    )


def _codex_desktop_app_is_running():
    if platform.system() != "Darwin":
        return False
    try:
        proc = subprocess.run(
            ["ps", "-axo", "command"],
            stdout=subprocess.PIPE,
            stderr=subprocess.DEVNULL,
            text=True,
            timeout=1.0,
            check=False,
        )
    except (OSError, subprocess.SubprocessError):
        return False
    if proc.returncode != 0:
        return False
    for line in proc.stdout.splitlines():
        if ".app/Contents/MacOS/Codex" in line:
            return True
    return False


def _open_codex_workspace_root_deeplink(root):
    if platform.system() != "Darwin" or not shutil.which("open"):
        return False
    url = "codex://new?path=" + urllib.parse.quote(str(root), safe="")
    try:
        proc = subprocess.run(
            ["open", url],
            stdout=subprocess.DEVNULL,
            stderr=subprocess.DEVNULL,
            timeout=2.0,
            check=False,
        )
    except (OSError, subprocess.SubprocessError):
        return False
    return proc.returncode == 0


def _wait_for_codex_workspace_roots(roots, timeout_s=2.0):
    wanted = set(roots or [])
    if not wanted:
        return set()
    deadline = time.monotonic() + max(0.0, float(timeout_s or 0))
    present = set(_codex_saved_workspace_roots())
    while not wanted.issubset(present) and time.monotonic() < deadline:
        time.sleep(0.1)
        present = set(_codex_saved_workspace_roots())
    return present


def _register_codex_sidebar_project_roots_live(roots):
    current = set(_codex_saved_workspace_roots())
    missing = [root for root in roots if root not in current]
    if not missing:
        return 0
    data = _read_codex_global_state() or {}
    active_roots = _codex_global_state_string_list(data, "active-workspace-roots")
    for root in missing:
        _open_codex_workspace_root_deeplink(root)
    if active_roots:
        active = active_roots[0]
        try:
            if Path(active).expanduser().is_dir():
                _open_codex_workspace_root_deeplink(active)
        except (OSError, RuntimeError, ValueError):
            pass
    present = _wait_for_codex_workspace_roots(missing)
    return sum(1 for root in missing if root in present)


def _append_codex_project_roots_to_global_state(roots):
    state_path = _codex_global_state_path()
    data = _read_codex_global_state()
    if data is None:
        return 0

    saved_before = set(_codex_global_state_string_list(
        data,
        "electron-saved-workspace-roots",
    ))
    changed = False
    for key in ("electron-saved-workspace-roots", "project-order"):
        current = _codex_global_state_string_list(data, key)
        present = set(current)
        added = [root for root in roots if root not in present]
        if not added:
            data[key] = current
            continue
        data[key] = added + current
        changed = True

    if not changed:
        return 0
    try:
        tmp = state_path.with_name(f"{state_path.name}.tmp-{os.getpid()}")
        tmp.write_text(json.dumps(data, indent=2, ensure_ascii=False) + "\n", encoding="utf-8")
        os.replace(tmp, state_path)
    except OSError:
        return 0
    saved_after = set(_codex_saved_workspace_roots())
    return sum(1 for root in roots if root not in saved_before and root in saved_after)


def _append_codex_sidebar_project_roots(repo_paths):
    """Add CCC-proven Codex repos to Codex Desktop's project sidebar state."""
    roots = _codex_sidebar_project_roots_from_values(repo_paths)
    if not roots:
        return 0
    if _read_codex_global_state() is None:
        return 0

    if _codex_desktop_app_is_running():
        return _register_codex_sidebar_project_roots_live(roots)
    return _append_codex_project_roots_to_global_state(roots)


def backfill_codex_sidebar_visibility(days=None, repo_paths=None, now=None, max_logs=2000):
    """Mark recent CCC-spawned Codex threads as Codex Desktop sidebar-visible."""
    if days is None:
        days = _codex_sidebar_backfill_window_days()
    try:
        now = float(now if now is not None else time.time())
    except (TypeError, ValueError):
        now = time.time()
    cutoff = now - (float(days) * 86400.0)
    ids = []
    seen_ids = set()

    def add_sid(sid):
        sid = str(sid or "").strip()
        if sid and sid not in seen_ids:
            seen_ids.add(sid)
            ids.append(sid)

    log_paths = _recent_codex_ccc_log_paths(
        repo_paths=repo_paths,
        days=days,
        now=now,
        max_logs=max_logs,
    )
    for path in log_paths:
        add_sid(_extract_codex_thread_id_from_log(path))

    try:
        registry_entries = _load_spawn_registry()
    except Exception:
        registry_entries = []
    for entry in registry_entries:
        if entry.get("engine") != "codex":
            continue
        entry_epoch = _codex_registry_entry_epoch(entry)
        if entry_epoch and entry_epoch < cutoff:
            continue
        log_path = entry.get("log")
        if log_path and not entry_epoch:
            try:
                if Path(log_path).expanduser().stat().st_mtime < cutoff:
                    continue
            except OSError:
                continue
        if not entry_epoch and not log_path:
            continue
        add_sid(entry.get("session_id") or entry.get("resumed_sid"))
        if log_path:
            add_sid(_extract_codex_thread_id_from_log(log_path))

    updated = 0
    already_visible = 0
    skipped = 0
    project_roots = []
    for sid in ids:
        before_row = _codex_thread_row(sid) or {}
        ok = _mark_codex_thread_user_visible(sid)
        after_row = _codex_thread_row(sid) or {}
        _restore_codex_rollout_mtime_from_row(after_row)
        root = _codex_sidebar_project_root_for_thread(after_row)
        if root:
            project_roots.append(root)
        after_thread_source = after_row.get("thread_source")
        after_source = after_row.get("source")
        if ok and after_thread_source == "user" and (after_source in (None, "vscode")):
            if (
                before_row.get("thread_source") == "user"
                and before_row.get("source") in (None, "vscode")
            ):
                already_visible += 1
            else:
                updated += 1
        else:
            skipped += 1
    projects_added = _append_codex_sidebar_project_roots(project_roots)
    return {
        "ok": True,
        "days": days,
        "scanned_logs": len(log_paths),
        "found": len(ids),
        "updated": updated,
        "already_visible": already_visible,
        "skipped": skipped,
        "projects_added": projects_added,
    }


def _codex_sidebar_visibility_backfill_once():
    try:
        result = backfill_codex_sidebar_visibility()
    except Exception as e:
        print(f"  [codex-sidebar] backfill skipped ({e})")
        return
    if result.get("updated"):
        print(
            "  [codex-sidebar] marked "
            f"{result['updated']} recent CCC Codex thread(s) as IDE-visible"
        )
    if result.get("projects_added"):
        print(
            "  [codex-sidebar] registered "
            f"{result['projects_added']} recent CCC Codex project(s) with Codex Desktop"
        )


def _claude_desktop_backfill_window_days():
    raw = os.environ.get("CCC_CLAUDE_DESKTOP_BACKFILL_DAYS", "7")
    try:
        days = float(raw)
    except (TypeError, ValueError):
        days = 7.0
    return days if days > 0 else 7.0


def _is_probable_claude_spawn_log(path):
    name = Path(path).name
    blocked_prefixes = (
        "spawn-codex-",
        "resume-codex-",
        "spawn-gemini-",
        "resume-gemini-",
        "spawn-antigravity-",
        "resume-antigravity-",
    )
    if name.startswith(blocked_prefixes):
        return False
    return (
        (name.startswith("spawn-") or name.startswith("resume-"))
        and name.endswith(".log")
        and not name.endswith(".agy.log")
    )


def _recent_claude_ccc_log_paths(repo_paths=None, days=None, now=None, max_logs=2000):
    """Recent CCC Claude spawn/resume logs, bounded to known repos."""
    if days is None:
        days = _claude_desktop_backfill_window_days()
    try:
        max_logs = max(1, int(max_logs or 2000))
    except (TypeError, ValueError):
        max_logs = 2000
    try:
        now = float(now if now is not None else time.time())
    except (TypeError, ValueError):
        now = time.time()
    cutoff = now - (float(days) * 86400.0)
    raw_paths = []
    registry_entries = []
    try:
        registry_entries = _load_spawn_registry()
    except Exception:
        registry_entries = []
    for entry in registry_entries:
        engine = entry.get("engine") or "claude"
        if engine == "claude" and entry.get("log"):
            raw_paths.append(entry.get("log"))

    if repo_paths is None:
        candidates = []
        try:
            candidates.extend(_known_repo_paths())
        except Exception:
            pass
        try:
            candidates.extend(_discover_repo_paths_from_projects())
        except Exception:
            pass
        for entry in registry_entries:
            engine = entry.get("engine") or "claude"
            if engine != "claude":
                continue
            for key in ("repo_path", "cwd"):
                if entry.get(key):
                    candidates.append(entry.get(key))
        repo_paths = candidates

    seen_repos = set()
    for repo_path in repo_paths or []:
        try:
            repo = str(Path(repo_path).expanduser().resolve())
        except (OSError, RuntimeError, ValueError, TypeError):
            continue
        if repo in seen_repos:
            continue
        seen_repos.add(repo)
        try:
            log_dir = repo_log_dir(repo)
        except Exception:
            continue
        if not log_dir.is_dir():
            continue
        for pattern in ("spawn-*.log", "resume-*.log"):
            try:
                raw_paths.extend(log_dir.glob(pattern))
            except OSError:
                continue

    seen = set()
    recent = []
    for raw in raw_paths:
        try:
            p = Path(raw).expanduser().resolve()
            key = str(p)
            if key in seen or not _is_probable_claude_spawn_log(p):
                continue
            seen.add(key)
            st = p.stat()
        except (OSError, ValueError, RuntimeError, TypeError):
            continue
        if st.st_mtime < cutoff:
            continue
        recent.append((st.st_mtime, p))
    recent.sort(key=lambda item: item[0], reverse=True)
    return [p for _mtime, p in recent[:max_logs]]


def backfill_claude_desktop_visibility(days=None, repo_paths=None, now=None, max_logs=2000):
    """Create Claude Desktop sidebar metadata for recent CCC-spawned sessions."""
    if days is None:
        days = _claude_desktop_backfill_window_days()
    try:
        now = float(now if now is not None else time.time())
    except (TypeError, ValueError):
        now = time.time()
    cutoff = now - (float(days) * 86400.0)
    pruned = prune_unresumable_claude_desktop_metadata().get("pruned", 0)
    ids = []
    seen_ids = set()
    entries_by_sid = {}

    def add_sid(sid, entry=None):
        sid = str(sid or "").strip()
        if not sid or not _SESSION_UUID_RE.match(sid):
            return
        if entry and sid not in entries_by_sid:
            entries_by_sid[sid] = entry
        if sid not in seen_ids:
            seen_ids.add(sid)
            ids.append(sid)

    log_paths = _recent_claude_ccc_log_paths(
        repo_paths=repo_paths,
        days=days,
        now=now,
        max_logs=max_logs,
    )
    for path in log_paths:
        add_sid(extract_session_id(path))

    try:
        registry_entries = _load_spawn_registry()
    except Exception:
        registry_entries = []
    for entry in registry_entries:
        engine = entry.get("engine") or "claude"
        if engine != "claude":
            continue
        entry_epoch = _spawn_registry_entry_epoch(entry)
        if entry_epoch and entry_epoch < cutoff:
            continue
        log_path = entry.get("log")
        if log_path and not entry_epoch:
            try:
                if Path(log_path).expanduser().stat().st_mtime < cutoff:
                    continue
            except OSError:
                continue
        if not entry_epoch and not log_path:
            continue
        add_sid(entry.get("session_id") or entry.get("resumed_sid"), entry)
        if log_path:
            add_sid(extract_session_id(log_path), entry)

    updated = 0
    already_visible = 0
    skipped = 0
    for sid in ids:
        before_path = _claude_desktop_metadata_path_for_cli_session(sid)
        ok = _ensure_claude_desktop_session_visible(sid, spawn_entry=entries_by_sid.get(sid))
        after_path = _claude_desktop_metadata_path_for_cli_session(sid)
        if ok and after_path:
            if before_path:
                already_visible += 1
            else:
                updated += 1
        else:
            skipped += 1

    return {
        "ok": True,
        "days": days,
        "scanned_logs": len(log_paths),
        "found": len(ids),
        "updated": updated,
        "already_visible": already_visible,
        "skipped": skipped,
        "pruned": pruned,
    }


def _claude_desktop_visibility_backfill_once():
    try:
        result = backfill_claude_desktop_visibility()
    except Exception as e:
        print(f"  [claude-desktop] backfill skipped ({e})")
        return
    if result.get("updated"):
        print(
            "  [claude-desktop] added "
            f"{result['updated']} recent CCC Claude session(s) to the Desktop sidebar"
        )


def _register_codex_sidebar_project_for_spawn_entry(entry, sid=None):
    if not isinstance(entry, dict):
        return 0
    root = None
    for key in ("repo_path", "cwd"):
        root = _codex_sidebar_project_root_for_thread({"cwd": entry.get(key) or ""})
        if root:
            break
    if not root and sid:
        root = _codex_sidebar_project_root_for_thread(_codex_thread_row(sid))
    if not root:
        return 0
    return _append_codex_sidebar_project_roots([root])


def _codex_spawn_pid_by_thread_id():
    out = {}
    for s in _spawned_sessions:
        if s.get("engine") != "codex":
            continue
        sid = s.get("session_id") or s.get("resumed_sid") or _extract_codex_thread_id_from_log(s.get("log"))
        if sid:
            try:
                alive = _poll_spawn_entry(s) is None
            except Exception:
                alive = False
            _mark_codex_thread_user_visible(sid, update_rollout=not alive)
            _register_codex_sidebar_project_for_spawn_entry(s, sid)
            if not s.get("session_id"):
                s["session_id"] = sid
                _update_spawn_session_id_in_registry(s.get("pid"), sid)
            if sid not in out:
                out[sid] = {
                    "pid": s.get("pid"),
                    "alive": alive,
                    "log": s.get("log"),
                    "cwd": s.get("cwd") or "",
                    "repo_path": s.get("repo_path") or "",
                    "spawned_at": s.get("started") or "",
                    "prompt": s.get("prompt") or "",
                    "model": s.get("model") or "",
                }
    return out


def _codex_cwd_matches_repo(cwd, repo_path, git_top_cache):
    if not cwd:
        return False
    try:
        p = Path(cwd).expanduser().resolve()
        root = Path(repo_path).expanduser().resolve()
    except (OSError, RuntimeError, ValueError):
        p = Path(str(cwd))
        root = Path(str(repo_path))
    try:
        if p == root or root in p.parents:
            return True
    except RuntimeError:
        pass
    try:
        return _git_toplevel_for_path(str(p), git_top_cache) == str(root)
    except Exception:
        return False


# Per-file resume state for incremental codex tail parsing: path -> {offset,
# pos, pending_calls, meta, meta_version}. In-memory only (NOT persisted with
# _conv_meta_cache) — after a restart the first poll does one full parse and
# rebuilds it. Guarded by _conv_meta_cache_lock.
_codex_tail_resume = {}


def _extract_codex_tail_meta(path):
    try:
        st = path.stat()
    except OSError:
        return {}
    mtime = st.st_mtime
    size = st.st_size
    spath = str(path)
    cached = _conv_meta_cache.get(spath)
    if (
        cached
        and cached.get("mtime") == mtime
        and cached.get("engine") == "codex"
        and cached.get("meta_version") == _CODEX_META_VERSION
    ):
        return cached

    # Incremental resume. Rollout JSONL is append-only, so rather than
    # re-parsing the whole (often multi-MB) file on every poll — the mtime
    # cache above *always* misses for a live, actively-appending session, which
    # is exactly the session live-activity polls — carry forward the prior
    # parse state and read only the bytes appended since the last call.
    with _conv_meta_cache_lock:
        resume = _codex_tail_resume.get(spath)
    if (
        resume
        and resume.get("meta_version") == _CODEX_META_VERSION
        and size >= resume.get("offset", 0)
    ):
        meta = resume["meta"]
        pending_calls = resume["pending_calls"]
        pos = resume["pos"]
        start_offset = resume["offset"]
    else:
        meta = {
            "engine": "codex",
            "meta_version": _CODEX_META_VERSION,
            "mtime": mtime,
            "first_message": None,
            "last_meaningful_ts": 0,
            "last_prompt": None,
            "last_assistant_text": None,
            "last_event_type": None,
            "pending_tool": None,
            "pending_file": None,
            "pending_tool_ts": 0,
            "has_edit": False,
            "has_commit": False,
            "has_push": False,
            "last_edit_pos": 0,
            "last_commit_pos": 0,
            "last_push_pos": 0,
            "tail_pr_number": None,
            "tail_pr_url": None,
            "tail_branch": None,
            "tail_worktree_path": None,
            "has_external_cd": False,
            "cwd": None,
            "model": None,
            "latest_input_tokens": 0,
            "context_limit": 0,
        }
        pending_calls = {}
        pos = 0
        start_offset = 0
    pr_url_re = re.compile(r"github\.com/([^/\s]+/[^/\s]+)/pull/(\d{1,7})")
    # Binary + readline() so f.tell()/offset accounting stays exact (text-mode
    # iteration buffers ahead and corrupts the resume offset).
    try:
        with open(path, "rb") as f:
            if start_offset:
                f.seek(start_offset)
            while True:
                raw = f.readline()
                if not raw:
                    break
                if not raw.endswith(b"\n"):
                    # Partial trailing line — writer is mid-append. Leave the
                    # offset before it so the next poll re-reads it complete.
                    break
                start_offset += len(raw)
                pos += 1
                line = raw.decode("utf-8", "replace").strip()
                if not line:
                    continue
                try:
                    ev = json.loads(line)
                except json.JSONDecodeError:
                    continue
                usage = _codex_token_usage_from_event(ev)
                if usage:
                    inp = _codex_int(usage.get("input_tokens"))
                    if inp:
                        meta["latest_input_tokens"] = inp
                    payload = ev.get("payload") if isinstance(ev.get("payload"), dict) else {}
                    info = payload.get("info") or {}
                    if isinstance(info, dict):
                        cl = _codex_int(info.get("model_context_window"))
                        if cl:
                            meta["context_limit"] = cl
                    continue
                payload = ev.get("payload") if isinstance(ev.get("payload"), dict) else {}
                ts_epoch = _codex_event_epoch(ev)
                ev_type = ev.get("type")
                ptype = payload.get("type")
                if ev_type in ("session_meta", "turn_context"):
                    meta["cwd"] = payload.get("cwd") or meta["cwd"]
                    meta["model"] = payload.get("model") or meta["model"]
                    continue
                if ev_type == "event_msg":
                    if ptype == "user_message":
                        text = _strip_ccc_session_state_instruction(
                            payload.get("message") or ""
                        ).strip()
                        if text:
                            meta["first_message"] = meta["first_message"] or text
                            meta["last_prompt"] = text
                        meta["last_event_type"] = "user"
                        meta["pending_tool"] = None
                        meta["pending_file"] = None
                        meta["pending_tool_ts"] = 0
                        if ts_epoch:
                            meta["last_meaningful_ts"] = ts_epoch
                    elif ptype == "agent_message":
                        text = (payload.get("message") or "").strip()
                        if text:
                            meta["last_assistant_text"] = text
                            meta.update(_extract_codex_summary_signals(text, pr_url_re))
                        meta["last_event_type"] = "assistant"
                        if ts_epoch:
                            meta["last_meaningful_ts"] = ts_epoch
                    elif ptype == "task_complete":
                        text = (payload.get("last_agent_message") or payload.get("message") or "").strip()
                        if text:
                            meta.update(_extract_codex_summary_signals(text, pr_url_re))
                        meta["last_event_type"] = "result"
                        meta["pending_tool"] = None
                        meta["pending_file"] = None
                        meta["pending_tool_ts"] = 0
                        if ts_epoch:
                            meta["last_meaningful_ts"] = ts_epoch
                    continue
                if ev_type != "response_item":
                    continue
                if ptype == "function_call":
                    name = payload.get("name") or ""
                    args = _codex_args(payload.get("arguments"))
                    detail = _codex_tool_detail(name, args)
                    call_id = payload.get("call_id") or ""
                    meta["last_event_type"] = "assistant"
                    if ts_epoch:
                        meta["last_meaningful_ts"] = ts_epoch
                    meta["pending_tool"] = _codex_tool_name(name) or name
                    meta["pending_file"] = (detail[:80] if isinstance(detail, str) else None)
                    meta["pending_tool_ts"] = ts_epoch or meta.get("last_meaningful_ts") or mtime
                    if _codex_tool_name(name) == "apply_patch":
                        meta["has_edit"] = True
                        meta["last_edit_pos"] = pos
                    cmd = _codex_tool_command(name, args)
                    tool_workdir = _codex_tool_workdir(name, args) or meta.get("cwd")
                    if cmd:
                        signals = _codex_command_signals(cmd, base_cwd=tool_workdir)
                        if signals["edit"]:
                            meta["has_edit"] = True
                            meta["last_edit_pos"] = pos
                        if signals["commit"]:
                            meta["has_commit"] = True
                            meta["last_commit_pos"] = pos
                        if signals["push"]:
                            meta["has_push"] = True
                            meta["last_push_pos"] = pos
                        if signals["external_cd"]:
                            meta["has_external_cd"] = True
                        if signals.get("worktree_path"):
                            meta["tail_worktree_path"] = signals["worktree_path"]
                        if signals.get("worktree_branch"):
                            meta["tail_branch"] = signals["worktree_branch"]
                        if call_id:
                            pending_calls[call_id] = {"cmd": cmd, "pr": signals["pr"]}
                    elif call_id:
                        pending_calls[call_id] = {"cmd": "", "pr": False}
                elif ptype == "function_call_output":
                    call_id = payload.get("call_id") or ""
                    call = pending_calls.pop(call_id, {})
                    if call:
                        meta["pending_tool"] = None
                        meta["pending_file"] = None
                        meta["pending_tool_ts"] = 0
                    meta["last_event_type"] = "assistant"
                    if ts_epoch:
                        meta["last_meaningful_ts"] = ts_epoch
                    out = payload.get("output") or ""
                    if call.get("pr") and isinstance(out, str):
                        mp = pr_url_re.search(out)
                        if mp:
                            meta["tail_pr_number"] = int(mp.group(2))
                            meta["tail_pr_url"] = (
                                "https://github.com/" + mp.group(1) + "/pull/" + mp.group(2)
                            )
                else:
                    meta["last_event_type"] = "assistant"
                    if ts_epoch:
                        meta["last_meaningful_ts"] = ts_epoch
            end_offset = start_offset
    except OSError:
        return {}

    meta["mtime"] = mtime
    if not meta.get("last_meaningful_ts"):
        meta["last_meaningful_ts"] = mtime
    with _conv_meta_cache_lock:
        _conv_meta_cache[spath] = meta
        _codex_tail_resume[spath] = {
            "meta_version": _CODEX_META_VERSION,
            "offset": end_offset,
            "pos": pos,
            "pending_calls": pending_calls,
            "meta": meta,
        }
        global _conv_meta_cache_dirty
        _conv_meta_cache_dirty = True
    return meta


def _codex_stale_tool_threshold_s():
    try:
        threshold = float(os.environ.get("CCC_CODEX_STALE_TOOL_SEC", "900"))
    except (TypeError, ValueError):
        threshold = 900.0
    return max(0.0, threshold)


def _codex_stale_tool_fields(tail, now=None, threshold_s=None):
    threshold = _codex_stale_tool_threshold_s() if threshold_s is None else max(0.0, float(threshold_s))
    fields = {
        "stale_tool_call": False,
        "stale_tool_age_s": 0,
        "stale_tool_threshold_s": int(threshold),
    }
    if not tail or not tail.get("pending_tool"):
        return fields
    ts = tail.get("pending_tool_ts") or 0
    if not ts:
        return fields
    try:
        age = max(0.0, float(now if now is not None else time.time()) - float(ts))
    except (TypeError, ValueError):
        return fields
    fields["stale_tool_age_s"] = int(age)
    fields["stale_tool_call"] = bool(threshold > 0 and age >= threshold)
    return fields


def _stale_tool_threshold_s():
    """Stale-tool threshold for Claude/headless sessions (seconds).

    Mirrors the Codex knob but for the headless tool-child path. A tool child
    that has been "running" longer than this with no result is treated as hung,
    so the UI can warn the user (queued input cannot drain while a tool child is
    active). Configurable via ``CCC_STALE_TOOL_SEC`` (default 900s / 15m).
    """
    try:
        threshold = float(os.environ.get("CCC_STALE_TOOL_SEC", "900"))
    except (TypeError, ValueError):
        threshold = 900.0
    return max(0.0, threshold)


def _claude_stale_tool_fields(started_at, in_flight, now=None, threshold_s=None):
    """Stale-tool fields for a Claude headless session's active tool child.

    Codex synthesizes these from its rollout tail; Claude headless sessions have
    no rollout, but ``_spawn_entry_active_tool_child`` gives the real child start
    time (from ``ps`` etime). When an in-flight tool child has aged past the
    threshold it is almost certainly wedged (the real case: ``rg`` blocked on a
    ``.stdin`` FIFO for ~3.7h), and the input queue cannot drain while a child
    is alive — so flag it for the UI.
    """
    threshold = _stale_tool_threshold_s() if threshold_s is None else max(0.0, float(threshold_s))
    fields = {
        "stale_tool_call": False,
        "stale_tool_age_s": 0,
        "stale_tool_threshold_s": int(threshold),
    }
    if not in_flight or not started_at:
        return fields
    try:
        age = max(0.0, float(now if now is not None else time.time()) - float(started_at))
    except (TypeError, ValueError):
        return fields
    fields["stale_tool_age_s"] = int(age)
    fields["stale_tool_call"] = bool(threshold > 0 and age >= threshold)
    return fields


def _codex_activity_fields_from_tail(tail, live):
    """Map Codex rollout tail state into the sidecar-shaped UI fields.

    Claude sessions get this from command-center hooks. Codex does not run
    those hooks, so live rows synthesize equivalent activity from the rollout:
    an unfinished tool call names the tool; otherwise a mid-turn user/assistant
    tail shows as generic thinking.
    """
    fields = {
        "sidecar_status": None,
        "sidecar_has_writes": False,
        "sidecar_tool": None,
        "sidecar_file": None,
        "sidecar_ts": 0,
        "sidecar_in_flight": False,
        "question_waiting": False,
        "question_text": "",
        "question_header": "",
        "question_preamble": "",
        "question_options": [],
        "question_option_details": [],
    }
    if not live or not tail:
        return fields
    if _codex_stale_tool_fields(tail).get("stale_tool_call"):
        return fields

    ts = tail.get("last_meaningful_ts") or 0
    pending_tool = tail.get("pending_tool")
    if pending_tool:
        fields.update({
            "sidecar_status": "active",
            "sidecar_tool": pending_tool,
            "sidecar_file": tail.get("pending_file"),
            "sidecar_ts": ts,
            "sidecar_in_flight": True,
        })
        return fields

    if tail.get("last_event_type") in ("user", "assistant"):
        fields.update({
            "sidecar_status": "active",
            "sidecar_tool": "Thinking",
            "sidecar_file": None,
            "sidecar_ts": ts,
            "sidecar_in_flight": True,
        })
    return fields


def _codex_fresh_threshold_s():
    try:
        v = float(os.environ.get("CCC_CODEX_FRESH_SEC", "40"))
    except (TypeError, ValueError):
        v = 40.0
    return max(0.0, v)


def _codex_recent_window_s():
    try:
        v = float(os.environ.get("CCC_CODEX_RECENT_SEC", str(24 * 3600)))
    except (TypeError, ValueError):
        v = float(24 * 3600)
    return max(0.0, v)


def _codex_row_state(tail, mtime, now, pool_alive, has_live_proc):
    """Classify one codex session into working / idle / stuck / offline.

    Pure function (no I/O) so it is unit-testable. Caller applies the
    recency gate and resolves pool/liveness/mtime before calling.

    Priority: offline (engine down) > stuck (mid-turn, stale) >
    working (mid-turn, fresh) > idle (turn complete).
    """
    if not tail:
        return None
    mid_turn = bool(tail.get("pending_tool")) or (
        tail.get("last_event_type") in ("user", "assistant")
    )
    if not pool_alive and not has_live_proc:
        return "offline"
    if mid_turn:
        try:
            age = max(0.0, float(now) - float(mtime or 0))
        except (TypeError, ValueError):
            age = 0.0
        if age >= _codex_stale_tool_threshold_s():
            return "stuck"
        return "working"
    return "idle"


def _codex_pool_alive(now=None):
    """True when a `codex app-server` pool process is running.

    Cached for _ENGINE_LIVE_TTL like the engine-live scan. On any error,
    fall back to the last value (default True) so a transient ps failure
    never flips every codex row to a false 'offline'.
    """
    now = now if now is not None else time.time()
    cached = _codex_pool_alive_cache
    if now - cached["ts"] < _ENGINE_LIVE_TTL:
        return cached["alive"]
    try:
        alive = False
        for p in find_live_codex_processes():
            if "app-server" in (p.get("command") or ""):
                alive = True
                break
    except Exception:
        return cached["alive"]
    _codex_pool_alive_cache["ts"] = now
    _codex_pool_alive_cache["alive"] = alive
    return alive


def _codex_state_fields(sid, now=None):
    """Resolve {codex_state, codex_fresh} for one codex session id.

    Applies the recency gate (no chip for sessions whose rollout hasn't
    been touched within _codex_recent_window_s). Fails quiet to nulls.
    """
    fields = {"codex_state": None, "codex_fresh": False}
    if not sid:
        return fields
    try:
        path = _resolve_codex_rollout_path(sid)
        if not path:
            return fields
        mtime = os.path.getmtime(path)
    except OSError:
        return fields
    now = now if now is not None else time.time()
    if (now - mtime) > _codex_recent_window_s():
        return fields
    try:
        tail = _extract_codex_tail_meta(path) or {}
        pool_alive = _codex_pool_alive(now)
        has_live_proc = sid in _live_engine_session_ids()
        state = _codex_row_state(tail, mtime, now, pool_alive, has_live_proc)
    except Exception:
        return fields
    fields["codex_state"] = state
    if state == "working":
        fields["codex_fresh"] = (now - float(mtime)) < _codex_fresh_threshold_s()
    elif state == "stuck":
        fields["codex_state_reason"] = _codex_stuck_reason(tail, mtime, now)
    return fields


def _codex_stuck_reason(tail, mtime, now):
    """Human-readable 'why is this codex session stuck' string.

    Stuck = mid-turn but the rollout has not advanced past the stale
    threshold. Name the tool it stalled on (if any) and how long it has been
    silent, so the UI can answer 'do we know why it was stuck?'.
    """
    try:
        mins = int(max(0.0, float(now) - float(mtime or 0)) // 60)
    except (TypeError, ValueError):
        mins = 0
    ago = f"{mins}m" if mins else "under a minute"
    pending = (tail or {}).get("pending_tool")
    if pending:
        target = (tail or {}).get("pending_file") or ""
        label = (f"{pending} {target}".strip())
        return f"No output for {ago} while running {label} — the tool call looks hung."
    return f"No output for {ago} after the last message — the turn stalled with no tool running."


def find_codex_conversations(
    repo_path=None,
    include_old=True,
    repo_only=True,
    progress=None,
    limit=None,
    resolve_pr_states=True,
    resolve_worktree_dirty=True,
):
    rows = _codex_fetch_threads(limit=limit)
    if not rows:
        return []
    if repo_only:
        repo_path = resolve_repo_path(repo_path)
        repo_path_obj = Path(repo_path)
    try:
        repo_pins = _load_repo_pins()
    except Exception:
        repo_pins = {}
    try:
        name_overrides = _load_session_name_overrides()
    except Exception:
        name_overrides = {}
    try:
        archived_set = set(_load_archived_conversations())
    except Exception:
        archived_set = set()
    try:
        verified_set = set(_load_verified_conversations())
    except Exception:
        verified_set = set()
    try:
        last_interactions = _load_last_interactions()
    except Exception:
        last_interactions = {}

    cutoff = _session_scan_cutoff_ts(include_old)
    max_rows = _session_scan_file_limit(include_old)
    spawn_by_sid = _codex_spawn_pid_by_thread_id()
    git_top_cache = {}
    out = []
    scanned = 0
    for row in rows:
        sid = row.get("id") or ""
        if not sid:
            continue
        cwd = row.get("cwd") or ""
        pinned = repo_pins.get(sid)
        pinned_repo = False
        if repo_only:
            if pinned and pinned != repo_path:
                continue
            if pinned == repo_path:
                pinned_repo = True
            elif not _codex_cwd_matches_repo(cwd, repo_path_obj, git_top_cache):
                continue
        path = _codex_rollout_path_from_row(row)
        if not path or not path.is_file():
            continue
        scanned += 1
        try:
            st = path.stat()
        except OSError:
            continue
        tail = _extract_codex_tail_meta(path) or {}
        cwd = tail.get("cwd") or cwd
        modified = (
            tail.get("last_meaningful_ts")
            or _codex_ts_seconds(row, "updated")
            or st.st_mtime
        )
        freshness = max(modified, last_interactions.get(sid) or 0)
        if not include_old and sid not in spawn_by_sid and cutoff > 0 and freshness < cutoff:
            continue
        if not include_old and max_rows > 0 and len(out) >= max_rows:
            continue
        row_first_message = _strip_ccc_session_state_instruction(
            row.get("first_user_message") or ""
        ).strip()
        tail_first_message = _strip_ccc_session_state_instruction(
            tail.get("first_message") or ""
        ).strip()
        first_message = row_first_message or tail_first_message
        title = _strip_ccc_session_state_instruction(
            (row.get("title") or "").strip()
        ).strip()
        # Codex sometimes stores the verbatim first user message as the
        # "title" when the prompt is too short to summarize. Only treat the
        # title as AI-generated when it actually differs from first_message
        # — otherwise the ✨ glyph would show on rows where Codex did no
        # summarization.
        codex_ai_title = title if (title and title != first_message) else None
        # Codex's SQLite `title` is the raw first user message when the
        # prompt was too short to summarize — for annotation prompts that
        # can be many kilobytes, so clamp before it becomes the row title.
        display_name = (
            name_overrides.get(sid)
            or (row.get("agent_nickname") or "").strip()
            or _truncate_session_name(title)
            or (first_message[:80] if first_message else None)
        )
        branch = row.get("git_branch") or ""
        tail_branch = tail.get("tail_branch") or ""
        tail_worktree_path = tail.get("tail_worktree_path") or ""
        # Prefer the FIRST cwd candidate that still exists on disk. Without
        # this, a tail-extracted worktree path that has since been deleted
        # (deleted worktree, moved repo) would land in `session_cwd` and
        # Launch would try `cd '/.../no-such-worktree' && codex resume …`
        # — which fails and leaves the user in their home dir.
        effective_cwd = _first_existing_dir(
            tail_worktree_path, cwd, pinned
        ) or tail_worktree_path or cwd
        try:
            cwd_exists = bool(effective_cwd and Path(effective_cwd).is_dir())
        except OSError:
            cwd_exists = False
        folder_path = pinned or cwd or effective_cwd or ""
        if folder_path:
            _git_root = _find_git_root(folder_path)
            folder_label = _resolve_dir_case(_git_root or folder_path)
        else:
            folder_label = "Codex"
        _wt_worktree_label = None
        _wt_idx = folder_label.find("-wt-")
        if _wt_idx > 0:
            _wt_worktree_label = folder_label[_wt_idx + 4:]
            folder_label = folder_label[:_wt_idx]
        spawn_info = spawn_by_sid.get(sid) or {}
        spawn_pid = spawn_info.get("pid")
        spawn_alive = bool(spawn_info.get("alive"))
        codex_activity = _codex_activity_fields_from_tail(tail, spawn_alive)
        codex_stale_tool = _codex_stale_tool_fields(tail)
        out.append({
            "id": sid,
            "session_id": sid,
            "source": "codex",
            "engine": "codex",
            "timestamp": "",
            "branch": branch,
            "git_branch": branch,
            "first_message": first_message[:200],
            "display_name": display_name,
            "ai_title": codex_ai_title,
            "name_overridden": bool(name_overrides.get(sid)),
            "last_prompt": (tail.get("last_prompt") or "")[:200],
            "size": st.st_size,
            "modified": modified,
            "modified_human": time.strftime("%Y-%m-%d %H:%M", time.localtime(modified)),
            "mtime": modified,
            "jsonl_path": str(path),
            "folder_label": folder_label,
            "folder_path": folder_path,
            "worktree_label": _wt_worktree_label,
            "session_cwd": effective_cwd,
            "session_cwd_exists": cwd_exists,
            "session_cwd_is_worktree": bool(
                tail_worktree_path or (effective_cwd and (Path(effective_cwd) / ".git").is_file())
            ),
            "worktree_dirty": (
                _worktree_dirty_cached(effective_cwd, modified)
                if resolve_worktree_dirty and effective_cwd else False
            ),
            "effective_branch": tail_branch or None,
            "effective_kind": "worktree" if tail_worktree_path else None,
            "has_edit": tail.get("has_edit", False),
            "has_commit": tail.get("has_commit", False),
            "has_push": tail.get("has_push", False),
            "last_edit_pos": tail.get("last_edit_pos", 0),
            "last_commit_pos": tail.get("last_commit_pos", 0),
            "last_push_pos": tail.get("last_push_pos", 0),
            "last_event_type": tail.get("last_event_type"),
            "pending_tool": tail.get("pending_tool"),
            "pending_file": tail.get("pending_file"),
            "pending_tool_ts": tail.get("pending_tool_ts") or 0,
            "last_assistant_text": tail.get("last_assistant_text"),
            "tail_issue_number": None,
            "tail_pr_number": tail.get("tail_pr_number"),
            "tail_pr_url": tail.get("tail_pr_url"),
            "pr_state": None,
            "session_state": _parse_session_state(tail.get("last_assistant_text")),
            "archived": sid in archived_set or bool(row.get("archived")),
            "verified": sid in verified_set,
            "pinned_repo": pinned_repo,
            "last_interacted": last_interactions.get(sid),
            "is_live": spawn_alive,
            "spawn_pid": spawn_pid,
            **codex_activity,
            **codex_stale_tool,
            "needs_approval": False,
            "needs_approval_message": "",
            "model": row.get("model") or tail.get("model") or "",
            "reasoning_effort": row.get("reasoning_effort") or "",
            "latest_input_tokens": tail.get("latest_input_tokens") or 0,
            "context_limit": tail.get("context_limit") or 0,
        })
    if resolve_pr_states:
        _prime_pr_states(c.get("tail_pr_url") for c in out)
        for c in out:
            if c.get("tail_pr_url"):
                c["pr_state"] = _get_pr_state(c["tail_pr_url"])
    out.sort(key=lambda x: x.get("last_interacted") or x.get("modified") or 0, reverse=True)
    if progress:
        progress(
            "codex",
            state="done",
            count=len(out),
            total=scanned,
            detail=f"{len(out)} Codex thread card(s) ready.",
        )
    return out


def _codex_int(value):
    try:
        return int(value or 0)
    except (TypeError, ValueError):
        return 0


def _codex_token_usage_from_event(ev):
    payload = ev.get("payload") if isinstance(ev.get("payload"), dict) else {}
    if payload.get("type") != "token_count":
        return None
    info = payload.get("info") or {}
    if not isinstance(info, dict):
        return None
    usage = info.get("last_token_usage") or info.get("total_token_usage") or {}
    if not isinstance(usage, dict) or not usage:
        return None
    return {
        "input_tokens": _codex_int(usage.get("input_tokens")),
        "cached_input_tokens": _codex_int(usage.get("cached_input_tokens")),
        "output_tokens": _codex_int(usage.get("output_tokens")),
        "reasoning_output_tokens": _codex_int(usage.get("reasoning_output_tokens")),
        "total_tokens": _codex_int(usage.get("total_tokens")),
    }


def _parse_codex_event(ev, line_num, token_usage=None):
    ev_type = ev.get("type", "")
    payload = ev.get("payload") if isinstance(ev.get("payload"), dict) else {}
    ptype = payload.get("type", "")
    ts = _codex_event_timestamp(ev)
    if ev_type == "event_msg":
        if ptype == "user_message":
            text = _strip_ccc_session_state_instruction(payload.get("message") or "")
            images = []
            if text or images:
                return {"line": line_num, "ts": ts, "type": "user_text", "text": text, "images": images}
        if ptype == "agent_message":
            text = (payload.get("message") or "").strip()
            if text:
                return {
                    "line": line_num,
                    "ts": ts,
                    "type": "assistant",
                    "message_id": f"codex-{line_num}",
                    "blocks": [{"kind": "text", "text": text}],
                }
        if ptype == "task_complete":
            result = {
                "line": line_num,
                "ts": ts,
                "type": "result",
                "duration_ms": payload.get("duration_ms", "?"),
            }
            if token_usage:
                result["token_usage"] = token_usage
            return result
        return None
    if ev_type != "response_item":
        return None
    if ptype == "function_call":
        name = payload.get("name") or "tool"
        args = _codex_args(payload.get("arguments"))
        detail = _codex_tool_detail(name, args)
        if isinstance(detail, str) and len(detail) > 200:
            detail = detail[:200] + "..."
        block = {
            "kind": "tool_use",
            "name": _codex_tool_name(name),
            "detail": detail or "",
            "id": payload.get("call_id") or payload.get("id") or "",
        }
        command_text = _codex_tool_command(name, args)
        if command_text:
            redacted_command = _redacted_shell_command_text(command_text, max_len=12000)
            if redacted_command and (
                "\n" in redacted_command
                or len(redacted_command) > 160
                or re.sub(r"\s+", " ", redacted_command).strip() != (detail or "")
            ):
                block["command"] = redacted_command
                here = _extract_shell_heredoc(command_text)
                block["command_kind"] = _shell_script_label(here.get("head", "")) if here else "Shell command"
        return {
            "line": line_num,
            "ts": ts,
            "type": "assistant",
            "message_id": f"codex-tool-{line_num}",
            "blocks": [block],
        }
    if ptype == "function_call_output":
        output = payload.get("output") or ""
        images = []
        if isinstance(output, list):
            # Structured output (e.g. screenshots). Inlining the base64 here
            # balloons the payload to tens of MB and stalls the open, so pull
            # images out as lazy (line, idx) refs — same scheme the claude
            # parser uses — and /api/conv-image fetches them on demand.
            parts = []
            for item in output:
                if isinstance(item, str):
                    parts.append(item)
                elif isinstance(item, dict):
                    it = item.get("type")
                    url = item.get("image_url") or ""
                    if it == "input_image" and isinstance(url, str) and url.startswith("data:") and "base64," in url:
                        mt = url[5:].split(";", 1)[0] or "image/png"
                        images.append({"kind": "base64", "media_type": mt,
                                       "line": line_num, "idx": len(images)})
                    elif isinstance(item.get("text"), str):
                        parts.append(item["text"])
            output = "\n".join(parts)
        if not isinstance(output, str):
            output = str(output)
        if len(output) > 800:
            output = output[:800] + "\n..."
        result = {
            "line": line_num,
            "ts": ts,
            "type": "tool_result",
            "text": output,
            "tool_use_id": payload.get("call_id", ""),
            "is_error": False,
        }
        if images:
            result["images"] = images
        return result
    return None


def _parse_codex_conversation(thread_id, after_line=0):
    filepath = _resolve_codex_rollout_path(thread_id)
    events = []
    line_num = 0
    codex_token_usage = None
    if not filepath:
        return {"events": [], "last_line": 0}
    try:
        with open(filepath, "r", encoding="utf-8", errors="replace") as f:
            for line in f:
                line_num += 1
                if line_num <= after_line:
                    continue
                line = line.strip()
                if not line:
                    continue
                try:
                    ev = json.loads(line)
                except json.JSONDecodeError:
                    continue
                usage = _codex_token_usage_from_event(ev)
                if usage:
                    codex_token_usage = usage
                    continue
                parsed = _parse_codex_event(ev, line_num, codex_token_usage)
                if parsed:
                    events.append(parsed)
    except FileNotFoundError:
        pass
    return {"events": events, "last_line": line_num}


_pending_resume_queue: dict = {}   # session_id → [text, ...]
_pending_resume_lock = threading.Lock()
_pending_terminal_input_queue: dict = {}   # session_id → [text, ...]
_pending_terminal_input_lock = threading.Lock()
_pending_inputs_lock = threading.Lock()


def _load_pending_inputs():
    """Load pending queues from PENDING_INPUTS_FILE into memory."""
    global _pending_resume_queue, _pending_terminal_input_queue
    try:
        with open(PENDING_INPUTS_FILE) as f:
            data = json.load(f)
    except (OSError, json.JSONDecodeError):
        return
    if not isinstance(data, dict):
        return
    with _pending_resume_lock:
        rq = data.get("resume_queue")
        if isinstance(rq, dict):
            _pending_resume_queue.update({k: list(v) for k, v in rq.items() if isinstance(v, list)})
    with _pending_terminal_input_lock:
        tq = data.get("terminal_queue")
        if isinstance(tq, dict):
            _pending_terminal_input_queue.update({k: list(v) for k, v in tq.items() if isinstance(v, list)})


def _save_pending_inputs():
    """Save pending queues from memory to PENDING_INPUTS_FILE."""
    with _pending_inputs_lock:
        with _pending_resume_lock:
            rq = dict(_pending_resume_queue)
        with _pending_terminal_input_lock:
            tq = dict(_pending_terminal_input_queue)
        payload = {"resume_queue": rq, "terminal_queue": tq}
        try:
            PENDING_INPUTS_FILE.parent.mkdir(parents=True, exist_ok=True)
            tmp = PENDING_INPUTS_FILE.with_suffix(".json.tmp")
            with open(tmp, "w") as f:
                json.dump(payload, f, indent=2, sort_keys=True)
            tmp.replace(PENDING_INPUTS_FILE)
        except OSError as e:
            print(f"  [pending-inputs] save failed: {e}")


def _get_queued_events_for_session(session_id):
    """Get synthetic events for any queued messages of this session."""
    events = []
    if not session_id:
        return events
    with _pending_resume_lock:
        resume_queue = list(_pending_resume_queue.get(session_id, []))
    with _pending_terminal_input_lock:
        term_queue = list(_pending_terminal_input_queue.get(session_id, []))
    ts = time.time()
    for text in resume_queue:
        events.append({
            "line": None,
            "ts": ts,
            "type": "user_text",
            "text": text,
            "images": [],
            "pending": True
        })
    for text in term_queue:
        events.append({
            "line": None,
            "ts": ts,
            "type": "user_text",
            "text": text,
            "images": [],
            "pending": True
        })
    return events

_BUSY_SESSION_STATUSES = {"busy", "running"}


def _session_status_is_busy(status):
    return (status.get("status") or "").lower() in _BUSY_SESSION_STATUSES


_CCC_HOOK_SCRIPTS = ("pre-tool-use.py", "post-tool-use.py", "notification.py", "stop.py")


def _is_ccc_hook_command(command):
    """True if a child process is one of our own Claude Code hook scripts.

    The PreToolUse hook blocks (in its own process group) while a relayed
    AskUserQuestion waits for an answer. That hook is NOT a tool the agent is
    running — counting it as one flips the sidecar to a phantom "Bash" command,
    which masks the question and suppresses the answer modal.
    """
    return any(name in (command or "") for name in _CCC_HOOK_SCRIPTS)


def _spawn_entry_active_tool_child(entry):
    """Return metadata for a transient child tool process under a spawned agent.

    Claude's long-lived MCP servers stay in the Claude process group. Bash/tool
    subprocesses are launched as their own process group, so a direct child with
    a different PGID is a strong signal that the session is still busy even when
    the sidecar says "waiting". Our own hook processes are skipped — a blocked
    question-relay hook is not a running tool.
    """
    try:
        parent_pid = int((entry or {}).get("pid") or 0)
    except (TypeError, ValueError):
        return None
    if parent_pid <= 0:
        return None
    try:
        proc = subprocess.run(
            ["ps", "-axo", "pid=,ppid=,pgid=,stat=,etime=,command="],
            capture_output=True,
            text=True,
            timeout=2,
        )
    except (subprocess.TimeoutExpired, FileNotFoundError, OSError):
        return None
    if proc.returncode != 0:
        return None
    for raw in (proc.stdout or "").splitlines():
        parts = raw.strip().split(None, 5)
        if len(parts) < 5:
            continue
        try:
            pid = int(parts[0])
            ppid = int(parts[1])
            pgid = int(parts[2])
        except ValueError:
            continue
        if ppid != parent_pid or pgid == parent_pid:
            continue
        command = parts[5] if len(parts) > 5 else ""
        if _is_ccc_hook_command(command):
            continue
        # Derive the child's real start time from elapsed (ps etime) so the
        # UI shows the true tool age. Without this the caller stamps
        # time.time() every poll, freezing a hung child at "running <1s"
        # forever and dodging the frontend's 5-minute stale-tool cap.
        elapsed = _parse_ps_etime(parts[4])
        started_at = (time.time() - elapsed) if elapsed is not None else None
        return {
            "pid": pid,
            "pgid": pgid,
            "stat": parts[3],
            "command": command,
            "started_at": started_at,
        }
    return None


def _parse_ps_etime(text):
    """Parse BSD ps ``etime`` ([[DD-]HH:]MM:SS) into elapsed seconds.

    Returns None on anything unparseable so callers can fall back.
    """
    text = (text or "").strip()
    if not text:
        return None
    days = 0
    if "-" in text:
        day_part, _, text = text.partition("-")
        try:
            days = int(day_part)
        except ValueError:
            return None
    bits = text.split(":")
    try:
        nums = [int(b) for b in bits]
    except ValueError:
        return None
    if len(nums) == 3:
        h, m, s = nums
    elif len(nums) == 2:
        h, m, s = 0, nums[0], nums[1]
    else:
        return None
    return days * 86400 + h * 3600 + m * 60 + s


def _queue_terminal_input(session_id, text, status=None):
    """Queue input until a live Claude session reports it is idle again."""
    with _pending_terminal_input_lock:
        queue = _pending_terminal_input_queue.setdefault(session_id, [])
        queue.append(text)
        queued_count = len(queue)
    _save_pending_inputs()
    payload = {

        "ok": True,
        "queued": True,
        "via": "terminal-queued",
        "session_id": session_id,
        "queued_count": queued_count,
    }
    if status:
        payload["pid"] = status.get("pid")
        payload["status"] = status.get("status")
    return payload


def _terminal_input_queue_has_pending(session_id):
    with _pending_terminal_input_lock:
        return bool(_pending_terminal_input_queue.get(session_id))


def _load_daemon_roster():
    """Read Claude Code's background-agent roster, if the daemon is running."""
    try:
        data = json.loads(DAEMON_ROSTER_FILE.read_text())
    except (OSError, json.JSONDecodeError):
        return {}
    return data if isinstance(data, dict) else {}


def _find_live_bg_agent_entry_for_session(session_id):
    """Return the daemon roster worker for a live background Claude session."""
    if not session_id:
        return None
    workers = (_load_daemon_roster().get("workers") or {})
    if not isinstance(workers, dict):
        return None
    for short, worker in workers.items():
        if not isinstance(worker, dict):
            continue
        if worker.get("sessionId") != session_id:
            continue
        entry = dict(worker)
        entry["short"] = short
        return entry
    return None


def _bg_agent_state_for_session(session_id, status=None):
    """Read ~/.claude/jobs/<short>/state.json for a background agent."""
    if not session_id:
        return None
    status = status or {}
    candidates = []
    job_id = status.get("job_id") or status.get("jobId") or ""
    if job_id:
        candidates.append(CLAUDE_JOBS_ROOT / str(job_id) / "state.json")
    candidates.append(CLAUDE_JOBS_ROOT / session_id[:8] / "state.json")

    seen = set()
    for path in candidates:
        if path in seen:
            continue
        seen.add(path)
        try:
            data = json.loads(path.read_text())
        except (OSError, json.JSONDecodeError):
            continue
        if not isinstance(data, dict):
            continue
        if data.get("sessionId") in (None, session_id) or data.get("resumeSessionId") == session_id:
            return data

    try:
        state_files = list(CLAUDE_JOBS_ROOT.glob("*/state.json"))
    except OSError:
        return None
    for path in state_files:
        try:
            data = json.loads(path.read_text())
        except (OSError, json.JSONDecodeError):
            continue
        if not isinstance(data, dict):
            continue
        if data.get("sessionId") == session_id or data.get("resumeSessionId") == session_id:
            return data
    return None


def _bg_agent_ready_for_input(session_id, status=None):
    """Whether a live background agent has a prompt ready for user text.

    Claude's registry can report `busy` while the main agent is blocked for
    user input but a child local agent is still running. The jobs state is the
    better signal for background-agent input readiness.
    """
    sc = _read_sidecar_state(session_id)
    if sc and (sc.get("status") or "").lower() == "waiting":
        return True

    job_state = _bg_agent_state_for_session(session_id, status)
    if job_state:
        state = (job_state.get("state") or "").lower()
        if state in {"blocked", "done", "idle", "waiting"}:
            return True
        if state in {"active", "busy", "running", "working"}:
            return False

    status_text = ((status or {}).get("status") or "").lower()
    if status_text in {"idle", "waiting"}:
        return True
    if status_text in _BUSY_SESSION_STATUSES:
        return False
    return True


def _daemon_socket_path_allowed(path):
    """Clamp daemon socket use to Claude's per-user temp daemon directory."""
    if not path:
        return False
    try:
        real = os.path.realpath(path)
        daemon_dir = f"cc-daemon-{os.getuid()}"
        base_parents = {tempfile.gettempdir(), "/tmp", "/private/tmp"}
        for base_parent in base_parents:
            base = os.path.realpath(os.path.join(base_parent, daemon_dir))
            if real == base or real.startswith(base + os.sep):
                return True
        return False
    except (TypeError, ValueError, OSError):
        return False


def _clean_pty_prompt_text(text):
    """Drop terminal-control characters before writing into a background PTY."""
    text = str(text or "").replace("\r\n", "\n").replace("\r", "\n")
    return "".join(
        ch for ch in text
        if ch in ("\n", "\t") or (ord(ch) >= 32 and ord(ch) != 127)
    )


def _inject_bg_agent_via_pty_socket(worker, text):
    """Send text to a live `claude agents` background session.

    The daemon PTY socket uses framed messages:
      4-byte big-endian payload length, 1-byte channel, payload bytes.
    Channel 0 is PTY data. We bracket-paste the body so multi-line prompts
    land as text, then send Return to submit.
    """
    if not worker:
        return {
            "ok": False,
            "via": "bg-agent-pty",
            "error": "background agent is live, but its daemon worker was not found",
        }
    pty_sock = worker.get("ptySock") or ""
    if not _daemon_socket_path_allowed(pty_sock):
        return {
            "ok": False,
            "via": "bg-agent-pty",
            "error": "background agent PTY socket is outside the expected daemon directory",
        }
    try:
        mode = os.stat(pty_sock).st_mode
    except OSError as e:
        return {"ok": False, "via": "bg-agent-pty", "error": str(e)}
    if not stat.S_ISSOCK(mode):
        return {
            "ok": False,
            "via": "bg-agent-pty",
            "error": "background agent PTY path is not a socket",
        }

    clean_text = _clean_pty_prompt_text(text)
    if not clean_text.strip():
        return {"ok": False, "via": "bg-agent-pty", "error": "missing text"}
    payload = ("\x1b[200~" + clean_text + "\x1b[201~").encode("utf-8")
    frame = len(payload).to_bytes(4, "big") + b"\x00" + payload
    submit = b"\r"
    submit_frame = len(submit).to_bytes(4, "big") + b"\x00" + submit

    sock = socket.socket(socket.AF_UNIX, socket.SOCK_STREAM)
    sock.settimeout(2)
    try:
        sock.connect(pty_sock)
        sock.sendall(frame)
        time.sleep(0.05)
        sock.sendall(submit_frame)
    except (OSError, socket.timeout) as e:
        return {"ok": False, "via": "bg-agent-pty", "error": str(e)}
    finally:
        try:
            sock.close()
        except OSError:
            pass
    return {
        "ok": True,
        "via": "bg-agent-pty",
        "pid": worker.get("pid"),
        "session_id": worker.get("sessionId"),
    }


def _start_resume_queue_watcher() -> None:
    """Drain queued prompts once fire-and-watch engines or live terminal sessions go idle."""
    _load_pending_inputs()
    def _watcher():
        while True:
            time.sleep(5)
            with _pending_resume_lock:
                queued_sids = list(_pending_resume_queue.keys())
            for sid in queued_sids:
                busy = any(
                    s.get("resumed_sid") == sid and _poll_spawn_entry(s) is None
                    for s in _spawned_sessions
                    if s.get("engine") in ("codex", "gemini", "cursor", "antigravity")
                )
                if busy:
                    continue
                with _pending_resume_lock:
                    queue = _pending_resume_queue.get(sid, [])
                    if not queue:
                        _pending_resume_queue.pop(sid, None)
                        _save_pending_inputs()
                        continue
                    text = queue.pop(0)
                    if not queue:
                        _pending_resume_queue.pop(sid, None)
                _save_pending_inputs()
                try:
                    if _is_codex_session(sid):
                        resume_session_codex(sid, text)
                    elif _is_gemini_session(sid):
                        resume_session_gemini(sid, text)
                    elif _is_cursor_session(sid):
                        resume_session_cursor(sid, text)
                    elif _is_antigravity_session(sid):
                        resume_session_antigravity(sid, text)
                except Exception:
                    pass
            with _pending_terminal_input_lock:
                terminal_sids = list(_pending_terminal_input_queue.keys())
            for sid in terminal_sids:
                try:
                    # CRITICAL guard — never flush queued input while an
                    # AskUserQuestion is in-flight. The watcher previously
                    # only checked _session_status_is_busy() (status =
                    # busy/running), which can return False even when
                    # sidecar_tool == "AskUserQuestion" is still pending a
                    # user pick. Injecting queued text in that window made
                    # Claude Code synthesize a tool_result for the open
                    # AskUserQuestion (treating the queued text as the
                    # user's "answer") and continue the conversation —
                    # surfacing as "Claude continued silently past the
                    # question". The pending-question sidecar payload is
                    # the authoritative signal; if it exists, hold the
                    # queue until the user actually answers in the UI.
                    if _pending_ask_user_question_for_session(sid):
                        continue
                    status = session_live_status(sid, find_session_cwd(sid))
                    if status.get("live") and status.get("tty") and _session_status_is_busy(status):
                        continue
                    if status.get("live") and status.get("kind") == "bg":
                        if not _bg_agent_ready_for_input(sid, status):
                            continue
                    if status.get("live") and not status.get("tty"):
                        spawn = _find_live_spawn_entry_for_session(sid)
                        if spawn is not None and _spawn_entry_active_tool_child(spawn):
                            continue
                    with _pending_terminal_input_lock:
                        queue = _pending_terminal_input_queue.get(sid, [])
                        if not queue:
                            _pending_terminal_input_queue.pop(sid, None)
                            _save_pending_inputs()
                            continue
                        text = queue.pop(0)
                        if not queue:
                            _pending_terminal_input_queue.pop(sid, None)
                    _save_pending_inputs()
                    _inject_text_into_session(sid, text, _from_terminal_queue=True)
                except Exception:
                    pass
    threading.Thread(target=_watcher, daemon=True, name="resume-queue-watcher").start()


def _queue_codex_resume(session_id, text, pid=None):
    with _pending_resume_lock:
        _pending_resume_queue.setdefault(session_id, []).append(text)
    _save_pending_inputs()
    payload = {
        "ok": True,
        "queued": True,
        "via": "codex-resume-queued",
    }
    if pid is not None:
        payload["pid"] = pid
    return payload



def resume_session_codex(session_id, text, *, steer=False):
    """Resume a dormant Codex thread with a new prompt via `codex exec resume`."""
    text = _strip_ccc_session_state_instruction(text)
    if not text:
        return {"ok": False, "error": "missing text"}
    image_paths = _extract_pasted_image_paths(text)
    resolved = _resolve_codex_bin()
    if not resolved["available"]:
        return {"ok": False, "error": resolved["reason"], "code": resolved.get("code")}
    active_resume_entry = None
    for s in _spawned_sessions:
        if s.get("engine") == "codex" and s.get("resumed_sid") == session_id:
            try:
                if _poll_spawn_entry(s) is None:
                    active_resume_entry = s
                    break
            except Exception:
                pass
    row = _codex_thread_row(session_id) or {}
    spawned_ctx = _spawn_registry_entry_for_session(session_id, "codex") or {}
    cwd = (
        row.get("cwd")
        or spawned_ctx.get("cwd")
        or (active_resume_entry or {}).get("cwd")
        or find_session_cwd(session_id)
    )
    cwd_error = None
    if not cwd or not Path(cwd).is_dir():
        try:
            cwd = repo_from_session(session_id)["cwd"]
        except RepoContextError as e:
            cwd_error = e
            cwd = None
    # Per-session override (set via the click-to-switch picker) wins over
    # the env-var default and the previous run's recorded model.
    override = _get_session_override(session_id)
    override_model = (override or {}).get("model") if override else None
    model = override_model or os.environ.get("CCC_CODEX_MODEL") or row.get("model") or "gpt-5.5"
    if steer:
        return _codex_steer_via_app_server(
            session_id,
            text,
            cwd=cwd,
            model=model,
            image_paths=image_paths,
        )
    app_result = _codex_resume_or_steer_via_app_server(
        session_id,
        text,
        cwd=cwd,
        model=model,
        image_paths=image_paths,
        allow_start=active_resume_entry is None,
    )
    if app_result.get("ok"):
        return app_result
    if app_result.get("fallback") == "queue":
        return _queue_codex_resume(
            session_id,
            text,
            pid=(active_resume_entry or {}).get("pid"),
        )
    if active_resume_entry is not None:
        return _queue_codex_resume(session_id, text, pid=active_resume_entry.get("pid"))
    if cwd_error is not None:
        return cwd_error.as_payload()
    timestamp = time.strftime("%Y%m%dT%H%M%S")
    log_filename = f"resume-codex-{session_id[:8]}-{timestamp}.log"
    repo_for_logs = _git_toplevel_for_existing_dir(cwd) or cwd
    log_dir = repo_log_dir(repo_for_logs)
    log_dir.mkdir(parents=True, exist_ok=True)
    log_path = log_dir / log_filename
    cmd = [
        resolved["bin"], *_codex_context_window_args(), "exec", "resume",
        "--json",
        "--skip-git-repo-check",
        "--dangerously-bypass-approvals-and-sandbox",
        "--model", model,
    ]
    for image_path in image_paths:
        cmd.extend(["--image", image_path])
    cmd.extend([session_id, text])
    log_fh = open(log_path, "w")
    try:
        proc = subprocess.Popen(
            cmd,
            stdin=subprocess.DEVNULL,
            stdout=log_fh,
            stderr=subprocess.STDOUT,
            cwd=cwd,
            start_new_session=True,
        )
    except (FileNotFoundError, OSError) as e:
        log_fh.close()
        return {"ok": False, "error": str(e), "via": "codex-resume"}
    entry = {
        "pid": proc.pid,
        "name": f"resume-codex-{session_id[:8]}",
        "log": str(log_path),
        "prompt": text[:200],
        "started": timestamp,
        "proc": proc,
        "log_fh": log_fh,
        "resumed_sid": session_id,
        "fifo": None,
        "stdin_fd": None,
        "engine": "codex",
        "cwd": cwd,
        "repo_path": repo_for_logs,
        "model": model,
    }
    _spawned_sessions.append(entry)
    _record_spawn_to_registry(
        pid=proc.pid,
        name=entry["name"],
        log_path=log_path,
        cwd=cwd,
        spawned_at=timestamp,
        command_summary=text[:200],
        fifo=None,
        engine="codex",
        session_id=session_id,
        repo_path=repo_for_logs,
        model=model,
    )
    return {"ok": True, "pid": proc.pid, "log": str(log_path), "resumed": True, "via": "codex-resume"}


def _extract_codex_usage(session_id):
    empty = {
        "latest_input_tokens": 0,
        "peak_input_tokens": 0,
        "total_output_tokens": 0,
        "total_input_tokens": 0,
        "total_cache_creation_tokens": 0,
        "total_cache_read_tokens": 0,
        "model": "",
        "context_limit": 0,
        "cost_usd": 0.0,
        "cost_breakdown_usd": {"input": 0.0, "cache_creation": 0.0,
                               "cache_read": 0.0, "output": 0.0},
    }
    path = _resolve_codex_rollout_path(session_id)
    row = _codex_thread_row(session_id) or {}
    if not path:
        return empty
    latest = {}
    totals = {}
    peak = 0
    context_limit = 0
    model = row.get("model") or ""
    try:
        with open(path, "r", encoding="utf-8", errors="replace") as f:
            for line in f:
                try:
                    ev = json.loads(line)
                except json.JSONDecodeError:
                    continue
                payload = ev.get("payload") if isinstance(ev.get("payload"), dict) else {}
                if ev.get("type") == "turn_context":
                    model = payload.get("model") or model
                if payload.get("type") != "token_count":
                    continue
                info = payload.get("info") or {}
                context_limit = _codex_int(info.get("model_context_window")) or context_limit
                usage = info.get("last_token_usage") or info.get("total_token_usage") or {}
                total_usage = info.get("total_token_usage") or usage
                if not isinstance(usage, dict):
                    continue
                if isinstance(total_usage, dict):
                    totals = total_usage
                latest = usage
                # Codex/OpenAI usage reports cached input as a subset of
                # input_tokens. Adding it again turns cumulative session usage
                # into impossible context-window numbers.
                window = _codex_int(usage.get("input_tokens"))
                peak = max(peak, window)
    except OSError:
        return empty
    if not latest:
        return {**empty, "override": _get_session_override(session_id)}
    latest_input = _codex_int(latest.get("input_tokens"))
    total_input = _codex_int(totals.get("input_tokens"))
    cache_read = _codex_int(totals.get("cached_input_tokens"))
    total_output = _codex_int(totals.get("output_tokens"))
    return {
        **empty,
        "latest_input_tokens": latest_input,
        "peak_input_tokens": peak,
        "total_output_tokens": total_output,
        "total_input_tokens": max(total_input - cache_read, 0),
        "total_cache_creation_tokens": 0,
        "total_cache_read_tokens": cache_read,
        "model": model,
        "context_limit": context_limit,
        "cost_usd": 0.0,
        "override": _get_session_override(session_id),
    }


def _extract_codex_timeline(session_id):
    path = _resolve_codex_rollout_path(session_id)
    if not path:
        return {"events": [], "total_turns": 0}
    events = []
    pending_by_id = {}
    turn = 0
    try:
        with open(path, "r", encoding="utf-8", errors="replace") as f:
            for line in f:
                try:
                    ev = json.loads(line)
                except json.JSONDecodeError:
                    continue
                payload = ev.get("payload") if isinstance(ev.get("payload"), dict) else {}
                ts = _codex_event_timestamp(ev)
                if ev.get("type") == "event_msg" and payload.get("type") == "agent_message":
                    turn += 1
                    continue
                if ev.get("type") != "response_item":
                    continue
                if payload.get("type") == "function_call":
                    name = payload.get("name") or ""
                    args = _codex_args(payload.get("arguments"))
                    cmd = _codex_tool_command(name, args)
                    if not cmd:
                        continue
                    kind = None
                    subject = ""
                    if _TIMELINE_PR_CREATE_RE.search(cmd):
                        kind = "pr"
                        m = _TIMELINE_PR_TITLE_RE.search(cmd)
                        if m:
                            subject = m.group(1)
                    elif _TIMELINE_PUSH_RE.search(cmd):
                        kind = "push"
                    elif _TIMELINE_COMMIT_RE.search(cmd):
                        kind = "commit"
                        m = _TIMELINE_COMMIT_MSG_RE.search(cmd)
                        if m:
                            subject = m.group(1)
                    if not kind:
                        continue
                    events.append({
                        "kind": kind,
                        "turn": max(turn, 1),
                        "ts": ts,
                        "subject": subject,
                        "success": None,
                    })
                    call_id = payload.get("call_id") or ""
                    if call_id:
                        pending_by_id[call_id] = len(events) - 1
                elif payload.get("type") == "function_call_output":
                    call_id = payload.get("call_id") or ""
                    if call_id not in pending_by_id:
                        continue
                    idx = pending_by_id.pop(call_id)
                    entry = events[idx]
                    entry["success"] = True
                    text = payload.get("output") or ""
                    if entry["kind"] == "commit":
                        m = _TIMELINE_COMMIT_RESULT_RE.search(text)
                        if m:
                            entry["sha"] = m.group(1)
                            if not entry.get("subject"):
                                entry["subject"] = m.group(2).strip()[:200]
                    elif entry["kind"] == "pr":
                        m = _TIMELINE_PR_NUMBER_FROM_URL_RE.search(text)
                        if m:
                            entry["pr_number"] = int(m.group(1))
    except OSError:
        return {"events": [], "total_turns": 0}
    return {"events": events, "total_turns": turn}


